-- Poems batch 396
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-172','贺圣朝','马子严','宋','宋词','song-ci','贺圣朝','[]','游人拾翠不知远。',58,'宋词/ci.song.12000.json','["游人拾翠不知远。", "被子规呼转。", "红楼倒影背斜阳，坠几声弦管。", "荼䕷香透，海棠红浅。", "恰平分春半。", "花前一笑不须悭，待花飞休怨。"]'),
('song-ci-173','鱼游春水','马子严','宋','宋词','song-ci','鱼游春水','[]','池塘生春草。',105,'宋词/ci.song.12000.json','["池塘生春草。", "数尽归鸿人未到。", "天涯目断，青鸟尚赊音耗。", "晓月频窥白玉堂，暮雨还湿青门道。", "巢燕引雏，乳莺空老。", "庭际香红倦扫。", "乾鹊休来枝上嗓。", "前回准拟同他，翻成病了。", "欲题红叶凭谁寄，独抱孤桐无心挑。", "眉间翠攒，鬓边霜早。"]'),
('song-ci-174','海棠春','马子严','宋','宋词','song-ci','海棠春','[]','柳腰暗怯花风弱。',54,'宋词/ci.song.12000.json','["柳腰暗怯花风弱。", "红映秋千院落。", "归逐燕儿飞，斜撼真珠箔。", "满林翠叶胭脂萼。", "不忍频频觑著。", "护取一庭春，莫弹花间鹊。"]'),
('song-ci-175','鹧鸪天','马子严','宋','宋词','song-ci','鹧鸪天','[]','睡鸭俳徊烟缕长。',64,'宋词/ci.song.12000.json','["睡鸭俳徊烟缕长。", "日高春困不成妆。", "步敧草色金莲润，拈断花鬚玉笋香。", "轻洛浦，笑巫阳。", "锦纹亲织寄檀郎。", "儿家闭户藏春色，戏蝶游蜂不敢狂。"]'),
('song-ci-176','归朝欢','马子严','宋','宋词','song-ci','归朝欢','[]','听得提壶沽美酒。',122,'宋词/ci.song.12000.json','["听得提壶沽美酒。", "人道杏花深处有。", "杏花狼藉鸟啼风，十分春色今无九。", "麝煤销永昼。", "青烟飞上庭前柳。", "画堂深，不寒不暖，正是好时候。", "团团宝月凭纤手。", "暂借歌喉招舞袖。", "真珠滴破小槽红，香肌缩尽纤罗瘦。", "投分须白首。", "黄金散与亲和旧。", "且衔杯，壮心未落，风月长相守。"]'),
('song-ci-177','孤鸾','马子严','宋','宋词','song-ci','孤鸾','[]','沙堤香软。',119,'宋词/ci.song.12000.json','["沙堤香软。", "正宿雨初收，落梅飘满。", "可奈东风，暗逐马蹄轻卷。", "湖波又远涨绿，粉墙阴、日融烟暖。", "蓦地刺桐枝上，有一声春唤。", "任酒帘、飞动画楼晚。", "便指数烧灯，时节非远。", "陌上叫声，好是卖花行院。", "玉梅对妆雪柳，闹蛾儿、象生娇颤。", "归去争先戴取，倚宝钗双燕。"]'),
('song-ci-178','阮郎归','马子严','宋','宋词','song-ci','阮郎归','[]','清明寒食不多时。',56,'宋词/ci.song.12000.json','["清明寒食不多时。", "香红渐渐稀。", "番腾妆束闹苏堤。", "留春春怎知。", "花褪雨，絮沾泥。", "凌波寸不移。", "三三两两叫船儿。", "人归春也归。"]'),
('song-ci-179','浣溪沙慢','马子严','宋','宋词','song-ci','浣溪沙慢','[]','璧月上极浦。',103,'宋词/ci.song.12000.json','["璧月上极浦。", "帆落人挝鼓。", "石城倒影，深夜鱼龙舞。", "佳气郁郁，紫阕腾云雨。", "回首分今古。", "千载是和非，夕阳中、双燕语。", "向人诉。", "记玉井辘轳，胭脂涨腻，几许蛾眉妒。", "感叹息、花好随风去。", "流景如羽。", "且共乐升平，不须后庭玉树。"]'),
('song-ci-180','锦缠道','马子严','宋','宋词','song-ci','锦缠道','[]','雨过园林，触处落红凝绿。',78,'宋词/ci.song.12000.json','["雨过园林，触处落红凝绿。", "正桑叶、齐如沃。", "娇羞只恐人偷目。", "背立墙阴，慢展纤纤玉。", "听鸠啼几声，耳边相促。", "念蚕饥、四眠初熟。", "劝路旁、立马莫踟躇，是那里唱道秋胡曲。"]'),
('song-ci-181','满江红','马子严','宋','宋词','song-ci','满江红','[]','瑞霭秋空，银河里、非烟非雾。',115,'宋词/ci.song.12000.json','["瑞霭秋空，银河里、非烟非雾。", "应想是、岳锺神秀，再生尹傅。", "昨夜五云随梦入，今朝万象朝元去。", "正六星、炳炳耀文昌，循初度。", "五马贵，多文富。", "人品异，心朝古。", "似冰清瑶水，玉森元圃。", "天子方将循异政，灵孙又合为霖雨。", "问汾阳、几考在中书，从今数。"]'),
('song-ci-182','水调歌头','马子严','宋','宋词','song-ci','水调歌头','[]','万仞鹅湖顶，千岁矫苍龙。',114,'宋词/ci.song.12000.json','["万仞鹅湖顶，千岁矫苍龙。", "楼台一簇，仙家遥寄五云中。", "天上朝元佳节，人世生贤华旦，瑞气郁葱葱。", "六辔耀闽海，列郡喜趋风。", "记昔年，当此际，早梅红。", "插花饮酒，狂歌醉舞寿昌宫。", "零落青袍如旧，敛板绣衣庭下，欣见黑头公。", "王室要师保，叔父忽居东。"]'),
('song-ci-183','感皇恩','马子严','宋','宋词','song-ci','感皇恩','[]','深约海棠开，一庭儿女。',82,'宋词/ci.song.12000.json','["深约海棠开，一庭儿女。", "共插满头笑相语。", "入春准备了，到今朝团聚。", "近来都不怕，风和雨。", "一个一杯，君山绿醑。", "何必贪多似彭祖。", "但须看遍，子生孙孙生子。", "便年年拼一醉，花前舞。"]'),
('song-ci-184','浪淘沙','马子严','宋','宋词','song-ci','浪淘沙','[]','娇额尚涂黄。',64,'宋词/ci.song.12000.json','["娇额尚涂黄。", "不久时妆。", "十分轻脆奈风霜。", "几度细腰寻得蜜，错认蜂房。", "东阁久凄凉。", "江路悠长。", "休将颜色较芬芳。", "无奈花间真若伪，赖有幽香。"]'),
('song-ci-185','苏幕遮','马子严','宋','宋词','song-ci','苏幕遮','[]','地偏灵，天应瑞。',76,'宋词/ci.song.12000.json','["地偏灵，天应瑞。", "簇簇银花，团绕真珠蕊。", "金阕玉楼分十二。", "要伴姮娥，与月循环睡。", "月如花，花表岁。", "人到闰年，添个真奇异。", "不许扬州夸间气。", "昨夜春风，吹送柴门里。"]'),
('song-ci-186','万年欢','赵师侠','宋','宋词','song-ci','万年欢','[]','电绕神枢，华渚流虹，诞弥良用佳辰。',123,'宋词/ci.song.12000.json','["电绕神枢，华渚流虹，诞弥良用佳辰。", "万宇讴歌归舞，宝历增新。", "四七年间盛事，皇威畅、边鄙无尘。", "仁恩被，华夏咸安，太平极治欢声。", "重华道隆德茂，亘古今希有，揖逊重闻。", "圣子三宫欢聚，两世慈亲。", "幸际千秋圣旦，沾镐宴、普率惟均。", "封人祝，亿万斯年，寿皇尊并高真。"]'),
('song-ci-187','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','金鼎调元手，玉殿涣恩华。',114,'宋词/ci.song.12000.json','["金鼎调元手，玉殿涣恩华。", "宣威蜀道，曾见千骑拥高牙。", "凭仗元枢筹略，宽我宸旒西顾，惠泽被幽遐。", "为忆江城好，南浦艗仙槎。", "格天心，膺帝眷，极褒嘉。", "琳宫香火缘在，远近玉皇家。", "霖雨久思贤佐，看即声传丹禁，唤仗听宣麻。", "衮绣公归去，宰路筑堤沙。"]'),
('song-ci-188','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','江亭送行客，肠断木兰舟。',114,'宋词/ci.song.12000.json','["江亭送行客，肠断木兰舟。", "水高风快，满木烟树织成愁。", "咿轧数声柔橹，拍塞一怀离恨，指顾隔汀洲。", "独立苍茫外，欲去强迟留。", "海山长，云水阔，思难收。", "小亭深院歌笑，不忍记同游。", "唯有当时明月，千里有情还共，后会尚悠悠。", "此恨无重数，和泪付东流。"]'),
('song-ci-189','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','韶华能几许，节物叹推移。',114,'宋词/ci.song.12000.json','["韶华能几许，节物叹推移。", "群花兢芳争艳，无奈隙驹驰。", "红紫随风何处，唯有抟枝新绿，暗逐雨摧肥。", "乔木莺初啭，深院燕交飞。", "渐清和，微扇暑，日迟迟。", "新荷泛水摇漾，萍藻弄晴漪。", "百岁光阴难挽，一笑欢娱易失，莫惜酒盈卮。", "无计留连住，还是送春归。"]'),
('song-ci-190','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','江流清浅外，山色有无中。',114,'宋词/ci.song.12000.json','["江流清浅外，山色有无中。", "平田坡岸回曲，一目望难穷。", "波面轻鸥容与，沙际野航横渡，不信画图工。", "路入神仙宅，翠锁梵王宫。", "俯晴郊，增胜概，气横空。", "云林城市层列，知有几重重。", "更上危亭高几，徙倚栏干虚敞，象纬逼璇穹。", "要尽无边景，烟雨看空濛。"]'),
('song-ci-191','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','人生如寄耳，世态逐时移。',114,'宋词/ci.song.12000.json','["人生如寄耳，世态逐时移。", "浮名薄利能几，方寸漫交驰。", "粗足生涯随分，到眼风光可乐，终不羡轻肥。", "有志但长叹，无路且卑飞。", "恨年华，何去速，又来迟。", "绿荫浓映池沼，縠浪皱风漪。", "啭午莺声睍睆，滚地杨花飘荡，爱景惜芳卮。", "此意谁能解，一笑任春归。"]'),
('song-ci-192','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','心景雨无著，情物岂能移。',114,'宋词/ci.song.12000.json','["心景雨无著，情物岂能移。", "超然远览失笑，名利苦纷驰。", "一品官资荣显，百万金珠豪富，空自喜家肥。", "会得个中理，川泳与云飞。", "静中乐，闲中趣，自舒迟。", "心如止水，无风无自更生漪。", "已是都忘人我，一任吾身醒醉，有酒引连卮。", "万法无差别，融解即同归。"]'),
('song-ci-193','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','世态万纷变，人事一何忙。',114,'宋词/ci.song.12000.json','["世态万纷变，人事一何忙。", "胸中素韬奇蕴，匣剑岂能藏。", "不向燕然纪绩，便与渔樵争席，摆脱是非乡。", "要地时难得，间处日偏长。", "志横秋，谋夺众，谩轩昂。", "蝇头蜗角微利，争较一毫芒。", "幸有乔木修竹，随分粗衣粝食，何必计冠裳。", "我已乐箫散，谁与共平章。"]'),
('song-ci-194','水调歌头','赵师侠','宋','宋词','song-ci','水调歌头','[]','台星明翼轸，和气满潇湘。',114,'宋词/ci.song.12000.json','["台星明翼轸，和气满潇湘。", "长淮胜处地灵，应产股肱良。", "共仰三朝元老，要识一时英杰，人物自堂堂。", "直气薄霄汉，德望耸岩廊。", "拥貔貅，森棨戟，镇藩方。", "折冲樽俎，春融花柳侑壶觞。", "两世麟符玉节，九郡恩风惠雨，仁者寿宜长。", "凤诏来丹阙，绣衮觐明光。"]'),
('song-ci-195','满江红','赵师侠','宋','宋词','song-ci','满江红','[]','渺渺春江，迷望眼、蒲萄涨绿。',115,'宋词/ci.song.12000.json','["渺渺春江，迷望眼、蒲萄涨绿。", "春过也、萧疏庭户，寂寥心目。", "念远不禁啼鴂闹，愁多易遣修蛾蹙。", "向小窗、时把彩笺看，翻新曲。", "晴昼永，便新浴。", "相思泪，不成哭。", "空无言憔悴，暗销肌玉。", "目断碧云无信息，试凭青翼飞南北。", "听掀帘、疑是故人来，风敲竹。"]'),
('song-ci-196','满江红','赵师侠','宋','宋词','song-ci','满江红','[]','烟浪连天，寒尚峭、空濛细雨。',115,'宋词/ci.song.12000.json','["烟浪连天，寒尚峭、空濛细雨。", "春去也、红销芳径，绿肥江树。", "山色云笼迷远近，滩声水满望艰阻。", "挂片帆、掠岸晚风轻，停烟渚。", "浮世事，皆如许。", "名利役，惊时序。", "叹清明寒食，小舟为旅。", "露宿风餐安所赋，石泉榴火知何处。", "动归心、犹赖翠烟中，无杜宇。"]'),
('song-ci-197','满江红','赵师侠','宋','宋词','song-ci','满江红','[]','露冷天高，秋气爽、千林叶落。',115,'宋词/ci.song.12000.json','["露冷天高，秋气爽、千林叶落。", "惊初见、小桃枝上，盛开红萼。", "浅淡胭脂经雨洗，剪裁玛瑙如云薄。", "问素商、何事斗春工，施丹艧。", "芙蓉苑，颜如灼。", "曾暗与，花王约。", "要乘秋名字，并传京洛。", "回首瑶池高宴处，桂花香里骖高鹤。", "但莫教、容易逐西风，轻飘却。"]'),
('song-ci-198','满江红','赵师侠','宋','宋词','song-ci','满江红','[]','凉入三湘，秋气爽、江澄沙白。',115,'宋词/ci.song.12000.json','["凉入三湘，秋气爽、江澄沙白。", "人欲去、离愁暗暗，莫留行色。", "盍在中朝陪鹓鹭，暂来南楚分风月。", "与元枢、鹗荐共扶摇，朝天阙。", "皇华使，和戎策。", "西府赞，中兴业。", "有缁衣同美，武公勋烈。", "樯燕已知添别意，骊驹谁为歌新阕。", "恨此情、如月过中秋，圆还缺。"]'),
('song-ci-199','满江红','赵师侠','宋','宋词','song-ci','满江红','[]','去去春光，留不住、情怀索莫。',115,'宋词/ci.song.12000.json','["去去春光，留不住、情怀索莫。", "那堪是、日长人困，雨馀寒薄。", "叶底青青梅胜豆，枝头颗颗花留萼。", "叹流年、空有惜春心，凭春酌。", "歌共酒，谁酬酢。", "非与是，忘今昨。", "且随时随分，强欢寻乐。", "世事燕鸿南北去，人生乌兔东西落。", "问故园、不负送春期，明年约。"]'),
('song-ci-200','沁园春','赵师侠','宋','宋词','song-ci','沁园春','[]','雨接梅霖，风怯槐暑，麦天已秋。',141,'宋词/ci.song.12000.json','["雨接梅霖，风怯槐暑，麦天已秋。", "正榴燃红炬，枝头色艳，荷翻绿盖，池面香浮。", "心景俱清，身名何有，且向忙中早转头。", "尘劳事，枉朝思夕计，细虑深谋。", "悠悠。", "不复徼求。", "但安分、随缘休便休。", "纵官居极品，徒为美玩，家称钜富，未免闲愁。", "遇酒开颜，逢欢乐意，有似木人骑土牛。", "从他笑，看一朝解悟，八极遨游。"]'),
('song-ci-201','沁园春','赵师侠','宋','宋词','song-ci','沁园春','[]','羊角飘尘，金乌烁石，雨凉念秋。',140,'宋词/ci.song.12000.json','["羊角飘尘，金乌烁石，雨凉念秋。", "有虚堂临水，披襟散发，纱幮雾卷，湘潭波浮。", "远列云峰，近参荷气，卧看文书琴枕头。", "蝉声寂，向庄周梦里，栩栩无谋。", "茶瓯。", "醒困堪求。", "粗饱饭安居可以休。", "算け闲静胜，吾能自乐，荣华纷扰，人谩多愁。", "习懒非痴，觉迷是病，一力那能胜九牛。", "俱休问，且追寻觞咏，知友从游。"]'),
('song-ci-202','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','["\u897f\u6e56"]','枕山平远。',120,'宋词/ci.song.12000.json','["枕山平远。", "记当年小阁，牙床曾展。", "围幅高深春昼永，寂寂重帘不卷。", "棹檥西湖，人归南陌，酒晕红生脸。", "困来无那，玉肌小倚娇软。", "堪恨身在天涯，曲屏环枕，此意何由见。", "想像高唐无梦到，独拥闲衾展转。", "物是人非，山长水阔，触处思量遍。", "愁遮不断，夜阑依旧斜掩。"]'),
('song-ci-203','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','[]','飘流踪迹，趁春来、还趁春光归去。',120,'宋词/ci.song.12000.json','["飘流踪迹，趁春来、还趁春光归去。", "九十韶华能几许，著意留他不住。", "趱柳催花，催红长翠，多少风和雨。", "蜂闲蝶怨，尽凭枝上莺语。", "归棹去去难留，桃花浪暖，绿涨迷津浦。", "回首重城天样远，人在重城深处。", "惜别愁分，凝暗有泪，总寄阳关句。", "不堪肠断，恨随江水东注。"]'),
('song-ci-204','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','[]','斜风疏雨，正无聊情绪，天涯寒食。',120,'宋词/ci.song.12000.json','["斜风疏雨，正无聊情绪，天涯寒食。", "烟重云娇春烂漫，却得轻寒邀勒。", "柳褪鹅黄，池添鸭绿，桃杏浑狼藉。", "乱山深处，尚留些子春色。", "海燕未便归来，踏青斗草，谁与同寻觅。", "杜宇多情芳树里，只管声声历历。", "似劝行人，不如闻早，作个归消息。", "休教肠断，梦魂空费思忆。"]'),
('song-ci-205','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','[]','晓风清暑，映湖光如练，山光如染。',120,'宋词/ci.song.12000.json','["晓风清暑，映湖光如练，山光如染。", "十里荷花香满路，飞盖斜敧妆面。", "一叶扁舟，数声柔橹，陡觉红尘远。", "六桥三塔，恍然图画中见。", "因念当日三贤，两山佳处，应也经行遍。", "琢月吟风无限句，景物随人俱显。", "贺监风流，玄真清致，我亦情非浅。", "渔蓑投老，利名何用深羡。"]'),
('song-ci-206','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','[]','化工何意，向天涯海峤，有花清绝。',120,'宋词/ci.song.12000.json','["化工何意，向天涯海峤，有花清绝。", "缟袂绿裳无俗韵，不畏炎荒烦热。", "玉骨无尘，冰姿有艳，雅淡天然别。", "真香冶态，未饶红紫春色。", "底事□落江南，水仙兄弟，端自难优劣。", "瘴雨蛮烟魂梦远，宁识溪桥霜雪。", "薝卜同芳，素馨为伴，百和清芬热。", "凄然风热，夜凉香泛明月。"]'),
('song-ci-207','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','[]','平生奇观，爱登高临远，寻幽选胜。',120,'宋词/ci.song.12000.json','["平生奇观，爱登高临远，寻幽选胜。", "欲上层巅穷望眼，一半崎岖危径。", "万瓦鳞鳞，四山簇簇，咫尺疏林映。", "山川城郭，恍然多少清兴。", "残照斜敛馀红，横陈平远，一抹轻烟暝。", "何处飞来双白鹭，点破遥空澄莹。", "鹤岭云平，龙江波渺，不羡潇湘咏。", "襟怀舒旷，曲栏倚了远凭。"]'),
('song-ci-208','酹江月・念奴娇','赵师侠','宋','宋词','song-ci','酹江月・念奴娇','[]','韶华婉娩，正和风迟日，喧妍清昼。',120,'宋词/ci.song.12000.json','["韶华婉娩，正和风迟日，喧妍清昼。", "紫燕黄鹂争巧语，催老芬芳花柳。", "灼灼花王，盈盈娇艳，独殿春光后。", "鹤翎初拆，露沾香沁珠溜。", "遥想京洛风流，姚黄魏紫，间绿如铺纤。", "小盖低回雕栏曲，车马纷驰圆囿。", "天雨曼珠，玉盘金束，占得声名久。", "留连朝暮，赏心不压芳酒。"]'),
('song-ci-209','促拍满路花','赵师侠','宋','宋词','song-ci','促拍满路花','[]','栽花春烂漫，叠石翠巑岏。',105,'宋词/ci.song.12000.json','["栽花春烂漫，叠石翠巑岏。", "小亭相对倚，数峰寒。", "主人寻胜，接竹引清泉。", "凿破苍苔地，一掬泓澄，六花疑是深渊。", "向闲中、百虑け然。", "情事寄鸣弦。", "炉香陪茗碗，可望言。", "喷珠溅雪，历历听潺湲。", "尘世知何计，不老朱颜，静看日月跳丸。"]'),
('song-ci-210','促拍满路花','赵师侠','宋','宋词','song-ci','促拍满路花','[]','连枝蟠古木，瑞阴映晴空。',104,'宋词/ci.song.12000.json','["连枝蟠古木，瑞阴映晴空。", "桃江江上景，古今同。", "忙中取静，心地尽从容。", "扫尽荆榛蔽，结屋诛茅，道人一段家风。", "任乌飞兔走匆匆。", "世事亦何穷。", "官闲民不扰，更年丰。", "箪瓢云水，时与话西东。", "真乐谁能识，兀坐忘言，浩然天地之中。"]'),
('song-ci-211','永遇乐','赵师侠','宋','宋词','song-ci','永遇乐','[]','金昊行秋，季商回律，天气佳处。',128,'宋词/ci.song.12000.json','["金昊行秋，季商回律，天气佳处。", "瑞应皇家，祥开圣旦，宝历绵基祚。", "瑶池人祝，钧天乐奏，湛露宴均寰宇。", "万花覆、千官尽醉，盛事顿超今古。", "中兴天统，四三传序，揖逊自归明主。", "黄屋非心，萝图有永，远付当今主。", "希夷高蹈，寿康长保，五世祖孙欢聚。", "尊之至，千秋令节，万年圣父。"]'),
('song-ci-212','永遇乐','赵师侠','宋','宋词','song-ci','永遇乐','[]','秋满衡皋，淡云笼月，晚来风劲。',128,'宋词/ci.song.12000.json','["秋满衡皋，淡云笼月，晚来风劲。", "一抹残霞，数声过雁，远是黄昏近。", "凭高临远，倚楼凝睇，多少断愁幽兴。", "听渔村、鸣榔隐隐，别浦暮烟收暝。", "湘妃起舞，芳栏纫佩，约略乱峰云鬓。", "景物悲凉，楚天澄淡，过尽归帆影。", "斜阳低处，远山重叠，萧树乱鸦成阵。", "空无言，栏干凭暖，闷怀似困。"]'),
('song-ci-213','永遇乐','赵师侠','宋','宋词','song-ci','永遇乐','[]','日丽风暄，暗催春去，春尚留恋。',128,'宋词/ci.song.12000.json','["日丽风暄，暗催春去，春尚留恋。", "香褪花梢，苔侵柳径，密幄清阴展。", "海棠零乱，梨花淡伫，初听闹空莺燕。", "有轻盈、妍姿靓态，缓步阆风仙苑。", "绿丛红萼，芳鲜柔媚，约略试妆深浅。", "细叶来禽，长梢戏蝶，簇簇枝头见。", "酡颜鬒发，春愁无力，困倚画屏娇软。", "只应怕、风欺雨横，落红万点。"]'),
('song-ci-214','风入松','赵师侠','宋','宋词','song-ci','风入松','[]','溪山佳处是湘中。',88,'宋词/ci.song.12000.json','["溪山佳处是湘中。", "今古言同。", "平林远岫浑如画，更渔村、返照斜红。", "两岸荻风策策，一江秋水溶溶。", "苍涯石壁景尤雄。", "人自西东。", "利名汩没黄尘里，又那知、清胜无穷。", "何日轻舠蓑笠，持竿独钓西风。"]'),
('song-ci-215','凤凰阁','赵师侠','宋','宋词','song-ci','凤凰阁','[]','正薰风初扇，雨细梅黄暑溽。',83,'宋词/ci.song.12000.json','["正薰风初扇，雨细梅黄暑溽。", "并摇双桨去程速。", "那更黄流浩淼，白浪如屋。", "动归思、离愁万斛。", "平生奇观，颇快江山寓目。", "日斜云定晚风熟。", "白鹭飞来，点破一川明绿。", "展十幅、潇湘画轴。"]'),
('song-ci-216','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','柳眼窥春春渐吐。',70,'宋词/ci.song.12000.json','["柳眼窥春春渐吐。", "又是东风，摇曳黄金树。", "宜入新春闻好语。", "一犁处处催耕雨。", "未有花须金缕缕。", "醉梦悠扬，似蝶翩跹舞。", "一枕仙游何处去。", "觉来依旧江南住。"]'),
('song-ci-217','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','春到园林能几许。',70,'宋词/ci.song.12000.json','["春到园林能几许。", "昨夜疏疏，过却催花雨。", "暖日晴岚原上路。", "雕鞍暂系芳菲树。", "仙洞同游皆胜侣。", "翻忆年时，醉里曾寻句。", "要与龙江春作主。", "翩然又趁东风去。"]'),
('song-ci-218','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','剪剪西风催碧树。',70,'宋词/ci.song.12000.json','["剪剪西风催碧树。", "乱菊残荷，节物惊秋暮。", "绿叶红苞迎晓露。", "锦屏绣幄围芳圃。", "尘世鸾骖那肯驻。", "尚忆层城，仙苑飞琼侣。", "能共牡丹争几许。", "惜花对景聊为主。"]'),
('song-ci-219','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','百叠霜罗香蕊细。',70,'宋词/ci.song.12000.json','["百叠霜罗香蕊细。", "袅袅垂铃，缀簇黄金碎。", "独占九秋风露里。", "芳心不与群英比。", "采采东篱今古意。", "秀色堪餐，更惹兰膏腻。", "不用南山横紫翠。", "悠然消得因花醉。"]'),
('song-ci-220','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','剪水凌虚飞雪片。',70,'宋词/ci.song.12000.json','["剪水凌虚飞雪片。", "认得清香，雪树深深见。", "傅粉凝酥明玉艳。", "含章檐下春风面。", "照影溪桥情不浅。", "羌管声中，叠恨传幽怨。", "陇首人归芳信断。", "万重云水江南远。"]'),
('song-ci-221','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','夜雨鸣檐声录蔌。',70,'宋词/ci.song.12000.json','["夜雨鸣檐声录蔌。", "薄酒浇愁，不那更筹促。", "感旧伤今难举目。", "无聊独剪西窗烛。", "弹指光阴如电速。", "富贵功名，本自无心逐。", "粝食粗衣随分足。", "此身安健他何欲。"]'),
('song-ci-222','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','春入园林新雨过。',70,'宋词/ci.song.12000.json','["春入园林新雨过。", "次第芳菲，惹起情无那。", "蜀锦青红初剪破。", "枝头点点胭脂颗。", "柳带随风金袅娜。", "隐映馀霞，灿灿红云堕。", "高烛夜寒光照坐。", "只□沈醉谁扶我。"]'),
('song-ci-223','蝶恋花','赵师侠','宋','宋词','song-ci','蝶恋花','[]','解语花枝娇朵朵。',70,'宋词/ci.song.12000.json','["解语花枝娇朵朵。", "不为伤春，爱把眉峰锁。", "宜笑精神偏一个。", "微涡媚靥樱桃破。", "先自腰肢常袅娜。", "更被新来，酒饮频过火。", "茶饭不忺犹自可。", "脸儿瘦得些娘大。"]'),
('song-ci-224','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','烟霭空濛江上春。',64,'宋词/ci.song.12000.json','["烟霭空濛江上春。", "夕阳芳草渡头情。", "飞红已逐东风远，嫩绿还因夜雨深。", "情脉脉，思沈沈。", "卷帘愁与暮云平。", "栏干倚遍东西曲，杜宇一声肠断人。"]'),
('song-ci-225','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','玉带红花供奉班。',64,'宋词/ci.song.12000.json','["玉带红花供奉班。", "裹头新样总宜男。", "闹装鞍辔青骢马，帖体衣裳紫窄衫。", "云鬓重，黛眉弯。", "内家妆束冠江南。", "轻裘缓带风流帅，锦绣丛花拥骑远。"]'),
('song-ci-226','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','榕叶阴阴未著霜。',64,'宋词/ci.song.12000.json','["榕叶阴阴未著霜。", "浅寒犹试夹衣裳。", "雾浓烟重遥山暗。", "云淡天低去水长。", "风渐沥，景凄凉。", "乱鸦声里又斜阳。", "孤帆落处惊鸥鹭，飞映书空雁字行。"]'),
('song-ci-227','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','一叶惊秋风露清。',64,'宋词/ci.song.12000.json','["一叶惊秋风露清。", "砌蛩初听傍窗声。", "人逢役鹊飞乌夜，桥渡牵牛织女星。", "银汉淡，暮云轻。", "新蟾斜挂一钩明。", "人间天上佳期处，凉意还从过雨生。"]'),
('song-ci-228','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','风定江流似镜平。',64,'宋词/ci.song.12000.json','["风定江流似镜平。", "斜阳天外挂微明。", "云归远岫千山暝，雾映疏林一抹横。", "渔火细，钓丝轻。", "黄尘扑扑谩争荣。", "何时了却人间事，泛宅浮家过此生。"]'),
('song-ci-229','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','妙曲清声压楚城。',64,'宋词/ci.song.12000.json','["妙曲清声压楚城。", "蕙心兰态见柔情。", "凌波隐称金莲步，蘸甲从教玉笋斟。", "歌缓缓，笑吟吟。", "向人真处可怜生。", "仙源幸有藏春处，何事乘风逐世尘。"]'),
('song-ci-230','鹧鸪天','赵师侠','宋','宋词','song-ci','鹧鸪天','[]','爆竹声中岁又除。',64,'宋词/ci.song.12000.json','["爆竹声中岁又除。", "顿回和气满寰区。", "春风解绿江南树，不与人间染白须。", "残蜡烛，旧桃符。", "宁辞末后饮屠苏。", "归与幸有园林胜，次第花开可自娱。"]'),
('song-ci-231','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','节物推移。',61,'宋词/ci.song.12000.json','["节物推移。", "青阳景变，玉琯灰飞。", "彩仗泥牛，星球雪柳，争报春回。", "丝金缕玉幡儿。", "更斜袅、东风应时。", "宜入新春，人随春好，春与人宜。"]'),
('song-ci-232','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','红紫凋零。',61,'宋词/ci.song.12000.json','["红紫凋零。", "化工特地，剪玉裁琼。", "碧叶丛芳，檀心点素，香雪团英。", "柔风唤起娉婷。", "似无力、斜敧翠屏。", "细细吹香，盈盈浥露，花里倾城。"]'),
('song-ci-233','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','漠漠轻阴。',61,'宋词/ci.song.12000.json','["漠漠轻阴。", "养花天气，乍暗还明。", "曲径风微，蜂迷红片，蝶趁游人。", "平芜极目青青。", "谩怅望、谁招断魂。", "柳外愁闻，莺雏唤友，鸠妇呼晴。"]'),
('song-ci-234','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','料峭馀寒。',61,'宋词/ci.song.12000.json','["料峭馀寒。", "元宵欲过，灯火阑珊。", "宿酒难醒，新愁未解，摇兀吟鞍。", "深林百舌关关。", "更雨洗、桃红未乾。", "野烧痕青，荒陂水满，春事何堪。"]'),
('song-ci-235','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','烟敛云收。',61,'宋词/ci.song.12000.json','["烟敛云收。", "夕阳斜照，暮色迟留。", "天接波光，水涵山影，都在扁舟。", "虚名白尽人头。", "问来往、何时是休。", "潮落潮生，吴山越岭，依旧临流。"]'),
('song-ci-236','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','人间春足。',61,'宋词/ci.song.12000.json','["人间春足。", "一番红紫，水流风逐。", "戏蝶初闲，轻摇粉翅，高低飞扑。", "雨昏烟暝增明，似积雪、枝间映绿。", "后土琼芳，蓬莱仙伴，蕊粉香粟。"]'),
('song-ci-237','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','矫首遐观。',61,'宋词/ci.song.12000.json','["矫首遐观。", "崇台徙倚，心目俱宽。", "一水萦蓝，群峰耸翠，天接高寒。", "平生江北江南。", "总未识、闽中好山。", "雨暗前汀，云生衣袂，身倦跻攀。"]'),
('song-ci-238','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','暑怀烦郁。',61,'宋词/ci.song.12000.json','["暑怀烦郁。", "危栏徙倚，凝情独立。", "榕叶连阴，横罔接秀，壶峰凝碧。", "海山云树微茫，更无数、归帆暮集。", "却忆潇湘，孤村烟渚，晚风斜日。"]'),
('song-ci-239','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','水满方塘。',61,'宋词/ci.song.12000.json','["水满方塘。", "菰蒲深处，戏浴鸳鸯。", "灿锦舒霞，红幢绿盖，时递幽香。", "天弓摇挂孤光。", "映烟树、云间渺茫。", "散发披襟，都忘身世，真在仙乡。"]'),
('song-ci-240','柳梢青','赵师侠','宋','宋词','song-ci','柳梢青','[]','浓碧抟枝，柔黄衬紫，独殿春风。',61,'宋词/ci.song.12000.json','["浓碧抟枝，柔黄衬紫，独殿春风。", "菡萏轻盈，甘瓜馥郁，叶萼相重。", "人生一笑难同。", "更馀韵、都藏笑中。", "日助清芬，酒添风味，须与从容。"]'),
('song-ci-241','浣溪沙','赵师侠','宋','宋词','song-ci','浣溪沙','[]','日丽风和春昼长。',48,'宋词/ci.song.12000.json','["日丽风和春昼长。", "杏花枝上正芬芳。", "无情社雨亦何狂。", "一洗娇红啼嫩脸，半开新绿映残妆。", "画梁空有燕泥香。"]'),
('song-ci-242','浣溪沙','赵师侠','宋','宋词','song-ci','浣溪沙','[]','落日沈沈堕翠微。',48,'宋词/ci.song.12000.json','["落日沈沈堕翠微。", "断云轻逐晚风归。", "西山南浦画屏围。", "一目波光明欲溜，雨眉山色翠长低。", "须知人与景相宜。"]'),
('song-ci-243','浣溪沙','赵师侠','宋','宋词','song-ci','浣溪沙','[]','松雪纷纷落冻泥。',48,'宋词/ci.song.12000.json','["松雪纷纷落冻泥。", "栖禽犹困傍枝低。", "茅檐冰柱玉鞭垂。", "流水溅溅春意动，群山灿灿晓光迷。", "朔风寒日度云迟。"]'),
('song-ci-244','浣溪沙','赵师侠','宋','宋词','song-ci','浣溪沙','[]','不比阳关去路赊。',48,'宋词/ci.song.12000.json','["不比阳关去路赊。", "使君行即返京华。", "清江江上是吾家。", "聚散有时思夜雨，留连无计劝流霞。", "红愁绿惨一川花。"]'),
('song-ci-245','浣溪沙','赵师侠','宋','宋词','song-ci','浣溪沙','[]','雪絮飘池点绿漪。',48,'宋词/ci.song.12000.json','["雪絮飘池点绿漪。", "舞风游漾燕交飞。", "阴阴庭院日迟迟。", "一缕水沈香散后，半瓯新茗味回时。", "け闲万事总忘机。"]'),
('song-ci-246','浣溪沙','赵师侠','宋','宋词','song-ci','浣溪沙','[]','本是孤根傲雪霜。',48,'宋词/ci.song.12000.json','["本是孤根傲雪霜。", "肌肤不肯涴铅黄。", "要随尘世浅匀妆。", "似杏著花尤灿灿，比梅成实自双双。", "青枝巧缀碧鸳鸯。"]'),
('song-ci-247','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','扁舟又向萧滩去。',52,'宋词/ci.song.12000.json','["扁舟又向萧滩去。", "危墙却系江头树。", "风送雨声来。", "凉生真快哉。", "电光云际掣。", "白浪天相接。", "不用怯风波。", "风波平地多。"]'),
('song-ci-248','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','娇花媚柳新妆靓。',52,'宋词/ci.song.12000.json','["娇花媚柳新妆靓。", "裙边微露双鸳并。", "笑靥最多情。", "春从两脸生。", "香罗萦皓腕。", "翠袖笼歌扇。", "馀韵遏云低。", "梁尘簌簌飞。"]'),
('song-ci-249','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','晚风断送归帆急。',52,'宋词/ci.song.12000.json','["晚风断送归帆急。", "重城回首天连碧。", "犹有小楼情。", "西山如旧青。", "故园今渐近。", "应卜灯花信。", "一喜一牵萦。", "平分两处心。"]'),
('song-ci-250','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','故人心尚如天远。',52,'宋词/ci.song.12000.json','["故人心尚如天远。", "故心人更何由见。", "肠断楚江头。", "泪和江水流。", "江流空滚滚。", "泪尽情无尽。", "不怨薄情人。", "人情逐处新。"]'),
('song-ci-251','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','小春爱日融融暖。',52,'宋词/ci.song.12000.json','["小春爱日融融暖。", "危亭望处晴岚满。", "江静绿回环。", "横陈无际山。", "清霜欺远树。", "黄叶风扶去。", "试探岭头梅。", "点红开未开。"]'),
('song-ci-252','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','琼英为惜轻飞去。',52,'宋词/ci.song.12000.json','["琼英为惜轻飞去。", "可人妙笔移缣素。", "潇洒向南枝。", "永无开谢时。", "闺房难并秀。", "自是春风手。", "何必问逃禅。", "人间水墨仙。"]'),
('song-ci-253','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','多情可是怜高节。',52,'宋词/ci.song.12000.json','["多情可是怜高节。", "濡毫幻出真清绝。", "雨叶共风枝。", "天寒人倚时。", "萧萧襟韵胜。", "堪与梅兄并。", "不用翠成林。", "坡仙曾赏音。"]'),
('song-ci-254','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','霜风落木千山远。',52,'宋词/ci.song.12000.json','["霜风落木千山远。", "护霜云散晴曦暖。", "潇洒小旗亭。", "山花照眼明。", "粉妆匀未了。", "一捻春风小。", "把酒恨匆匆。", "深情妩媚中。"]'),
('song-ci-255','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','行舟荡漾鸣双桨。',52,'宋词/ci.song.12000.json','["行舟荡漾鸣双桨。", "江流为我添新涨。", "指顾隔汀洲。", "人归心尚留。", "阳关三叠举。", "怨柳离情苦。", "何似莫来休。", "不来无许愁。"]'),
('song-ci-256','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','故人话别情难已。',52,'宋词/ci.song.12000.json','["故人话别情难已。", "故人此别何时会。", "江上驻危亭。", "离怀牵故情。", "悠悠东去水。", "簇簇渔村市。", "应记合江滨。", "潇湘别故人。"]'),
('song-ci-257','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','西风又老潇湘树。',52,'宋词/ci.song.12000.json','["西风又老潇湘树。", "翩翩黄叶辞枝去。", "斜日淡云笼。", "溪山烟霭中。", "危阑闲独倚。", "縠浪连天际。", "残角起江城。", "书空征雁横。"]'),
('song-ci-258','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','东皇不受人间俗。',52,'宋词/ci.song.12000.json','["东皇不受人间俗。", "为嫌花柳纷红绿。", "特地閟春和。", "连延雨雪多。", "梅梢封玉蕊。", "春半开犹未。", "还恐怨韶华。", "吹绵作柳花。"]'),
('song-ci-259','菩萨蛮','赵师侠','宋','宋词','song-ci','菩萨蛮','[]','水风叶底波光浅。',52,'宋词/ci.song.12000.json','["水风叶底波光浅。", "亭亭翠叶红妆面。", "六月下塘春。", "平铺云锦屏。", "露凉轻点缀。", "绿映珍珠袂。", "浑似太真妃。", "倚阑娇困时。"]'),
('song-ci-260','好事近','赵师侠','宋','宋词','song-ci','好事近','[]','红杏已香残，唯有海棠堪惜。',53,'宋词/ci.song.12000.json','["红杏已香残，唯有海棠堪惜。", "天气著花如酒，醉娇红无力。", "娉娉袅袅倚东风，柔媚忍轻摘。", "凭仗暮寒要住，赛锦川春色。"]'),
('song-ci-261','好事近','赵师侠','宋','宋词','song-ci','好事近','[]','云度鹊成桥，青翼已传消息。',53,'宋词/ci.song.12000.json','["云度鹊成桥，青翼已传消息。", "彩仗蕊宫初下，应人问佳夕。", "龙烟缥渺散妆楼，香雾拥瑶席。", "准拟洞房披扇，看仙家春色。"]'),
('song-ci-262','醉蓬莱','赵师侠','宋','宋词','song-ci','醉蓬莱','[]','正金风零露，玉宇生凉，晚秋天气。',120,'宋词/ci.song.12000.json','["正金风零露，玉宇生凉，晚秋天气。", "华渚流虹，应生商佳瑞。", "电绕神枢，庆绵宗社，御宝图宸极。", "脱屣尘凡，游心澹泊，逍遥物外。", "圣子神孙，祖皇文母，上接三宫，下通五世。", "至盛难名，亘古今无比。", "诞节重明，燕乐和气，动普天均被。", "寿祝南山，尊倾北海，臣邻欢醉。"]'),
('song-ci-263','汉宫春','赵师侠','宋','宋词','song-ci','汉宫春','[]','丹诏天飞，见皇家愿治，侧席英才。',118,'宋词/ci.song.12000.json','["丹诏天飞，见皇家愿治，侧席英才。", "鸿儒抱负素蕴，壮志兴怀。", "文场战胜，便从此、脱迹蒿莱。", "人共羡，鹿鸣劝驾，还因计吏偕来。", "先春占早争开。", "是人间第一，唯有江梅。", "莆中旧传盛事，六亚三魁。", "桃花浪暖，更平地、听一声雷。", "蓝绶袅，芦鞭骏马，长安走遍天街。"]'),
('song-ci-264','厅前柳','赵师侠','宋','宋词','song-ci','厅前柳','[]','晚秋天。',71,'宋词/ci.song.12000.json','["晚秋天。", "过暮雨，云容敛，月澄鲜。", "正风露凄清处，砌蛩喧。", "更黄蝶。", "舞翩翩。", "念故里、千山云水隔，被名缰利锁萦牵。", "莫作悲秋意，对尊前。", "且同乐。", "太平年。"]'),
('song-ci-265','厅前柳','赵师侠','宋','宋词','song-ci','厅前柳','[]','景清佳。',71,'宋词/ci.song.12000.json','["景清佳。", "正倦客，凝秋思。", "浩无涯。", "递十里香芬馥，桂初华。", "向碧叶。", "露芳葩。", "为粟粒、鹅儿情淡薄，倩西风染就丹砂。", "不比黄金雨，灿馀霞。", "送幽梦，到仙家。"]'),
('song-ci-266','诉衷情','赵师侠','宋','宋词','song-ci','诉衷情','[]','清和时候雨初晴。',54,'宋词/ci.song.12000.json','["清和时候雨初晴。", "密树翠阴成。", "新篁嫩摇碧玉，芳径绿苔深。", "雏燕语，乳莺声。", "暑风轻。", "帘旌微动，沈篆烟消，午枕馀清。"]'),
('song-ci-267','诉衷情','赵师侠','宋','宋词','song-ci','诉衷情','[]','神功圣德妙难量。',54,'宋词/ci.song.12000.json','["神功圣德妙难量。", "灵应著莆阳。", "湄洲自昔仙境，宛在水中央。", "孚惠爱，备祈禳。", "降嘉祥。", "云车风马，肸蚃来歆，桂酒椒浆。"]'),
('song-ci-268','诉衷情','赵师侠','宋','宋词','song-ci','诉衷情','[]','茫茫云海浩无边。',54,'宋词/ci.song.12000.json','["茫茫云海浩无边。", "天与谁相连。", "舳舻万里来往，有祷必安全。", "专掌握，雨晹权。", "属丰年。", "琼卮玉醴，飨此精诚，福庆绵绵。"]'),
('song-ci-269','诉衷情','赵师侠','宋','宋词','song-ci','诉衷情','[]','威灵千里护封圻。',54,'宋词/ci.song.12000.json','["威灵千里护封圻。", "十万户归依。", "白湖宫殿云耸，香火尽虔祈。", "倾寿酒，诵声诗。", "谅遥知。", "民康俗阜，雨润风滋，功与天齐。"]'),
('song-ci-270','一翦梅','赵师侠','宋','宋词','song-ci','一翦梅','["\u897f\u6e56"]','雪里盈盈玉破花。',70,'宋词/ci.song.12000.json','["雪里盈盈玉破花。", "遐想风流，压尽京华。", "点酥团粉任敧斜。", "独露春妍谁似他。", "有酒何须稚子赊。", "访戴归来，倚棹溪涯。", "人生得意定谈夸。", "除却西湖，不计谁家。"]'),
('song-ci-271','一翦梅','赵师侠','宋','宋词','song-ci','一翦梅','["\u897f\u6e56"]','暖日烘梅冷未苏。',72,'宋词/ci.song.12000.json','["暖日烘梅冷未苏。", "脱叶随风，独见枯株。", "先春占早又何如。", "玉点枝头，犹自萧疏。", "江北江南景不殊。", "雪里花清，月下香浮。", "他年调鼎费工夫。", "且与藏春，处士西湖。"]'),
('song-ci-272','朝中措','赵师侠','宋','宋词','song-ci','朝中措','[]','斜阳留照有馀红。',57,'宋词/ci.song.12000.json','["斜阳留照有馀红。", "烟霭淡冥濛。", "麦陇青摇一望，前山翠失双峰。", "高台徙倚，松飘逸韵，梅减冰容。", "俯视尘寰如掌，翩然我欲乘风。"]'),
('song-ci-273','朝中措','赵师侠','宋','宋词','song-ci','朝中措','[]','疏疏帘幕映娉婷。',57,'宋词/ci.song.12000.json','["疏疏帘幕映娉婷。", "初试晓妆新。", "玉腕云边缓转，修蛾波上微颦。", "铅华淡薄，轻匀桃脸，深注樱唇。", "还似舞鸾窥沼，无情空恼行人。"]'),
('song-ci-274','朝中措','赵师侠','宋','宋词','song-ci','朝中措','[]','西风著意送归船。',57,'宋词/ci.song.12000.json','["西风著意送归船。", "家近总欣然。", "去日梅开烂漫，归时秋满山川。", "京华倦客，难堪羁思，历尽秋边。", "寄语姮娥休笑，月圆人亦团圆。"]'),
('song-ci-275','朝中措','赵师侠','宋','宋词','song-ci','朝中措','[]','乱山春过雪成堆。',57,'宋词/ci.song.12000.json','["乱山春过雪成堆。", "七里递香回。", "蕊簇玲珑金粟，花装碎屑玫瑰。", "兰衰梅谢，桃粗李俗，谁与追随。", "清绝殿春仙侣，清风吹破荼䕷。"]'),
('song-ci-276','朝中措','赵师侠','宋','宋词','song-ci','朝中措','[]','开随律琯度芳辰。',57,'宋词/ci.song.12000.json','["开随律琯度芳辰。", "鲜艳见天真。", "不比浮花浪蕊，天教月月常新。", "蔷薇颜色，玫瑰态度，宝相精神。", "休数岁时月季，仙家栏槛长春。"]'),
('song-ci-277','朝中措','赵师侠','宋','宋词','song-ci','朝中措','[]','眉间黄色喜何如。',57,'宋词/ci.song.12000.json','["眉间黄色喜何如。", "花县拜恩初。", "五品荣颁命服，十行祗奉天书。", "萱堂绣阁，均封大邑，盛事同居。", "此日银章朱绂，行看玉带金鱼。"]'),
('song-ci-278','点绛唇','赵师侠','宋','宋词','song-ci','点绛唇','[]','日暖风喧，殿春琼蕊依台榭。',50,'宋词/ci.song.12000.json','["日暖风喧，殿春琼蕊依台榭。", "雪堆花架。", "不用丹青写。", "莹彻精神，映月唯宜夜。", "幪香帕。", "倩风扶下。", "碎玉残妆卸。"]'),
('song-ci-279','点绛唇','赵师侠','宋','宋词','song-ci','点绛唇','[]','漠漠春阴，褪花时候馀寒峭。',50,'宋词/ci.song.12000.json','["漠漠春阴，褪花时候馀寒峭。", "数声啼鸟。", "唤起帘栊晓。", "云鬓慵梳，淡拂春山小。", "情多少。", "乱萦愁抱。", "风里垂杨袅。"]'),
('song-ci-280','点绛唇','赵师侠','宋','宋词','song-ci','点绛唇','[]','袅袅娉娉，可人尤赛娘风韵。',50,'宋词/ci.song.12000.json','["袅袅娉娉，可人尤赛娘风韵。", "花娇玉润。", "一捻春期近。", "占路藏机，已向棋中进。", "俱休问。", "酒旗花阵。", "早晚争先胜。"]'),
('song-ci-281','扑蝴蝶','赵师侠','宋','宋词','song-ci','扑蝴蝶','[]','清和时候，薰风来小院。',90,'宋词/ci.song.12000.json','["清和时候，薰风来小院。", "琅玕脱箨，方塘荷翠飐。", "柳丝轻度流莺，画栋低飞乳燕。", "园林绿阴初遍。", "景何限。", "轻纱细葛，纶巾和羽扇。", "披襟散发，心清尘不染。", "一杯洗涤无馀，万事消磨去远。", "浮名薄利休羡。"]'),
('song-ci-282','醉桃源・阮郎归','赵师侠','宋','宋词','song-ci','醉桃源・阮郎归','[]','微云扫尽碧虚宽。',56,'宋词/ci.song.12000.json','["微云扫尽碧虚宽。", "月华光影寒。", "山河表里鉴中看。", "沈沈清夜阑。", "风细细，露漙漙。", "神游八极间。", "九宵回首望尘寰。", "悠然醉梦还。"]'),
('song-ci-283','醉桃源・阮郎归','赵师侠','宋','宋词','song-ci','醉桃源・阮郎归','[]','纤枝延蔓走青虬。',56,'宋词/ci.song.12000.json','["纤枝延蔓走青虬。", "风清体更柔。", "故绕檀蕊著花稠。", "疏疏如缀旒。", "琼作靥，玉成裘。", "玫瑰应辈流。", "惜香愁怕罥搔头。", "宁随□事休。"]'),
('song-ci-284','醉桃源・阮郎归','赵师侠','宋','宋词','song-ci','醉桃源・阮郎归','[]','杜鹃花发映山红。',56,'宋词/ci.song.12000.json','["杜鹃花发映山红。", "韶光觉正浓。", "水流红紫各西东。", "绿肥春已空。", "闲戏蝶，懒游蜂。", "破除花影重。", "问春何事不从容。", "忧愁风雨中。"]'),
('song-ci-285','贺圣朝','赵师侠','宋','宋词','song-ci','贺圣朝','[]','千林脱落群芳息。',58,'宋词/ci.song.12000.json','["千林脱落群芳息。", "有一枝先白。", "孤标疏影压花丛，更清香堪惜。", "吟情无尽，赏音未已，早纷纷藉藉。", "想贪结子去调羹，任叫云横笛。"]'),
('song-ci-286','踏莎行','赵师侠','宋','宋词','song-ci','踏莎行','[]','白云开残，红云吹尽。',67,'宋词/ci.song.12000.json','["白云开残，红云吹尽。", "园林新绿迷芳径。", "榆钱不解青春，随风乱点苍苔晕。", "紫燕飞忙，黄鹂声嫩。", "日长烟暖游蜂困。", "凭高念远思无穷，那堪宿酒厌厌病。"]'),
('song-ci-287','踏莎行','赵师侠','宋','宋词','song-ci','踏莎行','[]','万事随缘，一身须正。',68,'宋词/ci.song.12000.json','["万事随缘，一身须正。", "功名富贵皆前定。", "多图广计要争强，如何人力将天胜。", "枉费机谋，徒劳奔竞。", "到头毕竟由他命。", "安时处顺得心闲，饥餐困寝亏贤甚。"]'),
('song-ci-288','忆秦娥','赵师侠','宋','宋词','song-ci','忆秦娥','[]','伤离索。',56,'宋词/ci.song.12000.json','["伤离索。", "不堪凉月穿珠箔。", "穿珠箔。", "料应别后，粉销琼削。", "无聊倚遍西楼角。", "枝头几误惊飞鹊。", "惊飞鹊。", "先来憔悴，更逢摇落。"]'),
('song-ci-289','武陵春','赵师侠','宋','宋词','song-ci','武陵春','[]','一阵晓风花信早，先到小桃枝。',56,'宋词/ci.song.12000.json','["一阵晓风花信早，先到小桃枝。", "冉冉红云映翠微。", "开宴忆瑶池。", "零乱分飞贪结子，芳径自成蹊。", "消得刘郎去路迷。", "肠断武陵溪。"]'),
('song-ci-290','武陵春','赵师侠','宋','宋词','song-ci','武陵春','[]','乍雨笼晴云不定，芳草绿纤柔。',58,'宋词/ci.song.12000.json','["乍雨笼晴云不定，芳草绿纤柔。", "燕语莺啼小院幽。", "春色二分休。", "试凭危栏凝远目，山与水光浮。", "滚滚闲愁逐水流。", "流不尽、许多愁。"]'),
('song-ci-291','清平乐','赵师侠','宋','宋词','song-ci','清平乐','[]','无风轻燕。',54,'宋词/ci.song.12000.json','["无风轻燕。", "缭绕深深院。", "昼永人闲帘不卷。", "时听莺簧巧啭。", "清和天气阴阴。", "南风初奏薰琴。", "唤起午窗新梦，愁添一掬归心。"]'),
('song-ci-292','清平乐','赵师侠','宋','宋词','song-ci','清平乐','[]','一宵风雨。',54,'宋词/ci.song.12000.json','["一宵风雨。", "春与人俱去。", "春解再来花作主。", "只有行人无据。", "殷勤满酌离觞。", "阳关唱起愁肠。", "苦恨无情杜宇，声声叫断斜阳。"]'),
('song-ci-293','清平乐','赵师侠','宋','宋词','song-ci','清平乐','[]','纤秾娇小。',54,'宋词/ci.song.12000.json','["纤秾娇小。", "也解争春早。", "占得中央颜色好。", "装点枝枝新巧。", "东皇初到江城。", "殷勤先去迎春。", "乞与黄金腰带，压持红紫纷纷。"]'),
('song-ci-294','鹊桥仙','赵师侠','宋','宋词','song-ci','鹊桥仙','[]','风波平地，尘埃扑面，总是争名竞利。',68,'宋词/ci.song.12000.json','["风波平地，尘埃扑面，总是争名竞利。", "悟时不必苦贪图，但言任、流行坎止。", "忽来忽去，何荣何辱，天也知人深意。", "一帆风送过桐江，喜跳出、琉璃井里。"]'),
('song-ci-295','鹊桥仙','赵师侠','宋','宋词','song-ci','鹊桥仙','[]','同云幕幕，狂风浩浩，激就六花飞下。',68,'宋词/ci.song.12000.json','["同云幕幕，狂风浩浩，激就六花飞下。", "山川满目白模糊，更茅舍、溪桥潇洒。", "玉田银界，瑶林琼树，光映乾坤不夜。", "行人不为旅人忙，怎解识、天然图画。"]'),
('song-ci-296','鹊桥仙','赵师侠','宋','宋词','song-ci','鹊桥仙','[]','春光已暮，花残叶密，更值无情风雨。',68,'宋词/ci.song.12000.json','["春光已暮，花残叶密，更值无情风雨。", "斜阳芳树翠烟中，又听得、声声杜宇。", "血流无用，离魂空断，只挠凄凉为旅。", "在家谁道不如归，你何似、随风归去。"]'),
('song-ci-297','鹊桥仙','赵师侠','宋','宋词','song-ci','鹊桥仙','[]','明河风细，鹊桥云淡，秋入庭梧先坠。',69,'宋词/ci.song.12000.json','["明河风细，鹊桥云淡，秋入庭梧先坠。", "摩孩罗荷叶伞儿轻，总排列、双双对对。", "花瓜应节、蛛丝卜巧，望月穿针楼外。", "不知谁见女牛忙，谩多少、人间欢会。"]'),
('song-ci-298','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','风和雨。',53,'宋词/ci.song.12000.json','["风和雨。", "又送一番春去。", "春去不知何处住。", "惜春无觅处。", "柳老空抟香絮。", "莺娇乍迁芳树。", "回念故园如旧否。", "不堪闻杜宇。"]'),
('song-ci-299','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','江水绿。',53,'宋词/ci.song.12000.json','["江水绿。", "江山数峰如簇。", "唤渡小舟来岸北。", "笋舆行太速。", "素艳窗纱笼玉。", "埠负看花心目。", "今夜知他何处宿。", "断魂沙路曲。"]'),
('song-ci-300','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','沙畔路。',53,'宋词/ci.song.12000.json','["沙畔路。", "记得旧时行处。", "蔼蔼疏烟迷远树。", "野航横不渡。", "竹里疏花梅吐。", "照眼一川鸥鹭。", "家在清江江上住。", "水流愁不去。"]'),
('song-ci-301','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','风雨急。',53,'宋词/ci.song.12000.json','["风雨急。", "红紫又还狼藉。", "嫩绿团枝苔径湿。", "帘开双燕入。", "院静昼闲人寂。", "一缕水沈烟直。", "心事有谁能会得。", "阶前芳草碧。"]'),
('song-ci-302','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','风策策。',53,'宋词/ci.song.12000.json','["风策策。", "山迥暮烟横白。", "淅沥穿林翻败叶。", "羁怀愁倦客。", "问宿荒村山驿。", "谁识离情脉脉。", "雁足无书孤夜色。", "音尘千里隔。"]'),
('song-ci-303','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','花夜雨。',53,'宋词/ci.song.12000.json','["花夜雨。", "渺渺绿波南浦。", "擘絮晴云山外吐。", "凝情谁共语。", "十二玉梯空伫。", "闲却琐窗朱户。", "久客念归归未许。", "寸心愁万缕。"]'),
('song-ci-304','谒金门','赵师侠','宋','宋词','song-ci','谒金门','[]','风雨半。',53,'宋词/ci.song.12000.json','["风雨半。", "春锁绿杨深院。", "幕浪不翻香穗卷。", "轻寒闲便面。", "归兴新来不浅。", "勾引闲愁撩乱。", "一枕春酲谁与管。", "晓莺惊梦断。"]'),
('song-ci-305','东坡引','赵师侠','宋','宋词','song-ci','东坡引','[]','相看情未足。',64,'宋词/ci.song.12000.json','["相看情未足。", "离觞已催促。", "停歌欲语眉先蹙。", "何期归太速。", "如今去也，无计追逐。", "怎忍听、阳关曲。", "扁舟后夜滩头宿。", "愁随烟树簇。", "愁随烟树簇。"]'),
('song-ci-306','东坡引','赵师侠','宋','宋词','song-ci','东坡引','[]','飞花红不聚。',64,'宋词/ci.song.12000.json','["飞花红不聚。", "都因夜来雨。", "枝头冷落情如许。", "东风谁是主。", "看看满地，堆却香絮。", "但目断、章台路。", "残英剩蕊留春住。", "春归何处去。", "春归何处去。"]'),
('song-ci-307','东坡引','赵师侠','宋','宋词','song-ci','东坡引','[]','杯行情意密。',64,'宋词/ci.song.12000.json','["杯行情意密。", "今宵是何夕。", "行人此别真堪惜。", "愁肠空闷郁。", "明朝去也，回首相忆。", "要留恋、如何得。", "无端骤雨飘何急。", "人来心上滴。", "人来心上滴。"]'),
('song-ci-308','生查子','赵师侠','宋','宋词','song-ci','生查子','[]','梅从陇首传，柳向邮亭折。',48,'宋词/ci.song.12000.json','["梅从陇首传，柳向邮亭折。", "鸳瓦晓霜浓，掠面凝寒色。", "相逢意便亲，欲去如何说。", "我亦是行人，更与行人别。"]'),
('song-ci-309','生查子','赵师侠','宋','宋词','song-ci','生查子','[]','千山拥翠屏，一水萦罗带。',48,'宋词/ci.song.12000.json','["千山拥翠屏，一水萦罗带。", "雨过水痕添，云散山容在。", "亭高景最幽，天回风尤快。", "啼鸟一声闲，唤起情无奈。"]'),
('song-ci-310','生查子','赵师侠','宋','宋词','song-ci','生查子','[]','迟迟春昼长，冉冉东风软。',48,'宋词/ci.song.12000.json','["迟迟春昼长，冉冉东风软。", "寒食乍晴天，红紫芳菲遍。", "前峰积翠横，新涨挼蓝远。", "向晚淡烟迷，一段屏山展。"]'),
('song-ci-311','生查子','赵师侠','宋','宋词','song-ci','生查子','[]','春光不肯留，风雨催将去。',48,'宋词/ci.song.12000.json','["春光不肯留，风雨催将去。", "红逐故园尘，绿满江南树。", "阴晴寒食天，寂寞西郊路。", "芳草织新愁，怅望人何处。"]'),
('song-ci-312','生查子','赵师侠','宋','宋词','song-ci','生查子','[]','庭虚任雀喧，院静无人到。',48,'宋词/ci.song.12000.json','["庭虚任雀喧，院静无人到。", "回首十年非，赖得知几早。", "心随香篆销，意与梅花好。", "万事转头空，一笑吾身老。"]'),
('song-ci-313','少年游','赵师侠','宋','宋词','song-ci','少年游','[]','玉壶冰结暮天寒。',60,'宋词/ci.song.12000.json','["玉壶冰结暮天寒。", "朔吹绕阑干。", "雪破梢头，香传花外，春信入江南。", "巡檐索笑情无限，一点已微酸。", "待得黄垂，冥冥烟雨，绿树袅金丸。"]'),
('song-ci-314','少年游','赵师侠','宋','宋词','song-ci','少年游','[]','冰霜凝冻腊残时。',60,'宋词/ci.song.12000.json','["冰霜凝冻腊残时。", "暖律渐推移。", "彩胜罗幡，土牛春杖，和气与春回。", "花心柳眼知时节，微露向阳枝。", "喜入新春，称心百事，如意想都宜。"]'),
('song-ci-315','小重山','赵师侠','宋','宋词','song-ci','小重山','[]','乐岁农家喜夜春。',70,'宋词/ci.song.12000.json','["乐岁农家喜夜春。", "朝来收宿雾，快新晴。", "云移日转午风轻。", "香罗薄，喧暖困游人。", "积水满春塍。", "绿波翻郁郁，露秧针。", "幸无离绪苦牵情。", "烟林外，时听杜鹃声。"]'),
('song-ci-316','霜天晓角','赵师侠','宋','宋词','song-ci','霜天晓角','[]','雨馀风劲。',53,'宋词/ci.song.12000.json','["雨馀风劲。", "雾重千山暝。", "茅舍寒林相映。", "分明是、图画景。", "去程何日定。", "天远长安近。", "唤起新愁无尽。", "全没个、故园信。"]'),
('song-ci-317','霜天晓角','赵师侠','宋','宋词','song-ci','霜天晓角','[]','舣舟砂碛。',53,'宋词/ci.song.12000.json','["舣舟砂碛。", "秋净波澄碧。", "极目青山横远，悬崖断、拥苍壁。", "傍岩渔艇集。", "渡头人物立。", "八景潇湘真画，云笼日、晚风急。"]'),
('song-ci-318','江南好・忆江南','赵师侠','宋','宋词','song-ci','江南好・忆江南','[]','天共水，水远与天连。',64,'宋词/ci.song.12000.json','["天共水，水远与天连。", "天净水平寒月漾，水光月色两相兼。", "月映水中天。", "人与景，人景古难全。", "景若佳时心自快，心远乐处景应妍。", "休与俗人言。"]'),
('song-ci-319','关河令・清商怨','赵师侠','宋','宋词','song-ci','关河令・清商怨','[]','亭皋霜重飞叶满。',52,'宋词/ci.song.12000.json','["亭皋霜重飞叶满。", "听西风断雁。", "闲凭危阑，斜阳红欲敛。", "行人归期太晚。", "误仿佛、征帆几点。", "水远连天，愁云遮望眼。"]'),
('song-ci-320','关河令・清商怨','赵师侠','宋','宋词','song-ci','关河令・清商怨','[]','江头伊轧动柔橹。',52,'宋词/ci.song.12000.json','["江头伊轧动柔橹。", "渐楚天欲暮。", "浩荡轻鸥，波间自容与。", "岸蓼汀苹无绪。", "更满目、潇疏江树。", "此意何穷，凭谁图画取。"]'),
('song-ci-321','采桑子','赵师侠','宋','宋词','song-ci','采桑子','[]','连朝雨骤驱春去，瓦注盆倾。',52,'宋词/ci.song.12000.json','["连朝雨骤驱春去，瓦注盆倾。", "不记初春。", "润柳催花忒有情。", "春光解有重来日，宁耐休争。", "待得秋深。", "听你无聊点滴声。"]'),
('song-ci-322','采桑子','赵师侠','宋','宋词','song-ci','采桑子','[]','梅花谢后樱花绽，浅浅匀红。',52,'宋词/ci.song.12000.json','["梅花谢后樱花绽，浅浅匀红。", "试手天工。", "百卉千葩一信通。", "馀寒未许开舒妥，怨雨愁风。", "结子筠笼。", "万颗匀圆讶许同。"]'),
('song-ci-323','浪淘沙','赵师侠','宋','宋词','song-ci','浪淘沙','[]','绛萼衬轻红。',64,'宋词/ci.song.12000.json','["绛萼衬轻红。", "缀簇玲珑。", "夭桃繁李一时同。", "独向枝头春意闹，娇倚东风。", "飞片入帘栊。", "粉淡香浓。", "凤箫声断月明中。", "只恐明朝风雨恶，燕嘴泥融。"]'),
('song-ci-324','浪淘沙','赵师侠','宋','宋词','song-ci','浪淘沙','[]','桃萼正芳菲。',64,'宋词/ci.song.12000.json','["桃萼正芳菲。", "初占春时。", "蒸霞灿锦望中迷。", "斜出繁枝临曲沼，鸾鉴妆迟。", "蜂蝶镇相依。", "天气融怡。", "空教追忆武陵溪。", "片片漫随流水去，风暖烟霏。"]'),
('song-ci-325','浪淘沙','赵师侠','宋','宋词','song-ci','浪淘沙','[]','摇曳万丝风。',64,'宋词/ci.song.12000.json','["摇曳万丝风。", "轻染烟浓。", "鹅黄初褪绿茸茸。", "雨洗云娇春向晚，雪絮空濛。", "车马灞桥中。", "别绪匆匆。", "只知攀折怨西东。", "不道晓风残月岸，离恨无穷。"]'),
('song-ci-326','双头莲令','赵师侠','宋','宋词','song-ci','双头莲令','[]','太平和气兆嘉祥。',56,'宋词/ci.song.12000.json','["太平和气兆嘉祥。", "草木总成双。", "红苞翠盖出横塘。", "两两斗芬芳。", "干摇碧玉并青房。", "仙髻拥新妆。", "连枝不解引鸾皇。", "留取映鸳鸯。"]'),
('song-ci-327','画堂春','赵师侠','宋','宋词','song-ci','画堂春','[]','西真仙子宴瑶池。',55,'宋词/ci.song.12000.json','["西真仙子宴瑶池。", "素裳琼艳冰肌。", "瑞笼香雾扑铢衣。", "凤翥鸾飞。", "玉骨解凌风露，铅华不涴凝脂。", "戍楼羌管正孤吹。", "月淡烟低。"]'),
('song-ci-328','南柯子・南歌子','赵师侠','宋','宋词','song-ci','南柯子・南歌子','[]','木落千山瘦，风微一水澄。',62,'宋词/ci.song.12000.json','["木落千山瘦，风微一水澄。", "清霜暖日快归程。", "唤渡沙头、款款话离情。", "傍岸渔舟集，横空雁字轻。", "凭阑凝望眼增明。", "一片潇湘、真个画难成。"]'),
('song-ci-329','西江月','赵师侠','宋','宋词','song-ci','西江月','[]','笳鼓旌旗改色，弓刀铠甲增明。',58,'宋词/ci.song.12000.json','["笳鼓旌旗改色，弓刀铠甲增明。", "攒花簇队马蹄轻。", "禀听元戎号令。", "羊祐轻裘临阵，亚夫细柳屯营。", "观瞻已耸定王城。", "飞虎威名日振。"]'),
('song-ci-330','西江月','赵师侠','宋','宋词','song-ci','西江月','[]','淼淼澄清波面，依依紫翠山光。',58,'宋词/ci.song.12000.json','["淼淼澄清波面，依依紫翠山光。", "危栏徙倚对斜阳。", "山影波流荡漾。", "世事一番醒醉，人生几度炎凉。", "高情收拾付觥觞。", "何止羲皇人上。"]'),
('song-ci-331','洞仙歌','赵师侠','宋','宋词','song-ci','洞仙歌','[]','元宵三五。',108,'宋词/ci.song.12000.json','["元宵三五。", "正好嬉游去。", "梅柳蛾蝉斗济楚。", "换鞋儿、添头面，只等黄昏，恰恨有、些子无情风雨。", "心忙腹热，没顿浑身处。", "急把灯台炙艾炷。", "做匙婆、许葱油，麦灰画葫芦，更漏转，越㬠不停不住。", "待归去、尤自意迟疑，但无语空将，眼儿厮觑。"]'),
('song-ci-332','南乡子','赵师侠','宋','宋词','song-ci','南乡子','[]','元夜景尤殊。',66,'宋词/ci.song.12000.json','["元夜景尤殊。", "万斛金莲照九衢。", "锤拍豉汤都卖得，争如。", "甘露杯中万颗珠。", "应是著功夫。", "脑麝浓薰费小厨。", "不比七夕黄蜡做，知无。", "要底圆儿糖上浮。"]'),
('song-ci-333','行香子','赵师侠','宋','宋词','song-ci','行香子','[]','春日迟迟。',84,'宋词/ci.song.12000.json','["春日迟迟。", "春景熙熙。", "渐郊原、芳草萋萋。", "夭桃灼灼，杨柳依依。", "见燕喃喃，蜂簇簇，蝶飞飞。", "闲庭寂寂，曲沼漪漪。", "更秋千、红索垂垂。", "游人队队，乐意嬉嬉。", "尽醉醺醺，歌缓缓，语低低。"]'),
('song-ci-334','卜算子','赵师侠','宋','宋词','song-ci','卜算子','[]','晴日敛春泥，陌上东风软。',52,'宋词/ci.song.12000.json','["晴日敛春泥，陌上东风软。", "料峭寒禁花柳闲，枉恨春工浅。", "绿涨一江深，黛泼千山远。", "目断平芜无际愁，数尽征鸿点。"]'),
('song-ci-335','卜算子','赵师侠','宋','宋词','song-ci','卜算子','[]','杨柳褪金丝，艳杏摇红影。',52,'宋词/ci.song.12000.json','["杨柳褪金丝，艳杏摇红影。", "欲雨还晴二月天，春色浑无定。", "晓梦不堪惊，午昼新来永。", "一掬归心万叠愁，空惹长亭恨。"]'),
('song-ci-336','卜算子','赵师侠','宋','宋词','song-ci','卜算子','[]','娇艳醉杨妃，轻袅怜飞燕。',52,'宋词/ci.song.12000.json','["娇艳醉杨妃，轻袅怜飞燕。", "人在昭阳睡足时，初试妆深浅。", "一段锦新裁，万里来何远。", "高烛休教照夜寒，媚脸融春艳。"]'),
('song-ci-337','卜算子','赵师侠','宋','宋词','song-ci','卜算子','[]','绿暗柳藏烟，红淡花经雨。',52,'宋词/ci.song.12000.json','["绿暗柳藏烟，红淡花经雨。", "更著如花似玉人，艳态娇波注。", "纤手捧瑶卮，缓遏歌云缕。", "只恐莺花不解留，还逐东风去。"]'),
('song-ci-338','卜算子','赵师侠','宋','宋词','song-ci','卜算子','[]','云敛料寒轻，雨涨春波渺。',52,'宋词/ci.song.12000.json','["云敛料寒轻，雨涨春波渺。", "旅枕无堪梦易惊，啼鴂声催晓。", "尚忆故园花，红紫为容好。", "世路崎岖长短亭，来往何时了。"]'),
('song-ci-339','伊州三台','赵师侠','宋','宋词','song-ci','伊州三台','[]','桂华移自云岩。',58,'宋词/ci.song.12000.json','["桂华移自云岩。", "更被灵砂染丹。", "清露湿酡颜。", "醉乘风、下临世间。", "素娥襟韵萧闲。", "不与群芳并看。", "蔌蔌绛绡单。", "觉身轻、梦回广寒。"]'),
('song-ci-340','水调歌头','陈亮','宋','宋词','song-ci','水调歌头','[]','不见南师久，谩说北群空。',114,'宋词/ci.song.12000.json','["不见南师久，谩说北群空。", "当场只手，毕竟还我万夫雄。", "自笑堂堂汉使，得似洋洋河水，依旧只流东。", "且复穹庐拜，会向藁街逢。", "尧之都，舜之壤，禹之封。", "於中应有，一个半个耻臣戎。", "万里腥膻如许，千古英灵安在，磅礴几时通。", "胡运何须问，赫日自当中。"]'),
('song-ci-341','念奴娇','陈亮','宋','宋词','song-ci','念奴娇','[]','江南春色，算来是、多少胜游清赏。',121,'宋词/ci.song.12000.json','["江南春色，算来是、多少胜游清赏。", "妖冶廉纤，只做得，飞鸟向人偎傍。", "地辟天开，精神朗慧，到底还京样。", "人家小语，一声声近清唱。", "因念旧日山城，个人如画，已作州中想。", "邓禹笑人无限也，冷落不堪惆怅。", "秋水双明，高山一弄，著我些悲壮。", "南徐好住，片帆有分来往。"]'),
('song-ci-342','贺新郎','陈亮','宋','宋词','song-ci','贺新郎','[]','修竹更深处。',140,'宋词/ci.song.12000.json','["修竹更深处。", "映帘栊、清阴障日，坐来无暑。", "水激泠泠如何许。", "跳碎危栏玉树。", "都不系、人间朝暮。", "东阁少年今老矣，况樽中有酒嫌推去。", "犹著我，明流语。", "大家绿野陪容与。", "算等闲、过了薰风，又还商素。", "手弄柔条人健否，尤忆当时雅趣。", "恩未报、恐成辜负。", "举目江河休感涕，念有君如此何愁虏。", "歌未罢，谁来舞。"]'),
('song-ci-343','满江红','陈亮','宋','宋词','song-ci','满江红','[]','曾洗乾坤，问何事、雄图顿屈。',113,'宋词/ci.song.12000.json','["曾洗乾坤，问何事、雄图顿屈。", "试著眼、阶除当下，又添英物。", "北向争衡幽愤在，南来遗恨狂酋失。", "算凄凉部曲几人存，三之一。", "诸老尽，郎君出。", "恩未报，家何恤。", "念横飞直上，有时还戢。", "笑我只知存饱暖，感君元不论阶级。", "休更上百尺旧家楼，尘侵帙。"]'),
('song-ci-344','桂枝香','陈亮','宋','宋词','song-ci','桂枝香','[]','天高气肃。',124,'宋词/ci.song.12000.json','["天高气肃。", "正月色分明，秋容新沐。", "桂子初收，三十六宫都足。", "不辞散落人间去，怕群花、自嫌凡俗。", "向他秋晚，唤回春意，几曾幽独。", "是天上、馀香剩馥。", "怪一树香风，十里相续。", "坐对花旁，但见色浮金粟。", "芙蓉只解添秋思，况东篱、凄凉黄菊。", "入时太浅，背时太远，爱寻高躅。"]'),
('song-ci-345','三部乐','陈亮','宋','宋词','song-ci','三部乐','[]','小屈穹庐，但二满三平，共劳均佚。',122,'宋词/ci.song.12000.json','["小屈穹庐，但二满三平，共劳均佚。", "人中龙虎，本为明时而出。", "只合是、端坐王朝，看指挥整办，扫荡飘忽。", "也持汉节，聊过旧家宫室。", "西风又还带暑，把征衫著上，有时披拂。", "休将看花泪眼，闻弦□骨。", "对遗民、有如皎日。", "行万里、依然故物。", "入奏几策，天下里、终定于一。"]'),
('song-ci-346','水调歌头','陈亮','宋','宋词','song-ci','水调歌头','[]','人物从来少，篱菊为谁黄。',114,'宋词/ci.song.12000.json','["人物从来少，篱菊为谁黄。", "去年今日，倚楼还是听行藏。", "未觉霜风无赖，好在月华如水，心事楚天长。", "讲论参洙泗，杯酒到虞唐。", "人未醉，歌宛转，兴悠扬。", "太平胸次，笑他磊磈欲成狂。", "且向武夷深处，坐对云烟开敛，逸思如微茫。", "我欲为君寿，何许得新腔。"]'),
('song-ci-347','念奴娇','陈亮','宋','宋词','song-ci','念奴娇','["\u957f\u6c5f"]','危楼远望，叹此意、今古几人曾会。',121,'宋词/ci.song.12000.json','["危楼远望，叹此意、今古几人曾会。", "鬼设神施，浑认作、天限南疆北界。", "一水横陈，莲岗三面，做出争雄势。", "六朝何事，只成门户私计。", "因笑王谢诸人，登高怀远，也学英雄涕。", "凭却长江管不到，河洛腥膻无际。", "正好长驱，不须反顾，寻取中流誓。", "小儿破贼，势成宁问疆场。"]'),
('song-ci-348','贺新郎','陈亮','宋','宋词','song-ci','贺新郎','[]','老去凭谁说。',142,'宋词/ci.song.12000.json','["老去凭谁说。", "看几番、神奇臭腐，夏裘冬葛。", "父老长安今馀几，后死无仇可雪。", "犹未燥、当时生发。", "二十五弦多少恨，算世间、那有平分月。", "胡妇弄，汉宫瑟。", "树犹如此堪重别。", "只使君、从来与我，话头多合。", "行矣置之无足问，谁唤妍皮痴骨。", "但莫使、伯牙弦绝。", "九转丹砂牢拾取，管精金、只是寻常铁。", "龙共虎，应声裂。"]'),
('song-ci-349','瑞云浓慢','陈亮','宋','宋词','song-ci','瑞云浓慢','[]','蔗浆酪粉，玉壶冰醑，朝罢更闻宣赐。',124,'宋词/ci.song.12000.json','["蔗浆酪粉，玉壶冰醑，朝罢更闻宣赐。", "去天咫尺，下拜再三，幸今有母可遗。", "年年此日，共道月入怀中最贵。", "向暑天，正风云会遇，有恁嘉瑞。", "鹤冲霄，鱼得水。", "一超便、直入神仙地。", "植根江表。", "开拓两河，做得黑头公未。", "骑鲸赤手，问如何、长鞭尺箠。", "向来王谢风流，只今管是。"]'),
('song-ci-350','阮郎归','陈亮','宋','宋词','song-ci','阮郎归','[]','波光渺渺浸晴陂。',56,'宋词/ci.song.12000.json','["波光渺渺浸晴陂。", "有亭湖岸西。", "芰荷香拂柳丝垂。", "升堂献寿卮。", "红约腕，绿侵衣。", "愿祝届期颐。", "花间妙语欲无诗。", "一年歌一词。"]'),
('song-ci-351','祝英台近','陈亮','宋','宋词','song-ci','祝英台近','[]','驾扁舟，冲剧暑。',95,'宋词/ci.song.12000.json','["驾扁舟，冲剧暑。", "千里江上去。", "夜宿晨兴，一一旧时路。", "百年望了旬头，被人馋破，故纸里、是争雄处。", "怎生诉。", "欲待细与分疏，其如有凭据。", "包裹生鱼，活底怎遭遇。", "相逢樽酒何时，征衫容易，君去也、自家须住。"]'),
('song-ci-352','蝶恋花','陈亮','宋','宋词','song-ci','蝶恋花','[]','手拈黄花还自笑。',70,'宋词/ci.song.12000.json','["手拈黄花还自笑。", "笑比渊明，莫也归来早。", "随世功名浑草草。", "五湖却共繁华老。", "冷淡家生冤得道。", "旖旎妖娆，春梦如今觉。", "管个岁华须到了。", "此花之后花应少。"]'),
('song-ci-353','水调歌头','陈亮','宋','宋词','song-ci','水调歌头','[]','人爱新来景，龙认旧时湫。',114,'宋词/ci.song.12000.json','["人爱新来景，龙认旧时湫。", "不论三伏，小住便觉凛生秋。", "我自醉眠其上，任是水流其下，湍激若为收。", "世事如斯去，不去为谁留。", "本无心，随所寓，触虚舟。", "东山始末，且向灵洞与沈浮。", "料得神仙窟穴，争似提封万里，大小几琉球。", "但有君才具，何用问时流。"]'),
('song-ci-354','念奴娇','陈亮','宋','宋词','song-ci','念奴娇','[]','西风带暑，又还是、长途利牵名役。',122,'宋词/ci.song.12000.json','["西风带暑，又还是、长途利牵名役。", "我已无心，君因甚，更把青衫为客。", "邂逅卑飞，几时高举，不露真消息。", "大家行处，到头须管行得。", "何处寻取狂徒，可能著意，更问渠侬骨。", "天上人间，最好是、闹里一般岑寂。", "瀛海无波，玉堂有路，稳著青霄翼。", "归来何事，眼光依旧生碧。"]'),
('song-ci-355','卜算子','陈亮','宋','宋词','song-ci','卜算子','[]','悄静菊花天，洗尽梧桐雨。',52,'宋词/ci.song.12000.json','["悄静菊花天，洗尽梧桐雨。", "倍九周遭烂熳开，祝寿当头取。", "顶戴玉袍黄，叠秀金棱吐。", "仙种花容晚节香，人愿争先睹。"]'),
('song-ci-356','贺新郎','陈亮','宋','宋词','song-ci','贺新郎','[]','离乱从头说。',141,'宋词/ci.song.12000.json','["离乱从头说。", "爱吾民，金缯不爱，蔓藤累葛。", "壮气尽消人脆好，冠盖阴山观雪。", "亏杀我，一星星发。", "涕出女吴成倒转，问鲁为齐弱何年月。", "丘也幸，由之瑟。", "斩新换出旗麾别。", "把当时、一椿大义，拆开收合。", "据地一呼吾往矣，万里摇肢动骨。", "这话霸、又成痴绝。", "天地洪炉谁扇韛，算於中、安得长坚铁。", "淝水破，关东裂。"]'),
('song-ci-357','垂丝钓','陈亮','宋','宋词','song-ci','垂丝钓','[]','菊花细雨。',81,'宋词/ci.song.12000.json','["菊花细雨。", "萧萧红蓼汀渚。", "景物渐幽，风致如许。", "秋未暮。", "又值吾初度。", "看天宇。", "正澄清欲往，登高未也，红尘当面飞舞。", "几人吊古。", "乌帽牢收取。", "短发还羞觑。", "遐寿身、近五云深处。"]'),
('song-ci-358','彩凤飞','陈亮','宋','宋词','song-ci','彩凤飞','[]','人立玉，天如水，特地如何撰。',102,'宋词/ci.song.12000.json','["人立玉，天如水，特地如何撰。", "海南沈烧著，欲寒犹暖。", "算从头，有多少、厚德阴功，人家上，一一旧时香案。", "□煞经惯。", "小驻吾舟才尔，依然欢声满。", "莫也教、公子王孙眼见。", "这些儿、颖脱处，高出书卷。", "经纶自入手，不了判断。"]'),
('song-ci-359','鹧鸪天','陈亮','宋','宋词','song-ci','鹧鸪天','[]','落魄行歌记昔游。',64,'宋词/ci.song.12000.json','["落魄行歌记昔游。", "头颅如许尚何求。", "心肝吐尽无馀事，口腹安然岂远谋。", "才怕暑，又伤秋。", "天涯梦断有书不。", "大都眼孔新来浅，羡尔微官作计周。"]'),
('song-ci-360','谒金门','陈亮','宋','宋词','song-ci','谒金门','[]','新雨足。',53,'宋词/ci.song.12000.json','["新雨足。", "洗尽山城袢褥。", "见说好峰三十六。", "峰峰如立玉。", "四海英游追逐。", "事业相时伸缩。", "入境德星须做福。", "只愁金诏趣。"]'),
('song-ci-361','天仙子','陈亮','宋','宋词','song-ci','天仙子','[]','一夜秋光先著柳。',80,'宋词/ci.song.12000.json','["一夜秋光先著柳。", "暑力平明羞失守。", "西风不放入帘帏，饶永昼。", "沈烟透。", "半月十朝秋定否。", "指点芙蕖凝伫久。", "高处成莲深处藕。", "百年长共月团圆，女进男，酒称寿。", "一点浮云人似旧。"]'),
('song-ci-362','水调歌头','陈亮','宋','宋词','song-ci','水调歌头','[]','事业随人品，今古几麾旌。',114,'宋词/ci.song.12000.json','["事业随人品，今古几麾旌。", "向来谋国，万事尽出汝书生。", "安识鲲鹏变化，九万里风在下，如许上南溟。", "斥鷃旁边笑，河汉一头倾。", "叹世间，多少恨，几时平。", "霸图消歇，大家创见又成惊。", "邂逅汉家龙种，正尔乌纱白纻，驰骛觉身轻。", "樽酒从渠说，双眼为谁明。"]'),
('song-ci-363','洞仙歌','陈亮','宋','宋词','song-ci','洞仙歌','[]','秋容一洗，不受凡尘涴。',107,'宋词/ci.song.12000.json','["秋容一洗，不受凡尘涴。", "许大乾坤这回大。", "向上头，些子是雕鹗抟空，篱底下，只有黄花几朵。", "骑鲸汗慢，那得人同坐。", "赤手丹心扑不破。", "问唐虞、禹汤文武，多少功名，犹自是、一点浮云铲过。", "且烧却、一瓣海南沈，任拈取、千年陆沈奇货。"]'),
('song-ci-364','祝英台近','陈亮','宋','宋词','song-ci','祝英台近','[]','嫩寒天，金气雨，揽断一秋事。',94,'宋词/ci.song.12000.json','["嫩寒天，金气雨，揽断一秋事。", "仝样霏微，远作小晴意。", "世间万宝都成，些儿无欠，只待与、黄花为地。", "好招致。", "对此郁郁葱葱，新篘未成醉。", "翻手为云，造物等儿戏。", "也知富贵来时，一班呈露，便做出人中祥瑞。"]'),
('song-ci-365','踏莎行','陈亮','宋','宋词','song-ci','踏莎行','[]','书册如仇，旧游浑讳。',68,'宋词/ci.song.12000.json','["书册如仇，旧游浑讳。", "有怀不断人应异。", "千山上去梦魂轻，片帆似下蛮溪水。", "已共酒杯，长坚海誓。", "见君忽忘花前醉。", "从来解事苦无多，不知解到毫芒未。"]'),
('song-ci-366','南乡子','陈亮','宋','宋词','song-ci','南乡子','[]','人物满东瓯。',66,'宋词/ci.song.12000.json','["人物满东瓯。", "别我江心识俊游。", "北尽平芜南似画，中流。", "谁系龙骧万斛舟。", "去去几时休。", "犹自潮上更来头。", "醉墨淋漓人感旧，离愁。", "一夜西风似夏不。"]'),
('song-ci-367','三部乐','陈亮','宋','宋词','song-ci','三部乐','[]','入脚西风，渐去去来来，早三之一。',122,'宋词/ci.song.12000.json','["入脚西风，渐去去来来，早三之一。", "春花无数，毕竟何如秋实。", "不须待、名品如麻，试为君屈指，是谁层出。", "十朝半月，争看抟空霜鹘。", "从来别真共假，任盘根错节，更饶仓卒。", "还他济时好手，封侯奇骨。", "没些儿、媻姗勃窣。", "也不是、峥嵘突兀。", "百二十岁，管做彻、元分人物。"]'),
('song-ci-368','贺新郎','陈亮','宋','宋词','song-ci','贺新郎','[]','话杀浑闲说。',140,'宋词/ci.song.12000.json','["话杀浑闲说。", "不成教、齐民也解，为伊为葛。", "樽酒相逢成二老，却忆去年风雪。", "新著了、几茎华发。", "百世寻人犹接踵，叹只今两地三人月。", "写旧恨，向谁瑟。", "男儿何用伤离别。", "况古来、几番际会，风从云合。", "千里情亲长晤对，妙体本心次骨。", "卧百尺、高楼斗绝。", "天下适安耕且老，看买犁卖剑平家铁。", "壮士泪，肺肝裂。"]'),
('song-ci-369','点绛唇','陈亮','宋','宋词','song-ci','点绛唇','[]','一夜相思，水边清浅横枝瘦。',50,'宋词/ci.song.12000.json','["一夜相思，水边清浅横枝瘦。", "小窗如昼。", "情共香俱透。", "清入梦魂，千里人长久。", "君知否。", "雨﹀人︽。", "格调还依旧。"]'),
('song-ci-370','点绛唇','陈亮','宋','宋词','song-ci','点绛唇','[]','电绕璇枢，此时昌运生真主。',50,'宋词/ci.song.12000.json','["电绕璇枢，此时昌运生真主。", "庆聊簪组。", "喜气生绵宇。", "宴启需云，湛露恩均布。", "锵韶濩。", "凤歌鸾舞。", "玉斝飞香醑。"]'),
('song-ci-371','点绛唇','陈亮','宋','宋词','song-ci','点绛唇','[]','碧落蟠桃，春风种在琼瑶苑。',50,'宋词/ci.song.12000.json','["碧落蟠桃，春风种在琼瑶苑。", "几回花绽。", "一子千年见。", "香染丹霞，摘向流虹旦。", "深深愿。", "万年天算。", "玉颗常来献。"]'),
('song-ci-372','点绛唇','陈亮','宋','宋词','song-ci','点绛唇','[]','烟雨楼台，晓来独上无滋味。',50,'宋词/ci.song.12000.json','["烟雨楼台，晓来独上无滋味。", "落花流水。", "掩映渔樵市。", "酒圣诗狂，只遣愁无计。", "频凝睇。", "问人天际。", "曾见归舟未。"]'),
('song-ci-373','南歌子','陈亮','宋','宋词','song-ci','南歌子','[]','池草抽新碧，山桃褪小红。',62,'宋词/ci.song.12000.json','["池草抽新碧，山桃褪小红。", "寻春闲过小园东。", "春在乱花深处、鸟声中。", "游镫归敲月，春衫醉舞风。", "谁家三弄学元戎。", "吹起闲愁，容易上眉峰。"]'),
('song-ci-374','好事近','陈亮','宋','宋词','song-ci','好事近','[]','篱菊吐寒花，香弄小园秋色。',53,'宋词/ci.song.12000.json','["篱菊吐寒花，香弄小园秋色。", "携手画阑西畔，忆去年同摘。", "小亭依旧锁西风，往事已无迹。", "懒向碧云深处，问征鸿消息。"]'),
('song-ci-375','好事近','陈亮','宋','宋词','song-ci','好事近','[]','横玉叫清宵，帘外月侵残烛。',53,'宋词/ci.song.12000.json','["横玉叫清宵，帘外月侵残烛。", "人在画楼高处，倚阑干几曲。", "穿云裂石韵悠扬，风细断远续。", "惊落小梅香粉，点一庭苔绿。"]'),
('song-ci-376','好事近','陈亮','宋','宋词','song-ci','好事近','[]','的皪两三枝，点破暮烟苍碧。',53,'宋词/ci.song.12000.json','["的皪两三枝，点破暮烟苍碧。", "好在屋檐斜入，傍玉奴横笛。", "月华如水过林塘，花阴弄苔石。", "欲向梦中飞蝶，恐幽香难觅。"]'),
('song-ci-377','浣溪沙','陈亮','宋','宋词','song-ci','浣溪沙','[]','小雨翻花落画檐。',48,'宋词/ci.song.12000.json','["小雨翻花落画檐。", "栏堂香注酒重添。", "花枝能语出朱帘。", "缓步金莲移小小，持杯玉笋露纤纤。", "此时谁不醉厌厌。"]'),
('song-ci-378','采桑子','陈亮','宋','宋词','song-ci','采桑子','[]','桃花已作东风笑，小蕊嫣然。',52,'宋词/ci.song.12000.json','["桃花已作东风笑，小蕊嫣然。", "春色暄妍。", "缓步烟霞到洞天。", "一杯满泻蒲桃绿，且共留连。", "醉倒花前。", "也占红香影里眠。"]'),
('song-ci-379','朝中措','陈亮','宋','宋词','song-ci','朝中措','[]','蓼花风淡水云纤。',57,'宋词/ci.song.12000.json','["蓼花风淡水云纤。", "倚阁卷重帘。", "索寞败荷翠减，萧疏晚□红添。", "魂销天末，眉横远岫，斜挂新蟾。", "谁信故人千里，此时却到眉尖。"]'),
('song-ci-380','柳梢青','陈亮','宋','宋词','song-ci','柳梢青','[]','柳丝烟织。',61,'宋词/ci.song.12000.json','["柳丝烟织。", "掩映小池，鳞鳞波碧。", "几片飞花，半檐残雨，长亭愁寂。", "凭高望断江南，怅千里、疏烟淡日。", "斗草风流，弄梅情分，教人思忆。"]'),
('song-ci-381','浪淘沙','陈亮','宋','宋词','song-ci','浪淘沙','[]','霞尾卷轻绡。',64,'宋词/ci.song.12000.json','["霞尾卷轻绡。", "柳外风摇。", "断虹低系碧山腰。", "古往今来离别地，烟水迢迢。", "归雁下平桥。", "目断魂销。", "夕阳无限满江皋。", "杨柳杏花相对晚，各自无聊。"]'),
('song-ci-382','浪淘沙','陈亮','宋','宋词','song-ci','浪淘沙','[]','院落晓风酸。',64,'宋词/ci.song.12000.json','["院落晓风酸。", "春如西园。", "芳英吹破玉阑干。", "墙外红尘飞不到，彻骨清寒。", "清浅小堤湾。", "瘦竹团栾。", "水光疏影有无间。", "仿佛浣沙溪上见，波面云鬟。"]'),
('song-ci-383','小重山','陈亮','宋','宋词','song-ci','小重山','[]','碧幕霞绡一缕红。',70,'宋词/ci.song.12000.json','["碧幕霞绡一缕红。", "槐枝啼宿鸟，冷烟浓。", "小楼愁倚画阑东。", "黄昏月，一笛碧云风。", "往事已成空。", "梦魂飞不到，楚王宫。", "翠绡和泪暗偷封。", "江南阔，无处觅征鸿。"]'),
('song-ci-384','转调踏莎行・踏莎行','陈亮','宋','宋词','song-ci','转调踏莎行・踏莎行','[]','洛浦尘生，巫山梦断。',81,'宋词/ci.song.12000.json','["洛浦尘生，巫山梦断。", "旗亭烟草里，春深浅。", "梨花落尽，荼䕷又绽。", "天气也似，寻常庭院。", "向晚情怀，十分恼乱。", "水边佳丽地，近前细看。", "娉婷笑语，流觞美满。", "意思不到，夕阳孤馆。"]'),
('song-ci-385','品令','陈亮','宋','宋词','song-ci','品令','[]','潇洒林塘暮。',79,'宋词/ci.song.12000.json','["潇洒林塘暮。", "正迤逦、香风度。", "一番天气，又添作琼枝玉树。", "粉蝶无踪，疑在落花深处。", "深沈庭院，也卷起、重帘否。", "十分春色，依约见了，水村竹坞。", "怎向江南，更说杏花烟雨。"]'),
('song-ci-386','最高楼','陈亮','宋','宋词','song-ci','最高楼','[]','春乍透，香早暗偷传。',100,'宋词/ci.song.12000.json','["春乍透，香早暗偷传。", "深院落，斗清妍。", "紫檀枝似流苏带，黄金须胜辟寒钿。", "更朝朝，琼树好，笑当年。", "花不向沈香亭上看。", "树不著唐昌宫里玩。", "衣带水，隔风烟。", "铅华不御凌波处，蛾眉淡扫至尊前。", "管如今，浑似了，更堪怜。"]'),
('song-ci-387','青玉案','陈亮','宋','宋词','song-ci','青玉案','[]','武陵溪上桃花路。',80,'宋词/ci.song.12000.json','["武陵溪上桃花路。", "见征骑、匆匆去。", "嘶入斜阳芳草渡。", "读书窗下，弹琴石上，留得销魂处。", "落花冉冉春将暮。", "空写池塘梦中句。", "黄犬书来何日许。", "辋川轻舸，杜陵尊酒，半夜灯前雨。"]'),
('song-ci-388','诉衷情','陈亮','宋','宋词','song-ci','诉衷情','[]','独凭江槛思悠悠。',54,'宋词/ci.song.12000.json','["独凭江槛思悠悠。", "斜日堕林邱。", "鸳鸯属玉飞处，急桨荡轻舟。", "红蓼岸，白苹洲。", "夜来秋。", "数声渔父，一曲水仙，歌断还愁。"]'),
('song-ci-389','南乡子','陈亮','宋','宋词','song-ci','南乡子','[]','风雨满苹洲。',66,'宋词/ci.song.12000.json','["风雨满苹洲。", "绣阁银屏一夜秋。", "当日袜尘何处去，溪楼。", "怎对烟波不泪流。", "天际自归舟。", "浪卷涛翻一叶浮。", "也似我侬魂不定，悠悠。", "宋玉方悲庾信愁。"]'),
('song-ci-390','一丛花','陈亮','宋','宋词','song-ci','一丛花','[]','冰轮斜辗镜天长。',94,'宋词/ci.song.12000.json','["冰轮斜辗镜天长。", "江练隐寒光。", "危阑醉倚人如画，隔烟村、何处鸣桹。", "乌鹊倦栖，鱼龙惊起，星斗挂垂杨。", "芦花千顷水微茫。", "秋色满江乡。", "楼台恍似游仙梦，又疑是、洛浦潇湘。", "风露浩然，山河影转，今古照凄凉。"]'),
('song-ci-391','清平乐','陈亮','宋','宋词','song-ci','清平乐','[]','银屏绣阁。',54,'宋词/ci.song.12000.json','["银屏绣阁。", "不道鲛绡薄。", "嘶骑匆匆尘漠漠。", "远过夕阳村落。", "乱山千叠无情。", "今宵遮断愁人。", "两处香消梦觉，一般晓月秋声。"]'),
('song-ci-392','渔家傲','陈亮','宋','宋词','song-ci','渔家傲','[]','漠漠平沙初落雁。',72,'宋词/ci.song.12000.json','["漠漠平沙初落雁。", "黄花浊酒情何限。", "红日渐低秋渐晚。", "听客劝。", "金荷莫诉真珠满。", "坐上少年差气岸。", "题诗落帽从来惯。", "戏马龙山当日燕。", "真奇观。", "尊前未觉风流远。"]'),
('song-ci-393','丑奴儿・采桑子','陈亮','宋','宋词','song-ci','丑奴儿・采桑子','[]','黄昏山驿销魂处，枝亚疏篱。',52,'宋词/ci.song.12000.json','["黄昏山驿销魂处，枝亚疏篱。", "枝亚疏离。", "酝藉香风蜜打围。", "隔篱鸡犬谁家舍，门掩斜晖。", "门掩斜晖。", "花落花开总不知。"]'),
('song-ci-394','滴滴金','陈亮','宋','宋词','song-ci','滴滴金','[]','断桥雪霁闻啼鸟。',60,'宋词/ci.song.12000.json','["断桥雪霁闻啼鸟。", "对林花、弄晴晓。", "画角吹香客愁醒，见梢头红小。", "团酥剪蜡知多少。", "向风前、压春倒。", "江嶂人烟画图中，有短篷香绕。"]'),
('song-ci-395','七娘子','陈亮','宋','宋词','song-ci','七娘子','[]','风流家世传张绪。',70,'宋词/ci.song.12000.json','["风流家世传张绪。", "似灵和新种垂杨缕。", "绮席摛词，银台奏赋。", "当年梦绕蓬山路。", "卖花声断蓝桥暮。", "记吟鞭醉帽曾经处。", "蜀郡归来，荆州老去。", "心情零乱随风絮。"]'),
('song-ci-396','醉花阴','陈亮','宋','宋词','song-ci','醉花阴','[]','峻极云端潇洒寺。',62,'宋词/ci.song.12000.json','["峻极云端潇洒寺。", "赋我登高意。", "好景属清游，玉友黄花，谩续龙山事。", "秋风满座芝兰媚。", "杯酒随宜醉。", "行乐任天真，一笑和同，休问无携妓。"]'),
('song-ci-397','醉花阴','陈亮','宋','宋词','song-ci','醉花阴','[]','姓名未勒慈恩寺。',62,'宋词/ci.song.12000.json','["姓名未勒慈恩寺。", "谁作山林意。", "杯酒且同欢，不许时人，轻料吾曹事。", "可怜风月於人媚。", "那对花前醉。", "珍重主人情，闻说当年，宴出红妆妓。"]'),
('song-ci-398','汉宫春','陈亮','宋','宋词','song-ci','汉宫春','[]','雪月相投。',118,'宋词/ci.song.12000.json','["雪月相投。", "看一枝才爆，惊动香浮。", "微阳未放线路，说甚来由。", "先天一着，待辟开、多少旬头。", "却引取，春工入脚，争教消息停留。", "官不容针时节，做一般孤瘦，无限清幽。", "随缘柳绿柳白，费尽雕锼。", "疏林野水，任横斜、谁与妆修。", "猛认得，些儿合处，不堪持献君侯。"]'),
('song-ci-399','暮花天・花发沁园春','陈亮','宋','宋词','song-ci','暮花天・花发沁园春','[]','天意微悭，春工多裕，长须末后殷勤。',129,'宋词/ci.song.12000.json','["天意微悭，春工多裕，长须末后殷勤。", "骨瘦挽先，肌韵恰好，花头径尺徐陈。", "红黄粉紫，更牛家、姚魏为真。", "留几种，蒂殢中州，异时齐顿浑身。", "承平当日开多少，笙歌何限，是甚人人。", "气入江南，心知芍药，仿佛前事犹存。", "名品应须，认旧家，雨露方新。", "成一处，蓓蕾根株，剩看诸谱纷纷。"]'),
('song-ci-400','新荷叶','陈亮','宋','宋词','song-ci','新荷叶','[]','艳态远幽，谁能洁净争妍。',100,'宋词/ci.song.12000.json','["艳态远幽，谁能洁净争妍。", "淡抹疑浓，肯将自在求怜。", "终嫌独好，任毛嫱、西子差肩。", "六郎涂涴，似和不似依然。", "赫日如焚，诸馀只凭光鲜。", "雨过风生，也应百事随缘。", "香须道地，对一池、著甚沈烟。", "根株好在，淤泥白藕如椽。"]'),
('song-ci-401','秋兰香','陈亮','宋','宋词','song-ci','秋兰香','[]','未老金茎，些子正气，东篱淡伫齐芳。',118,'宋词/ci.song.12000.json','["未老金茎，些子正气，东篱淡伫齐芳。", "分头添样白，同菊几般黄。", "向闲处、须一一排行。", "浅深饶间新妆。", "那陶令，漉他谁酒，趁醒消详。", "况是此花开后，便蝶乱无花，管甚蜂忙。", "你从今、采却蜜成房。", "秋英诚商量。", "多少为谁，甜得清凉。", "待说破，长生真诀，要饱风霜。"]'),
('song-ci-402','汉宫春','陈亮','宋','宋词','song-ci','汉宫春','[]','雪满江头，怪一枝不耐，还漏微阳。',118,'宋词/ci.song.12000.json','["雪满江头，怪一枝不耐，还漏微阳。", "诗人越样眼浅，早自成章。", "群葩如绣，到那时、争爱春长。", "须知道，未通春信，是谁饱试风霜。", "堪笑红炉画阁，问从来寒气，损甚容光。", "枝头有花恁好，映带新妆。", "寒窗愁绝，嗅清芬、不料饥肠。", "都缘是，此君小异，费他万种消详。"]'),
('song-ci-403','桂枝香','陈亮','宋','宋词','song-ci','桂枝香','[]','仙风透骨。',124,'宋词/ci.song.12000.json','["仙风透骨。", "向夏叶丛中，春花重出。", "骏发天香，不是世间尤物。", "占些空阔闲田地，共霜轮、伴他秋实。", "浅非冷蕊，深非幽艳，中无倚握。", "任拈取、龙涎笃耨。", "儿女子看承，万屈千屈。", "做数珠见，刻画毋盐唐突。", "不知几树栾团着，但口吻、非鸣云室。", "是耶非也，书生见识，圣贤心术。"]'),
('song-ci-404','水龙吟','陈亮','宋','宋词','song-ci','水龙吟','[]','钱王霸图成时，多应是百年遗树。',126,'宋词/ci.song.12000.json','["钱王霸图成时，多应是百年遗树。", "羞将高古，为渠遮映，鱼盐调度。", "且向空山，趁时多事，四垂盘踞。", "算兴衰坐阅，权奇磊块，世间□，□斤斧。", "又见当天明圣，便弹丸、也难分土。", "一番整顿，旧家草木，新来雨露。", "铁石心肠，叫龙根干，亭亭天柱。", "纵茯苓下结，茑萝高际，怎堪攀附。"]'),
('song-ci-405','临江仙','陈亮','宋','宋词','song-ci','临江仙','[]','五百年间非一日，可堪只到今年。',70,'宋词/ci.song.12000.json','["五百年间非一日，可堪只到今年。", "云龙欲化艳阳天。", "从来耆旧传，不博地行仙。", "昨夜风声何处度，典型犹在南山。", "自怜不结傍时缘。", "著鞭非我事，避路只渠贤。"]'),
('song-ci-406','水龙吟','陈亮','宋','宋词','song-ci','水龙吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','闹花深处层楼，画帘半卷东风软。',126,'宋词/ci.song.12000.json','["闹花深处层楼，画帘半卷东风软。", "春归翠陌，平莎茸嫩，垂杨金浅。", "迟日催花，淡云阁雨，轻寒轻暖。", "恨芳菲世界，游人未赏，都付与、莺和燕。", "寂寞凭高念远。", "向南楼、一声归雁。", "金钗斗草，青丝勒马，风流云散。", "罗绶分香，翠绡封泪，几多幽怨。", "正销魂，又是疏烟淡月，子规声断。"]'),
('song-ci-407','洞仙歌','陈亮','宋','宋词','song-ci','洞仙歌','[]','琐窗秋暮，梦高唐人困。',103,'宋词/ci.song.12000.json','["琐窗秋暮，梦高唐人困。", "独立西风万千恨。", "又檐花落处，滴碎空阶，芙蓉院，无限秋容老尽。", "枯荷催欲折，多少离声，锁断天涯诉幽闷。", "似蓬山去后，方士来时，挥粉泪、点点梨花香润。", "断送得，人间夜霖铃，更叶落梧桐，孤灯成晕。"]'),
('song-ci-408','虞美人','陈亮','宋','宋词','song-ci','虞美人','[]','东风荡扬轻云缕。',66,'宋词/ci.song.12000.json','["东风荡扬轻云缕。", "时送萧萧雨。", "水边台榭燕新归。", "一口香泥湿带、落花飞。", "海棠糁径铺香绣。", "依旧成春瘦。", "黄昏庭院柳啼鸦。", "记得那人和月、折梨花。"]'),
('song-ci-409','眼儿媚','陈亮','宋','宋词','song-ci','眼儿媚','[]','试灯天气又春来。',58,'宋词/ci.song.12000.json','["试灯天气又春来。", "难说是情怀。", "寂寥聊似，扬州何逊，不为江梅。", "扶头酒醒炉香炧，心绪未全灰。", "愁人最是，黄昏前后，烟雨楼台。"]'),
('song-ci-410','思佳客','陈亮','宋','宋词','song-ci','思佳客','[]','花拂阑干柳拂空。',64,'宋词/ci.song.12000.json','["花拂阑干柳拂空。", "花枝绰约柳鬟松。", "蝶翻淡碧低边影，莺啭浓香杪处风。", "深院落，小帘栊。", "寻芳犹忆旧相逢。", "桥边携手归来路，踏皱残花几片红。"]'),
('song-ci-411','浣溪沙','陈亮','宋','宋词','song-ci','浣溪沙','[]','爽气朝来卒未阑。',48,'宋词/ci.song.12000.json','["爽气朝来卒未阑。", "可能着我屋千间。", "不须拄笏望西山。", "柳外霎时征马骏，沙头尽日白鸥闲。", "称心容易足君欢。"]'),
('song-ci-412','贺新郎','陈亮','宋','宋词','song-ci','贺新郎','[]','镂刻黄金屋。',142,'宋词/ci.song.12000.json','["镂刻黄金屋。", "向炎天、蔷薇水洒，净瓶儿浴。", "湿透生绡裙微褪，谁把琉璃藉玉。", "更管甚、微凉生熟。", "磊浪星儿无著处，唤青奴、记度新翻曲。", "娇不尽，ソ州竹。", "一泓曲水鳞鳞蹙。", "粉生红、香脐皓腕，藕双莲独。", "拂掠乌云新妆晚，无奈纤腰似束。", "白笃耨、霞觞浮绿。", "三岛十州心在否，是天花、只怕凡心触。", "才乱坠，便簌簌。"]'),
('song-ci-413','贺新郎','陈亮','宋','宋词','song-ci','贺新郎','[]','昵昵骈头语。',142,'宋词/ci.song.12000.json','["昵昵骈头语。", "笑黄花、重阳去也，不成分数。", "倾国容华随时唤，依旧清歌妙舞。", "苦未冷、都无星暑。", "恰好良辰花共酒，斗尊前、见在阳台女。", "朝共暮，定何许。", "蓼红徙倚明汀渚。", "正萧萧、迎风夹岸，淡烟微雨。", "笃耨龙涎烧未也，好向儿家祝取。", "是有分、分工须与。", "以色事人能几好，愿衾稠、无缝休离阻。", "心一片，丝千缕。"]'),
('song-ci-414','水调歌头','李','宋','宋词','song-ci','水调歌头','[]','足迹半天下，家说在琼州。',114,'宋词/ci.song.12000.json','["足迹半天下，家说在琼州。", "往来无定，蓬头垢面任憎嫌。", "挥扫笔头万字，贯穿胸中千古，不记受生年。", "海角一相遇，缘契似从前。", "锺离歌，吕公篆，醉张颠。", "恍如赤城龙凤，来过我鲸仙。", "笑我未离世网，不染个中尘土，饥食困来眠。", "拟问君家祖，兜率乐天天。"]'),
('song-ci-415','六州歌头','李','宋','宋词','song-ci','六州歌头','[]','高皇神武，善驾驭豪英。',182,'宋词/ci.song.12000.json','["高皇神武，善驾驭豪英。", "攘北狄，驱群盗，命天膺。", "救苍生。", "奈梦绕沙漠，隔温情，屈和好，召大将，归兵柄，列枢庭。", "公指汴京。", "威已振河洛，不顾身烹。", "失一时机会，嗟左衽吾民。", "痛岳家军。", "孰扶倾。", "久沈冤愤，七十载，还复遇，帝王真。", "表遗列，锡王号，日照临。", "激士心。", "始识安刘计，宁祸己，是忠臣。", "我乘传，访壁垒，想精明。", "英气懔然若在，仍题扁、昭揭天恩。", "笑原头芳草，一死不能春。", "交怨人神。"]'),
('song-ci-416','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','寒眼乱空阔，客意不胜秋。',114,'宋词/ci.song.12000.json','["寒眼乱空阔，客意不胜秋。", "强呼斗酒，发兴特上最高楼。", "舒卷江山图画，应答龙鱼悲啸，不暇顾诗愁。", "风露巧欺客，分冷入衣裘。", "忽醒然，成感慨，望神州。", "可怜报国无路，空白一分头。", "都把平生意气，只作如今憔悴，岁晚若为谋。", "此意仗江月，分付与沙鸥。"]'),
('song-ci-417','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','杖屦觅春色，行遍大江西。',114,'宋词/ci.song.12000.json','["杖屦觅春色，行遍大江西。", "访花问柳，都自无语欲成蹊。", "不道七州三垒，今岁五风十雨，全是太平时。", "征辔晚乘月，渔钓夜垂丝。", "诗书帅，坐围玉，尘挥犀。", "兴方不浅，领袖风月过花期。", "只恐梅梢青子，已露调羹消息，金鼎待公归。", "回首腾王阁，空对落霞飞。"]'),
('song-ci-418','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','父老一杯酒，争劝史君留。',114,'宋词/ci.song.12000.json','["父老一杯酒，争劝史君留。", "可怜桃李千树，无语送归舟。", "听得拈笙玉指，都把万家遗爱，吹作许离愁。", "倚醉袖红湿，生怕夕阳流。", "问君侯，今几日，到东州。", "还家时候，次第梅已暗香浮。", "只恐道间驿使，先寄调羹消息，归去总无由。", "鼎铉功名了，徐赴赤松游。"]'),
('song-ci-419','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','买得一航月，醉卧出长安。',114,'宋词/ci.song.12000.json','["买得一航月，醉卧出长安。", "平堤千里过尽，杨柳绿阴间。", "依约晓莺啼处，认得南徐风物，客梦恍惊残。", "重到旧游所，如把画图看。", "英雄事，千古意，一凭阑。", "惜今老矣，无复健笔写江山。", "天上人间知己，赖有使星郎宿，照映此尘寰。", "准拟五湖去，为乞钓鱼竿。"]'),
('song-ci-420','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','把酒对斜阳，无语问西风。',114,'宋词/ci.song.12000.json','["把酒对斜阳，无语问西风。", "胭脂何事，都做颜色染芙蓉。", "放眼暮江千顷，中有离情万斛，无处落征鸿。", "天在阑干角，人倚醉醒中。", "千万里，江南北，浙西东。", "吾生如寄，尚想三径菊花丛。", "谁是中州豪杰，借我五湖舟楫，去作钓渔翁。", "故园且回首，此意莫匆匆。"]'),
('song-ci-421','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','一笛起城角，吹破小梅愁。',114,'宋词/ci.song.12000.json','["一笛起城角，吹破小梅愁。", "东风犹未，谁遣春信到吾州。", "闻得东来千骑，鼓舞儿童竹马，和气与空浮。", "桃李未阴处，准拟种千头。", "今太守，宋人物，晋风流。", "政成谈笑，不妨高兴在南楼。", "只恐蓬莱仙伯，合侍玉皇香案，难作寇恂留。", "约住紫泥诏，凭轼且优游。"]'),
('song-ci-422','水调歌头','杨炎正','宋','宋词','song-ci','水调歌头','[]','踏碎九街月，乘醉出京华。',114,'宋词/ci.song.12000.json','["踏碎九街月，乘醉出京华。", "半生湖海，谁念今日老还家。", "独把瓦盆盛酒，自与渔樵分席，说伊政声佳。", "竹马望尘去，倦客亦随车。", "听熏风，清晓月，韵梅花。", "人家十万，说尽炎热与咨嗟。", "只恐棠阴未满，已有枫宸趣召，归路不容遮。", "回首江边柳，空著旧栖鸦。"]'),
('song-ci-423','满江红','杨炎正','宋','宋词','song-ci','满江红','[]','春入台门，又见染、柳丝新绿。',115,'宋词/ci.song.12000.json','["春入台门，又见染、柳丝新绿。", "对此景，一年为寿，一番添福。", "莫怪凤池颁诏晚，要教淮水恩波足。", "听边民、千岁颂声中，重重祝。", "堂萱茂，庭枝馥。", "歌倚扇，杯持玉。", "共劝君一醉，满斟醽醁。", "今夜东风吹酒醒，明朝万里骑黄鹄。", "向九霞、光里望宸辉，看除目。"]'),
('song-ci-424','满江红','杨炎正','宋','宋词','song-ci','满江红','[]','笔染相思，暗题尽、朱门白壁。',115,'宋词/ci.song.12000.json','["笔染相思，暗题尽、朱门白壁。", "动离思、春生远岸，烟销残日。", "杨柳结成罗带恨，海棠染就胭脂色。", "想深情、幽怨绣屏间，双鶒鸂。", "春水绿，春山碧。", "花有恨，酒无力。", "对一奁愁思，九分孤寂。", "寸寸锦肠浑欲断，盈盈玉泪应偷滴。", "倩东风、吹雁过江南，传消息。"]'),
('song-ci-425','满江红','杨炎正','宋','宋词','song-ci','满江红','[]','寿酒如渑，拼一醉、劝君休惜。',115,'宋词/ci.song.12000.json','["寿酒如渑，拼一醉、劝君休惜。", "君不记、济河津畔，当年今夕。", "万丈文章光焰里，一星飞堕从南极。", "便御飞、乘兴入京华，班乡棘。", "君不是，长庚白。", "又不是，严陵客。", "只应是，明主梦中良弼。", "好把袖间经济手，如今去补天西北。", "等瑶池、侍宴夜归时，骑箕翼。"]'),
('song-ci-426','满江红','杨炎正','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','典尽春衣，也应是、京华倦客。',115,'宋词/ci.song.12000.json','["典尽春衣，也应是、京华倦客。", "都不记，麴尘香雾，西湖南陌。", "儿女别时和泪拜，牵衣曾问归时节。", "到归来、稚子已成阴，空头白。", "功名事，云霄隔。", "英雄伴，东南拆。", "对鸡豚社酒，依然乡国。", "三径不成陶令隐，一区未有扬雄宅。", "问渔樵、学作生生涯，从今日。"]'),
('song-ci-427','瑞鹤仙','杨炎正','宋','宋词','song-ci','瑞鹤仙','[]','风光开旧眼。',127,'宋词/ci.song.12000.json','["风光开旧眼。", "正梅雪初消，柳丝新染。", "楼台竞装点。", "照金荷十里，珠帘齐卷。", "湘弦楚管。", "动香风、旌旗影转。", "望云间，一点台星飞下，洞天清晚。", "争看。", "袖红围坐，舞翠回春，笑歌生暖。", "欢声正远。", "嬉游意，未容懒。", "恐丝纶趣召，清都仙伯，归去朝天夜半。", "倩邦人、挽取遨头，醉扶玉腕。"]'),
('song-ci-428','贺新郎','杨炎正','宋','宋词','song-ci','贺新郎','[]','十日狂风雨。',140,'宋词/ci.song.12000.json','["十日狂风雨。", "扫园林、红香万点，送春归去。", "独有荼䕷开未到，留得一分春住。", "早杨柳、趁晴飞絮。", "可奈暖埃欺昼永，试薄罗衫子轻如雾。", "惊旧恨，到眉宇。", "东风台榭知何处。", "问燕莺如今，尚有春光几许。", "可欢一年游赏倦，放得无情露醑。", "为唤取、扇歌裙舞。", "乞得风光远两眼，待为君、满把金杯举。", "扶醉玉，伴挥麈。"]'),
('song-ci-429','贺新郎','杨炎正','宋','宋词','song-ci','贺新郎','[]','梦里骖鸾驭。',139,'宋词/ci.song.12000.json','["梦里骖鸾驭。", "望蓬莱不远，翩然被风吹去。", "吹到楚楼烟月上，不记人间何处。", "但疑是、蓬壶别所。", "缥缈霓裳天女队，奉一仙、满把流霞举。", "如唤我，醉中舞。", "醉醒梦觉知何许。", "问潇湘今日，谁与主盟尊俎。", "无限青春难老意，拟倩管弦寄与。", "待新筑沙堤稳步。", "万里云霄都历遍，却依前、流水桃源路。", "留此笔，为君赋。"]'),
('song-ci-430','念奴娇','杨炎正','宋','宋词','song-ci','念奴娇','[]','汉天云静，望一星飞过，湘南湘北。',120,'宋词/ci.song.12000.json','["汉天云静，望一星飞过，湘南湘北。", "当是郴山猿鹤梦，唤起日边消息。", "羽扇纶巾，浩然乘兴，此意无人识。", "扁舟千里，但闻清夜横笛。", "记得天上人间，去年今日，曾作称觞客。", "明月风烟依旧似，只觉蓬莱悬隔。", "更恐明朝，诏黄飞下，趣驾冲霄翼。", "衮衣剑履，望公长在南极。"]'),
('song-ci-431','念奴娇','杨炎正','宋','宋词','song-ci','念奴娇','[]','杏花杨柳，对东风染尽、一年春色。',120,'宋词/ci.song.12000.json','["杏花杨柳，对东风染尽、一年春色。", "弹压烟光三万顷，谁识清都仙伯。", "夜泛银潢，手移星纬，飞堕从天阙。", "御风乘兴，偶然身到乡国。", "二年人乐升平，舞台歌榭，处处红牙拍。", "寿酒千觞斟不尽，一醉何妨今夕。", "更约明年，凤凰迟上，去作称觞客。", "梅花折得，赠君调鼎消息。"]'),
('song-ci-432','洞仙歌','杨炎正','宋','宋词','song-ci','洞仙歌','[]','芙蓉开了，春未江梅透。',104,'宋词/ci.song.12000.json','["芙蓉开了，春未江梅透。", "小小东风弄晴昼。", "把万家和气，吹入笙歌，炉熏里，都与慈闱做寿。", "黄堂今日贵，自著莱衣，捧劝金船十分酒。", "愿从今，江海上，日日韶华桃李迳，总为人间种就。", "但看取、天边老人星，有一点台星，共光南斗。"]'),
('song-ci-433','洞仙歌','杨炎正','宋','宋词','song-ci','洞仙歌','[]','带湖佳处，仿佛真蓬岛。',105,'宋词/ci.song.12000.json','["带湖佳处，仿佛真蓬岛。", "曾对金樽伴芳草。", "见桃花流水，别是春风，笙歌里，谁信东君曾老。", "功名都莫问，总是神仙，买断风光镇长好。", "但如今，经国手，袖里偷闲，天不管、怎得关河事了。", "待貌取、精神上凌烟，却旋买扁舟，归来闻早。"]'),
('song-ci-434','鹊桥仙','杨炎正','宋','宋词','song-ci','鹊桥仙','[]','思归时节，乍寒天气，总是离人愁绪。',68,'宋词/ci.song.12000.json','["思归时节，乍寒天气，总是离人愁绪。", "夜来无奈被西风，更吹作、一帘秋雨。", "征衫拂泪，阑干倚醉，羞对黄花无语。", "寄书除是雁来时，又只恐、书成雁去。"]'),
('song-ci-435','鹊桥仙','杨炎正','宋','宋词','song-ci','鹊桥仙','[]','筑成台榭，种成花柳，更又教成歌舞。',68,'宋词/ci.song.12000.json','["筑成台榭，种成花柳，更又教成歌舞。", "不知谁为带湖仙，收拾尽、壶天风露。", "闲中得味，酒中得趣，只恐天还也妒。", "青山纵买万千重，遮不断、诏书来路。"]'),
('song-ci-436','蝶恋花','杨炎正','宋','宋词','song-ci','蝶恋花','[]','离恨做成春夜雨。',70,'宋词/ci.song.12000.json','["离恨做成春夜雨。", "添得春江，划地东流去。", "弱柳系船都不住。", "为君愁绝听鸣橹。", "君到南徐芳草渡。", "想得寻春，依旧当年路。", "后夜独怜回首处。", "乱山遮隔无重数。"]'),
('song-ci-437','蝶恋花','杨炎正','宋','宋词','song-ci','蝶恋花','[]','点检笙歌多酿酒。',70,'宋词/ci.song.12000.json','["点检笙歌多酿酒。", "不放东风，独自迷杨柳。", "院院翠阴停永昼。", "曲栏随处堪垂手。", "昨日解酲今夕又。", "消得情怀，长被春僝僽。", "门外马嘶人去后。", "乱红不管花消瘦。"]'),
('song-ci-438','蝶恋花','杨炎正','宋','宋词','song-ci','蝶恋花','[]','万点飞花愁似雨。',70,'宋词/ci.song.12000.json','["万点飞花愁似雨。", "峭杀轻寒，不会留春住。", "满地乱红风扫聚。", "只教燕子衔将去。", "独倚阑干闲自觑。", "深院无人，行到无情处。", "帘外丝丝杨柳舞。", "又还装点人情绪。"]'),
('song-ci-439','千秋岁','杨炎正','宋','宋词','song-ci','千秋岁','[]','五云缥缈。',87,'宋词/ci.song.12000.json','["五云缥缈。", "朝退金门晓。", "归未稳，传宣到。", "龙楼陪夕宴，凤沼吟春草。", "人间世，谁知自有蓬莱岛。", "一杯宜劝了。", "换得天颜笑。", "人不老，春长好。", "从今千百岁，总是中书考。", "瑶池会，金盘剩荐安期枣。"]'),
('song-ci-440','玉人歌','杨炎正','宋','宋词','song-ci','玉人歌','[]','风西起。',107,'宋词/ci.song.12000.json','["风西起。", "又老尽篱花，寒轻香细。", "漫题红叶，句里意谁会。", "长天不恨江南远，苦恨无书寄。", "最相思，盘桔千枚，脍鲈十尾。", "鸿雁阻归计。", "算愁满离肠，十分岂止。", "倦倚阑干，顾影在天际。", "凌烟图画青山约，总是浮生事。", "判从今，买取朝醒夕醉。"]'),
('song-ci-441','点绛唇','杨炎正','宋','宋词','song-ci','点绛唇','[]','邂逅开尊，眼中有个人纤软。',50,'宋词/ci.song.12000.json','["邂逅开尊，眼中有个人纤软。", "袖罗轻转。", "玉腕回春暖。", "韵处无多，只恼人肠断。", "词将半。", "近前相劝。", "扑扑清香满。"]'),
('song-ci-442','点绛唇','杨炎正','宋','宋词','song-ci','点绛唇','[]','水载离怀，暮帆吹月寒欺酒。',50,'宋词/ci.song.12000.json','["水载离怀，暮帆吹月寒欺酒。", "楚梅春透。", "忍放持杯手。", "莫唱阳关，免湿盈盈袖。", "君行后。", "那人消瘦。", "不恼诗肠否。"]'),
('song-ci-443','秦楼月・忆秦娥','杨炎正','宋','宋词','song-ci','秦楼月・忆秦娥','[]','东风寂。',56,'宋词/ci.song.12000.json','["东风寂。", "垂杨舞困春无力。", "春无力。", "落红不管，杏花狼籍。", "断肠芳草萋萋碧。", "新来怪底相思极。", "相思极。", "冷烟池馆，又将寒食。"]'),
('song-ci-444','浣溪沙','杨炎正','宋','宋词','song-ci','浣溪沙','[]','杨柳笼烟袅嫩黄。',48,'宋词/ci.song.12000.json','["杨柳笼烟袅嫩黄。", "桃花蘸水染红香。", "薄罗衫子日初长。", "饮尽东风三百盏，醉来愁断几回肠。", "教人独自遣风光。"]'),
('song-ci-445','浣溪沙','杨炎正','宋','宋词','song-ci','浣溪沙','[]','三迳闲情傲落霞。',48,'宋词/ci.song.12000.json','["三迳闲情傲落霞。", "五湖高兴不浮家。", "自斟北斗浸丹砂。", "闲把胸中千涧壑，撰成醉处一生涯。", "雪楼风月篆岗花。"]'),
('song-ci-446','桃源忆故人','杨炎正','宋','宋词','song-ci','桃源忆故人','[]','尊前未语眉先皱。',56,'宋词/ci.song.12000.json','["尊前未语眉先皱。", "只把横波斜溜。", "此意问春知否。", "蝶困蜂儿瘦。", "𦟂膎呷丁些来酒。", "越会把人僝僽。", "有个约伊时候。", "梦里来相就。"]'),
('song-ci-447','踏莎行','杨炎正','宋','宋词','song-ci','踏莎行','[]','宿鹭栖身，飞鸿点泪，不堪更是重阳到。',68,'宋词/ci.song.12000.json','["宿鹭栖身，飞鸿点泪，不堪更是重阳到。", "一襟无处著凄凉。", "倚阑堪尽斜阳倒。", "瘦减难丰，悲伤易老，淡觞消得黄花笑。", "画眉人去玉篦存，浓愁如黛凭谁扫。"]'),
('song-ci-448','减字木兰花','杨炎正','宋','宋词','song-ci','减字木兰花','[]','月明如昼。',52,'宋词/ci.song.12000.json','["月明如昼。", "占断小楼供把酒。", "入眼人人。", "如月精神更有情。", "大家休睡。", "留到天明和月醉。", "生怕醒来。", "月到波心忆酒媒。"]'),
('song-ci-449','生查子','杨炎正','宋','宋词','song-ci','生查子','[]','金莲照夜红，玉腕扶春碧。',48,'宋词/ci.song.12000.json','["金莲照夜红，玉腕扶春碧。", "曲妙遏云行，人好欺花色。", "欢生酒面浓，笑染炉香湿。", "饮尽十玻璃，月堕东方白。"]'),
('song-ci-450','柳梢青','杨炎正','宋','宋词','song-ci','柳梢青','[]','生紫衫儿。',61,'宋词/ci.song.12000.json','["生紫衫儿。", "影金领子，著得偏宜。", "步稳金莲，香熏纨扇，舞转花枝。", "捧杯更著𦟂膎。", "唱一个、新行耍词。", "玉骨冰肌，好天良夜，怎不怜伊。"]'),
('song-ci-451','相见欢','杨炎正','宋','宋词','song-ci','相见欢','[]','江湖万里征鸿。',45,'宋词/ci.song.12000.json','["江湖万里征鸿。", "再相逢。", "多少风烟摸在、笑谈中。", "歌裙醉。", "罗巾泪。", "别愁浓。", "瘦减腰围不碍、带金重。"]'),
('song-ci-452','诉衷情','杨炎正','宋','宋词','song-ci','诉衷情','[]','露珠点点欲团霜。',54,'宋词/ci.song.12000.json','["露珠点点欲团霜。", "分冷与纱窗。", "锦书不到肠断，烟水隔茫茫。", "征燕尽，塞鸿翔。", "睇风樯。", "阑干曲处，又是一番，倚尽斜阳。"]'),
('song-ci-453','满江红','杨炎正','宋','宋词','song-ci','满江红','[]','豹尾班中，谁一似、神仙冠玉。',115,'宋词/ci.song.12000.json','["豹尾班中，谁一似、神仙冠玉。", "认得是、当年唱第，斗间星宿。", "万卷平生都看了，如今剗地无书读。", "向云霄、去路有行堤，沙新筑。", "黄封酒，生朝禄。", "金缕唱，生朝曲。", "且通宵一醉，剩裁红烛。", "待做太平真宰相，黑头坐对三槐绿。", "问恁时、犹有甚除书，长生箓。"]'),
('song-ci-454','点绛唇','俞灏','宋','宋词','song-ci','点绛唇','[]','欲问东君，为谁重到江头路。',50,'宋词/ci.song.12000.json','["欲问东君，为谁重到江头路。", "断桥薄暮。", "香透溪云渡。", "细草平沙，愁入凌波步。", "今何许。", "怨春无语。", "片片随流水。"]'),
('song-ci-455','清平乐','连久道','宋','宋词','song-ci','清平乐','[]','阵鸿惊处。',54,'宋词/ci.song.12000.json','["阵鸿惊处。", "一网沈江渚。", "落叶乱风和细雨。", "拨棹不如归去。", "芦花轻泛微澜。", "蓬窗独自清闲。", "一觉游仙好梦，任它竹冷松寒。"]'),
('song-ci-456','减字木兰花','赵师','宋','宋词','song-ci','减字木兰花','[]','江南春早。',52,'宋词/ci.song.12000.json','["江南春早。", "春到南枝花更好。", "不比寻常。", "深著胭脂学弄妆。", "寿阳开宴。", "拂拂红霞生酒面。", "从此溪桥。", "步障翻腾著绛绡。"]'),
('song-ci-457','苏幕遮','宋先生','宋','宋词','song-ci','苏幕遮','[]','气随神，神随气。',76,'宋词/ci.song.12000.json','["气随神，神随气。", "神气相随，透入泥丸里。", "长把金关牢锁闭。", "捉得金晶，暗地添欢喜。", "下辛勤，须发志。", "十二时中，莫把工夫弃。", "阴尽阳全神出体。", "功行成时，名列神仙位。"]'),
('song-ci-458','丑奴儿・采桑子','宋先生','宋','宋词','song-ci','丑奴儿・采桑子','[]','真人本是凡人做，悟者何难。',52,'宋词/ci.song.12000.json','["真人本是凡人做，悟者何难。", "名利如山。", "隔断神仙路往还。", "谢师指教生死限，长在心间。", "长在心间。", "十二时中不暂闲。"]'),
('song-ci-459','沁园春','宋先生','宋','宋词','song-ci','沁园春','[]','速速修行，惜取身中，无价□珍。',135,'宋词/ci.song.12000.json','["速速修行，惜取身中，无价□珍。", "把金乌玉兔，炉中炼用，阴阳造化，养就阳神。", "虎啸龙吟丹田里，顶内时时仙乐声。", "泥丸里，烹煎水火，铅汞成真。", "夜来端坐澄心神。", "见真人颜貌新。", "用河车搬载，充开牛斗，星辰洁皎，光射分明。", "服了刀圭功成后，自知道、仙班有姓名。", "诸仙请，待玉皇宣至，朝拜三清。"]'),
('song-ci-460','武陵春','宋先生','宋','宋词','song-ci','武陵春','[]','七返还丹人怎晓，晓后有何难。',56,'宋词/ci.song.12000.json','["七返还丹人怎晓，晓后有何难。", "夜静存神向内观。", "神水满泥丸。", "搬运金精无夜昼，呼吸不曾闲。", "功行成时出世寰。", "名姓列仙班。"]'),
('song-ci-461','武陵春','宋先生','宋','宋词','song-ci','武陵春','[]','虎绕龙蟠功最妙，交会在丹田。',56,'宋词/ci.song.12000.json','["虎绕龙蟠功最妙，交会在丹田。", "炉鼎烹煎火自然。", "日月炼为先。", "认取坎离为造化，真气要还源。", "向已澄静坐内观。", "九转炼成丹。"]'),
('song-ci-462','丑奴儿・采桑子','宋先生','宋','宋词','song-ci','丑奴儿・采桑子','[]','河车怎敢停留住，搬入泥丸。',52,'宋词/ci.song.12000.json','["河车怎敢停留住，搬入泥丸。", "水火烹煎。", "一粒丹砂炼汞铅。", "金丹大药人人有，只要心坚。", "休说闲言。", "不走阳精便是仙。"]'),
('song-ci-463','丑奴儿・采桑子','宋先生','宋','宋词','song-ci','丑奴儿・采桑子','[]','因师传说朝元理，昼夜功勤。',52,'宋词/ci.song.12000.json','["因师传说朝元理，昼夜功勤。", "炼煅成真。", "偷得阴阳共半斤。", "壶中天地何曾夜，四季长春。", "洞里光阴。", "交我如何与世论。"]'),
('song-ci-464','丑奴儿・采桑子','宋先生','宋','宋词','song-ci','丑奴儿・采桑子','[]','夜来子后披衣坐，心定神清。',52,'宋词/ci.song.12000.json','["夜来子后披衣坐，心定神清。", "见个真人。", "脸似胭脂体似银。", "炉中火焰炎炎起，紫气腾腾。", "一粒丹成。", "管取飞升上帝京。"]'),
('song-ci-465','太常引','宋先生','宋','宋词','song-ci','太常引','[]','金丹只在自身中。',62,'宋词/ci.song.12000.json','["金丹只在自身中。", "真水火、炼成功。", "因遇吕仙公。", "识返本、还元祖宗。", "阳全阴尽，神光现处，认得自真容。", "名姓列仙宫。", "已跳出、乾坤世笼。"]'),
('song-ci-466','点绛唇','宋先生','宋','宋词','song-ci','点绛唇','[]','二气工夫，河车搬入昆仑脑。',50,'宋词/ci.song.12000.json','["二气工夫，河车搬入昆仑脑。", "世人谁晓。", "此是玄元道。", "存得阳精，年老身不老。", "三田饱。", "行动都了。", "拂袖游蓬岛。"]'),
('song-ci-467','点绛唇','宋先生','宋','宋词','song-ci','点绛唇','[]','这个工夫，因师传授知元祖。',50,'宋词/ci.song.12000.json','["这个工夫，因师传授知元祖。", "论甚子午。", "说甚龙和虎。", "只在目前，明有神仙路。", "速修取。", "有朝归去。", "消了阴司簿。"]'),
('song-ci-468','捣练子','宋先生','宋','宋词','song-ci','捣练子','[]','真水火，谢师传。',48,'宋词/ci.song.12000.json','["真水火，谢师传。", "黑铅红汞鼎中煎。", "现神光，满目前。", "丹砂就，是神仙。", "金鼎捉住寿同天。", "待功成，玉帝宣。"]'),
('song-ci-469','临江仙','宋先生','宋','宋词','song-ci','临江仙','[]','说甚坎离龙共虎，休言火候周天。',70,'宋词/ci.song.12000.json','["说甚坎离龙共虎，休言火候周天。", "阳精不走自神全。", "双关明有路，直上至泥丸。", "牢锁金关并玉户，日魂月魄烹煎。", "三宫都满体牢坚。", "阳神朝上帝，永劫作天仙。"]'),
('song-ci-470','丑奴儿・采桑子','宋先生','宋','宋词','song-ci','丑奴儿・采桑子','[]','金公本是乾家子，住在坤宫。',52,'宋词/ci.song.12000.json','["金公本是乾家子，住在坤宫。", "真虎真龙。", "吃尽三尸及九虫。", "丹砂锻炼泥丸里，赫赫长红。", "一日成功。", "直见三清太上公。"]'),
('song-ci-471','浪淘沙','宋先生','宋','宋词','song-ci','浪淘沙','[]','我有一张琴。',64,'宋词/ci.song.12000.json','["我有一张琴。", "随坐随行。", "无弦胜似有弦声。", "欲对人前弹一曲，不遇知音。", "夜静响琤轰。", "神鬼俱惊。", "惊天动地若雷鸣。", "只候功成归去后，携向蓬瀛。"]'),
('song-ci-472','念奴娇','张','宋','宋词','song-ci','念奴娇','[]','绿云影里，把明霞织就，千重文绣。',120,'宋词/ci.song.12000.json','["绿云影里，把明霞织就，千重文绣。", "紫腻红娇扶不起，好是未开时候。", "半怯春寒，半便晴色，养得胭脂透。", "小亭人静，嫩莺啼破清昼。", "犹记携手芳阴，一枝斜戴，娇艳波双秀。", "小语轻怜花总见，争得似花长久。", "醉浅休归，夜深同睡，明日还相守。", "免教春去，断肠空欢诗瘦。"]'),
('song-ci-473','水调歌头','张','宋','宋词','song-ci','水调歌头','[]','孤棹溯霜月，远过阖闾城。',114,'宋词/ci.song.12000.json','["孤棹溯霜月，远过阖闾城。", "系船杨柳桥畔，吹袖晚寒轻。", "百尺层台重上，万事红尘一梦，回首几周星。", "风调信衰减，亲旧总雕零。", "认群峰，寻四塔，半烟横。", "平生感慨，况逢佳处辄销凝。", "休说当时雕辇，不见后来游鹿，斜照水空明。", "猛把画阑拍，飞雁两三声。"]'),
('song-ci-474','水调歌头','张','宋','宋词','song-ci','水调歌头','[]','忠肝贯日月，浩气抉云霓。',114,'宋词/ci.song.12000.json','["忠肝贯日月，浩气抉云霓。", "诗书名帅，谈笑果胜棘门儿。", "牛弩旁穿七札，虎将分行十道，先解近城围。", "一骑夜飞火，捷奏上天墀。", "畅皇威，宣使指，领全师。", "襄阳耆旧，请公直过洛之西。", "箪食欢呼迎处，已脱毡裘左衽，远著旧藏衣。", "笳鼓返京阙，风采震华夷。"]'),
('song-ci-475','木兰花慢','张','宋','宋词','song-ci','木兰花慢','[]','喜秋回霁宇，倩凉露、洗炎飙。',122,'宋词/ci.song.12000.json','["喜秋回霁宇，倩凉露、洗炎飙。", "被鹊误仙盟，经年恨阻，银汉迢迢。", "牛闲更停弄杼，趁佳期、华幄傍星桥。", "授玉鸾骞雾霭，赠绡龙戏花娇。", "欢娱回首是明朝。", "未别已魂销。", "想翠轭珠轮，归途望断，斗转斜勺。", "人间易离易遇，尽胜如、天上各云霄。", "携去一梳水月，巧楼犹醉笙箫。"]'),
('song-ci-476','木兰花慢','张鎡','宋','宋词','song-ci','木兰花慢','[]','年年三月二，是居士、始生朝。',122,'宋词/ci.song.12000.json','["年年三月二，是居士、始生朝。", "念绿鬓功名，初心已负，难报劬劳。", "天留帝城胜处，汇平湖、远岫碧岧嶢。", "竹色诗书燕几，柳阴桃杏横桥。", "西邻东舍不难招。", "大半是渔樵。", "任翁媪欢呼，儿孙歌笑，野具村醪。", "醉来便随鹤舞，看清风、送月过松梢。", "百岁因何快乐，尽从心底逍遥。"]'),
('song-ci-477','木兰花慢','张','宋','宋词','song-ci','木兰花慢','[]','驾飙车直上，绛衣惹、彩云轻。',123,'宋词/ci.song.12000.json','["驾飙车直上，绛衣惹、彩云轻。", "过宝树千峰，东逾绿海，宫殿峥嵘。", "檐楹万花灿倚，映阶层、十二总雕琼。", "剑佩簪裳卫肃，序班真辅仙卿。", "瑶京。", "谁解有神升。", "为密授玄经。", "拜九光霞里，轮金日耀，丹篆符明。", "龙鸾再催羽仗，报帝皇、新御紫阳城。", "归路梅花弄玉，数声月冷风清。"]'),
('song-ci-478','水龙吟','张','宋','宋词','song-ci','水龙吟','[]','这番真个休休，梦中深谢仙翁教。',126,'宋词/ci.song.12000.json','["这番真个休休，梦中深谢仙翁教。", "浮生幻境，向来识破，那堪又老。", "苦我身心，顺他眼耳，思量颠倒。", "许多时打哄，鲇鱼上竹，被人弄、知多少。", "解放微官系缚，似笼槛、猿归林草。", "云山有约，儿孙无债，为谁烦恼。", "自古高贤，急流勇退，直须闻早。", "把忧煎换取，长伸脚睡，大开口笑。"]'),
('song-ci-479','祝英台近','张','宋','宋词','song-ci','祝英台近','[]','暖风回，芳意动，吹破冻云凝。',95,'宋词/ci.song.12000.json','["暖风回，芳意动，吹破冻云凝。", "春到南湖，检校旧花径。", "手栽一色红梅，香笼十亩，忍轻负、酒肠诗兴。", "小亭凭。", "几多月魄□□，重重乱林影。", "却忆年时，同醉正同咏。", "问公白玉堂前，何如来听，玉龙喷、碧溪烟冷。"]'),
('song-ci-480','满江红','张','宋','宋词','song-ci','满江红','[]','玉照梅开，三百树、香云同色。',115,'宋词/ci.song.12000.json','["玉照梅开，三百树、香云同色。", "光摇动、一川银浪，九霄珂月。", "幸遇勋华时世好，欢娱况是张灯夕。", "更不邀、名胜赏东风，真堪惜。", "盘诰手，春秋笔。", "今内相，斯文伯。", "肯闲纡轩盖，远过泉石。", "奇事人生能几见，清尊花畔须教侧。", "到凤池、却欲醉鸥边，应难得。"]'),
('song-ci-481','满江红','张','宋','宋词','song-ci','满江红','[]','公为时生，才真是、禁中颇牧。',114,'宋词/ci.song.12000.json','["公为时生，才真是、禁中颇牧。", "擎天手、十年犹在，未应藏缩。", "说项无人堪欢息，瞻韩有意应恢复。", "用真儒、同建太平功，心相属。", "忠与孝，荣和辱。", "武昌柳，南湖竹。", "一箪瓢非欠，万锺非足。", "知命何曾怀喜愠，轻身岂为干名禄。", "看可汗生缚洗烟尘，机神速。"]'),
('song-ci-482','汉宫春','张','宋','宋词','song-ci','汉宫春','[]','城畔芙蓉，爱吹晴映水，光照园庐。',118,'宋词/ci.song.12000.json','["城畔芙蓉，爱吹晴映水，光照园庐。", "清霜乍雕岸柳，风景偏殊。", "登楼念远，望越山、青补林疏。", "人正在，秋风亭上，高情远解知无。", "江南久无豪气，看规恢意概，当代谁如。", "乾坤尽归妙用，何处非予。", "骑鲸浪海，更那须、采菊思鲈。", "应会得，文章事业，从来不在诗书。"]'),
('song-ci-483','烛影摇红','张鎡','宋','宋词','song-ci','烛影摇红','[]','宿雨初乾，舞梢烟瘦金丝袅。',116,'宋词/ci.song.12000.json','["宿雨初乾，舞梢烟瘦金丝袅。", "嫩云扶日破新晴，旧碧寻芳草。", "幽径兰芽尚小。", "怪今年、春归太早。", "柳塘花院，万朵红莲，一宵开了。", "梅雪翻空，忍教轻趁东风老。", "粉围香阵拥诗仙，战退春寒峭。", "现乐歌弹闹晓。", "宴亲宝、团圞同笑。", "醉归时候，月过珠楼，参横蓬岛。"]'),
('song-ci-484','贺新郎','张鎡','宋','宋词','song-ci','贺新郎','[]','看了梅花去。',141,'宋词/ci.song.12000.json','["看了梅花去。", "要东风、攀翻飞雪，与君同赋。", "海内从来天际眼，一笑平窥千古。", "待翦尽、烛花红吐。", "久矣南湖无此客，似乔松、万丈凌霄举。", "飞欬唾，扫尘土。", "承平气象森眉宇。", "想天家、骖鸾洞里，细烟冰雾。", "我亦秦关归未得，谁念干将醉扶。", "拼良夜、敧横冠屦。", "莫欢潇湘居尚远，拥戎轺万骑鸣笳鼓。", "云正锁，汴京路。"]'),
('song-ci-485','贺新郎','张','宋','宋词','song-ci','贺新郎','[]','邂逅非专约。',141,'宋词/ci.song.12000.json','["邂逅非专约。", "记当年、林堂对竹，艳歌春酌。", "一笑乘鸾明月影，馀事丹青麟阁。", "待宇宙、长绳穿却。", "念我中原空有梦，渺风尘、万里迷长乐。", "愁易老，欠灵药。", "别来几度霜天鹗。", "压纷纷、吞腥啄腐，狗偷乌攫。", "东晋风流兼慷慨，公自阳春有脚。", "妙悟处、不存毫发。", "何日相从云水去，看精神峭紧芝田鹤。", "书壮语，遍岩壑。"]'),
('song-ci-486','瑞鹤仙','张鎡','宋','宋词','song-ci','瑞鹤仙','[]','喜浓寒乍退。',126,'宋词/ci.song.12000.json','["喜浓寒乍退。", "风共日、已作深春天气。", "轻车载歌吹。", "选名坊闲玩，落梅秾李。", "无端雨细。", "动清愁、聊成浅醉。", "怅年时、携手同来，笑里绣帘斜倚。", "佳节匆匆又至。", "抚事惊心，忍堪重记。", "阑情倦意。", "行不是，坐不是。", "闷归来，已早游人回尽，灯暗重门欲闭。", "念欢娱、最是今宵，怎知恁地。"]'),
('song-ci-487','八声甘州','张鎡','宋','宋词','song-ci','八声甘州','[]','领千岩万壑岂无人，惟欠稼轩来。',118,'宋词/ci.song.12000.json','["领千岩万壑岂无人，惟欠稼轩来。", "正松梧秋到，旌旗风动，楼观雄开。", "俯槛何劳一笑，瀚海荡纤埃。", "馀事了凫骛，闲命尊罍。", "江左风流旧话，想登临浩叹，白骨苍苔。", "把龙韬藏去，游戏且蓬莱。", "念乡关、偏怜霜鬓，爱盛名、何似展真才。", "怀公处，夜深凝望、云汉星回。"]'),
('song-ci-488','八声甘州','张','宋','宋词','song-ci','八声甘州','[]','对黄花犹自满庭开，那恨过重阳。',118,'宋词/ci.song.12000.json','["对黄花犹自满庭开，那恨过重阳。", "凭阑干醉袖，依依晚日，飘动寒香。", "自叹平生豪纵，歌笑几千场。", "白发欺人早，多似清霜。", "谁信心情都懒，但禅龛道室，黄卷僧床。", "把偎红调粉，抛掷向他芳。", "□唤汝、东山归去，正灯明、松户竹篱旁。", "关门睡，尽教人道，痴钝何妨。"]'),
('song-ci-489','江城子','张','宋','宋词','song-ci','江城子','[]','飞来冰雪冷无声。',86,'宋词/ci.song.12000.json','["飞来冰雪冷无声。", "可中庭。", "骨毛清。", "卧看东南，和露两三星。", "蓦地神游天上去，呼彩凤，驾云骈。", "望舒宫殿玉峥嵘。", "桂千层。", "宝香凝。", "捣药仙童，邀我论长生。", "一笑归来人未睡，花送影，上窗棂。"]'),
('song-ci-490','渔家傲','张','宋','宋词','song-ci','渔家傲','[]','拂拂春风生草际。',72,'宋词/ci.song.12000.json','["拂拂春风生草际。", "新晴万景供游戏。", "鸥鹭飞来斜照里。", "金和翠。", "分明画出真山水。", "遮个渔翁无愠喜。", "乾坤都在乌蓬底。", "一曲高歌千古意。", "闲来睡。", "从教月到花汀外。"]'),
('song-ci-491','八声甘州','张','宋','宋词','song-ci','八声甘州','[]','叹流光迅景，百年间、能醉几中秋。',119,'宋词/ci.song.12000.json','["叹流光迅景，百年间、能醉几中秋。", "正凄蛩响砌，惊乌翻树，烟淡苹洲。", "谁唤金轮出海，不带一云浮。", "才上青林顶，俄转珠楼。", "人老欢情已减，料素娥信我，不为闲愁。", "念几番清梦，常是故乡留。", "倩风前、数声横管，叫玉鸾、骑向碧空游。", "谁能顾，黍炊荣利，蚁战仇雠。"]'),
('song-ci-492','木兰花慢','张','宋','宋词','song-ci','木兰花慢','[]','清明初过后，正空翠、霭晴鲜。',122,'宋词/ci.song.12000.json','["清明初过后，正空翠、霭晴鲜。", "念水际楼台，城隅花柳，春意无边。", "清时自多暇日，看连镳、飞盖拥群贤。", "朱邸横经满坐，紫微渊思如泉。", "高情那更属云天。", "语笑杂歌弦。", "向啼鴂声中，落红影里，忍负芳年。", "浮生转头是梦，恐他时、高会却难全。", "快意淋浪醉墨，要令海内喧传。"]'),
('song-ci-493','念奴娇','张鎡','宋','宋词','song-ci','念奴娇','[]','东吴名胜，有高楼直在，浮云齐处。',120,'宋词/ci.song.12000.json','["东吴名胜，有高楼直在，浮云齐处。", "十二阑干邀远望，历历斜阳烟树。", "香径人稀，屧廊山绕，往事今何许。", "一天和气，为谁吹散疏雨。", "知是兰省星郎，朱轮森戟，与风光为主。", "暇日登携多雅致，容我追随临赋。", "小宴重开，晚寒初劲，还下危梯去。", "烛花红坠，瑞堂犹按歌舞。"]'),
('song-ci-494','兰陵王','张鎡','宋','宋词','song-ci','兰陵王','[]','蓼汀侧。',158,'宋词/ci.song.12000.json','["蓼汀侧。", "朝霭依依弄色。", "知何许、湘女淡妆，羽节飞来带秋碧。", "轻裙素绡织。", "谁与明珰竞饰。", "无言处、相与溯回，应有柔情正堆积。", "当年驻香鹢。", "记草媚罗裙，波映文席。", "□□□□□□摘。", "□□□□□，□□□□，斜阳返照暮雨湿。", "爱天际凉入。", "愁寂。", "念畴昔。", "谩太华峰顶，幽梦寻觅。", "尔今两鬓如花白。", "但一线才思，半星心力。", "新词奇句，便做有，怎道得。"]'),
('song-ci-495','乌夜啼','张鎡','宋','宋词','song-ci','乌夜啼','[]','晓来闲立回塘。',44,'宋词/ci.song.12000.json','["晓来闲立回塘。", "一襟香。", "玉飐云松风外、数枝凉。", "相并浑如私语，恼人肠。", "飞去方知白鹭、在花旁。"]'),
('song-ci-496','如梦令','张','宋','宋词','song-ci','如梦令','[]','野菊亭亭争秀。',40,'宋词/ci.song.12000.json','["野菊亭亭争秀。", "闲伴露荷风柳。", "浅碧小开花，谁摘谁看谁嗅。", "知否。", "知否。", "不入东篱杯酒。"]'),
('song-ci-497','失调名','张','宋','宋词','song-ci','失调名','["\u6d1e\u5ead\u6e56"]','翠鬓佩明珂。',50,'宋词/ci.song.12000.json','["翠鬓佩明珂。", "度纹波。", "亲到曾入梦，听云和。", "洞庭香、随月影来过。", "无尘土、敢涴弓罗。", "正似梦时风韵、更娇多。"]'),
('song-ci-498','风入松','张','宋','宋词','song-ci','风入松','[]','芳丛簇簇水滨生。',90,'宋词/ci.song.12000.json','["芳丛簇簇水滨生。", "勾引午风清。", "六花大似天边雪，又几时、雪有三层。", "明艳射回蜂翅，净香熏透蝉声。", "晚檐人共月同行。", "疏影动银屏。", "指尖轻拈都如玉，听画栏、高啭流莺。", "道是花枝比得，不成花也多情。"]'),
('song-ci-499','蓦山溪','张','宋','宋词','song-ci','蓦山溪','[]','抚连吟就，檐葡还曾赋。',102,'宋词/ci.song.12000.json','["抚连吟就，檐葡还曾赋。", "相伴更无花，倦炉熏、日长难度。", "柔桑叶里，玉碾小芙蕖，生竺国，长闽山，移向玉城住。", "池亭竹院，宴坐冰围处。", "绿绕百千丛，夜将阑、争开迎露。", "煞曾评论，娇媚胜江梅，香称月，韵宜风，消尽人间暑。"]'),
('song-ci-500','菩萨蛮','张','宋','宋词','song-ci','菩萨蛮','[]','层层细剪冰花小。',52,'宋词/ci.song.12000.json','["层层细剪冰花小。", "新随荔子云帆到。", "一露一番开。", "玉人催卖栽。", "爱花心未已。", "摘放冠儿里。", "轻浸水晶凉。", "一窝云影香。"]'),
('song-ci-501','贺新郎','张','宋','宋词','song-ci','贺新郎','[]','桂隐传杯处。',142,'宋词/ci.song.12000.json','["桂隐传杯处。", "有风流、千岩韵胜，太丘遗绪。", "玉季金昆霄汉侣，平步鸾坡挥麈。", "莫便驾、飞帆烟渚。", "云动精神衡岳去，向君山、帝乐锵韶濩。", "兰艺畹，吊湘楚。", "南湖老矣无襟度。", "但尊前、踉跄醉影，帽花颠仆。", "只恐清时专文教，犹贷阴山狂虏。", "卧锦帐、貔貅钲鼓。", "忠烈前勋赍万恨，望神都、魏阙奔狐兔。", "呼翠袖，为君舞。"]'),
('song-ci-502','柳梢青','张','宋','宋词','song-ci','柳梢青','[]','天远山围，龙蟠淡霭，虎踞斜晖。',61,'宋词/ci.song.12000.json','["天远山围，龙蟠淡霭，虎踞斜晖。", "几度功名，几番成败，浑似鸥飞。", "楼台一望凄迷。", "算到底、空争是非。", "今夜潮生，明朝风顺，且送船归。"]'),
('song-ci-503','鹧鸪天','张','宋','宋词','song-ci','鹧鸪天','[]','御路东风拂翠衣。',64,'宋词/ci.song.12000.json','["御路东风拂翠衣。", "卖灯人散烛笼稀。", "不知月底梅花冷，只忆桥边步袜归。", "闲梦淡，旧游非。", "夜深谁在小帘帏。", "罘罳儿下围炉坐，明处行人立地时。"]'),
('song-ci-504','宴山亭・燕山亭','张','宋','宋词','song-ci','宴山亭・燕山亭','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','幽梦初回，重阴未开，晓色吹成疏雨。',123,'宋词/ci.song.12000.json','["幽梦初回，重阴未开，晓色吹成疏雨。", "竹槛气寒，蕙畹声摇，新绿暗通南浦。", "未有人行，才半启、回廊朱户。", "无绪。", "空望极霓旌，锦书难据。", "苔径追忆曾游，念谁伴、秋千采绳芳柱。", "犀奁黛卷，凤枕云孤，应也几番凝伫。", "怎得伊来，花雾绕、小堂深处。", "留住。", "直到老、不教归去。"]'),
('song-ci-505','柳梢青','张','宋','宋词','song-ci','柳梢青','[]','千丈风漪。',61,'宋词/ci.song.12000.json','["千丈风漪。", "霁光明处，花柳高低。", "箫鼓声中，宝钗遥认，兰棹交驰。", "贪呆觑著帘儿。", "不好价、伊家怎知。", "便是重来，真情厮向，难似当时。"]'),
('song-ci-506','朝中措','张','宋','宋词','song-ci','朝中措','["\u897f\u6e56"]','先生心地等空虚。',57,'宋词/ci.song.12000.json','["先生心地等空虚。", "行处幻仙都。", "点缀玲珑花柳，翻腾窈窕规模。", "三杯两盏，五言十字，迟老工夫。", "受用南湖风月，何须更到西湖。"]'),
('song-ci-507','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','玉带猩袍，遥望翠华，马去似龙。',140,'宋词/ci.song.12000.json','["玉带猩袍，遥望翠华，马去似龙。", "拥貂蝉争出，千宫鳞集，貔貅不断，万骑云从。", "细柳营开，团花袍窄，人指汾阳郭令公。", "山西将，算韬钤有种，五世元戎。", "旌旗蔽满寒空。", "鱼阵整、从容虎帐中。", "想刀明似雪，纵横脱鞘，箭飞如雨，霹雳鸣弓。", "威憾边城，气吞胡虏，惨淡尘沙吹北风。", "中兴事，看君王神武，驾驭英雄。"]'),
('song-ci-508','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','缓辔徐驱，儿童聚欢，神仙画图。',139,'宋词/ci.song.12000.json','["缓辔徐驱，儿童聚欢，神仙画图。", "正芹塘雨过，泥融路软，金莲自策，小小蓝舆。", "傍柳题诗，穿花劝酒，嗅蕊攀条得自如。", "经行处，有苍松夹道，不用传呼。", "清泉怪石盘纡。", "信风景江淮各异殊。", "记东坡赋就，沙笼素壁，西山句好，帘卷晴珠。", "白玉堂深，黄金印大，无此文君载后车。", "挥毫罢，看淋漓雪壁，真草行书。"]'),
('song-ci-509','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','古岂无人，可以似吾，稼轩者谁。',139,'宋词/ci.song.12000.json','["古岂无人，可以似吾，稼轩者谁。", "拥七州都督，虽然陶侃，机明神鉴，未必能诗。", "常衮何如，羊公聊尔，千骑东方侯会稽。", "中原事，纵匈奴未灭，毕竟男儿。", "平生出处天知。", "算整顿乾坤终有时。", "问湖南宾客，侵寻老矣，江西户口，流落何之。", "尽日楼台，四边屏幛，目断江山魂欲飞。", "长安道，奈世无刘表，王粲畴依。"]'),
('song-ci-510','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','问讯竹湖，竹如之何，如何未归。',139,'宋词/ci.song.12000.json','["问讯竹湖，竹如之何，如何未归。", "道吴山越水，无非佳处，来无定止，去亦何之。", "莫是秋来，未能忘耳，心与孤云相伴飞。", "愁无奈，但北窗寄傲，南涧题诗。", "人生万事成痴。", "算世上久无公是非。", "恨云台突兀，无君子者，雪堂寥落，有美人兮。", "疏雨梧桐，微云河汉，钟鼎山林无限悲。", "阳山县，是昌黎误汝，汝误昌黎。"]'),
('song-ci-511','沁园春','刘过','宋','宋词','song-ci','沁园春','["\u94b1\u5858\u6c5f", "\u6d1e\u5ead\u6e56"]','一剑横空，飞过洞庭，又为此来。',139,'宋词/ci.song.12000.json','["一剑横空，飞过洞庭，又为此来。", "有汝阳璡者，唱名殿陛，玉川公子，开宴尊罍。", "四举无成，十年不调，大宋神仙刘秀才。", "如何好，将百千万事，付两三杯。", "未尝戚戚于怀。", "问自古英雄安在哉。", "任钱塘江上，潮生潮落，姑苏台畔，花谢花开。", "盗号书生，强名举子，未老雪从头上催。", "谁羡汝，拥三千珠履，十二金钗。"]'),
('song-ci-512','沁园春','刘过','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','玉带金鱼，绿鬓朱颜，神仙画图。',139,'宋词/ci.song.12000.json','["玉带金鱼，绿鬓朱颜，神仙画图。", "把擎天柱石，空留绿野，济川舟楫，闲舣西湖。", "天欲安刘，公归重赵，许大元勋谁得如。", "平章处，看人如伊吕，世似唐虞。", "不须别样规模。", "但收揽人才多用儒。", "况自昔军中，胆能寒虏，而今胸次，气欲吞胡。", "紫府真人，黑头元宰，收敛神功寂似无。", "归来好，正芝香枣熟，鹤瘦松臞。"]'),
('song-ci-513','沁园春','刘过','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','斗酒彘肩，风雨渡江，岂不快哉。',140,'宋词/ci.song.12000.json','["斗酒彘肩，风雨渡江，岂不快哉。", "被香山居士，约林和靖，与东坡老，驾勒吾回。", "坡谓西湖，正如西子，浓抹淡妆临镜台。", "二公者，皆掉头不顾，只管衔杯。", "白云天竺飞来。", "图画里、峥嵘楼观开。", "爱东西双涧，纵横水绕，两峰南北，高下云堆。", "逋曰不然，暗香浮动，争似孤山先探梅。", "须晴去，访稼轩未晚，且此俳徊。"]'),
('song-ci-514','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','柳思花情，湖山应怪，先生又来。',139,'宋词/ci.song.12000.json','["柳思花情，湖山应怪，先生又来。", "想旧时谈舌，依然解使，六丁奔走，驱斥风雷。", "翠袖传觞，金貂换酒，痛饮何妨三百杯。", "人间世，算谪仙去后，谁是天才。", "碧窗画鼓船斋。", "胸次与乾坤一样开。", "试云间招手，下呼馀子，逡巡去矣，但觉尘埃。", "若是花时，无风无雨，一日须来一百回。", "教人道，看玉山自倒，不用相推。"]'),
('song-ci-515','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','万马不嘶，一声寒角，令行柳营。',139,'宋词/ci.song.12000.json','["万马不嘶，一声寒角，令行柳营。", "见秋原如掌，枪刀突出，星驰铁骑，阵势纵横。", "人在油幢，戎韬总制，羽扇从容裘带轻。", "君知否，是山西将种，曾系诗盟。", "龙蛇纸上飞腾。", "看落笔四筵风雨惊。", "便尘沙出塞，封侯万里，印金如斗，未惬平生。", "拂拭腰间，吹毛剑在，不斩楼兰心不平。", "归来晚，听随军鼓吹，已带边声。"]'),
('song-ci-516','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','画鹢凌空，红旗翻雪，灵鼍震雷。',140,'宋词/ci.song.12000.json','["画鹢凌空，红旗翻雪，灵鼍震雷。", "叹沈湘去国，怀沙吊古，江山凝恨，父老兴哀。", "正直难留，灵修已化，三户真能存楚哉。", "空江上，但烟波渺渺，岁月洄洄。", "持杯。", "西眺徘徊。", "些千载忠魂来不来。", "谩争标夺胜，鱼龙喷薄，呼声贾勇，地裂山摧。", "香黍缠丝，宝符插艾，犹有樽前儿女怀。", "兴亡事，付浮云一笑，身在天涯。"]'),
('song-ci-517','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','自注铜瓶，作梅花供，尊前数枝。',139,'宋词/ci.song.12000.json','["自注铜瓶，作梅花供，尊前数枝。", "说边头旧话，人生消得，几番行役，问我何之。", "小队红旗，黄金大印，直待封侯知几时。", "杯行处，且淋漓一醉，明日东西。", "如椽健笔鸾飞。", "还为写春风陌上词。", "便平生豪气，销磨酒里，依然此乐，儿辈争知。", "霜重貂裘，夜寒如水，饮到月斜犹未归。", "仙山路，有笙簧度曲，声到琴丝。"]'),
('song-ci-518','沁园春','刘过','宋','宋词','song-ci','沁园春','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','万里湖南，江山历历，皆吾旧游。',139,'宋词/ci.song.12000.json','["万里湖南，江山历历，皆吾旧游。", "看飞凫仙子，张帆直上，周郎赤壁，鹦鹉汀洲。", "吸尽西江，醉中横笛，人在岳阳楼上头。", "波涛静，泛洞庭青草，重整兰舟。", "长沙会府风流。", "有万户娉婷帘玉钩。", "恨楚城春晚，岸花墙燕，还将客送，不与人留。", "且唤阳城，更招元结，摩抚之馀歌咏休。", "心期处，算世间真有，骑鹤扬州。"]'),
('song-ci-519','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','一别三年，一日三秋，庶几见之。',139,'宋词/ci.song.12000.json','["一别三年，一日三秋，庶几见之。", "念丹霞秋冷，风巾雾屦，五湖春暖，雨笠烟蓑。", "山水光中，要人携手，独欠金华俞紫芝。", "谁知道，向酴醿香里，杯酒同持。", "油然川泳云飞。", "但口不能言心自知。", "便狂敲铜斗，我歌君和，醉拈如意，我舞君随。", "风韵如君，岂堪言别，别后如之何勿思。", "须金玉，再相逢莫负，芷约兰期。"]'),
('song-ci-520','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','一笛横风，稳转船头，系楫大江。',139,'宋词/ci.song.12000.json','["一笛横风，稳转船头，系楫大江。", "还有人争说，鸣琴手段，教侬重吐，锦绣肝肠。", "不复少年，插花槌鼓，雅意在乎云水乡。", "阳关泪，笑琼姬犹恋，奇俊王郎。", "谈兵齿颊冰霜。", "有万户侯封何用忙。", "借烟霞且作，诗中队仗，鹭鹓已是，归日班行。", "收敛平生，筹边胸次，以酒浇之书传香。", "消凝处，怕三更枕上，疏雨潇湘。"]'),
('song-ci-521','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','销薄春冰，碾轻寒玉，渐长渐弯。',140,'宋词/ci.song.12000.json','["销薄春冰，碾轻寒玉，渐长渐弯。", "见凤鞋泥污，偎人强剔，龙涎香断，拨火轻翻。", "学抚瑶琴，时时欲翦，更掬水鱼鳞波底寒。", "纤柔处，试摘花香满，镂枣成班。", "时将粉泪偷弹。", "记绾玉曾教柳傅看。", "算恩情相著，搔便玉体，归期暗数，画遍阑干。", "每到相思，沈吟静处，斜倚朱唇皓齿间。", "风流甚，把仙郎暗掐，莫放春闲。"]'),
('song-ci-522','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','洛浦凌波，为谁微步，轻尘暗生。',142,'宋词/ci.song.12000.json','["洛浦凌波，为谁微步，轻尘暗生。", "记踏花芳径，乱红不损，步苔幽砌，嫩绿无痕。", "衬玉罗悭，销金样窄，载不起、盈盈一段春。", "嬉游倦，笑教人款捻，微褪些跟。", "有时自度歌声。", "悄不觉、微尖点拍频。", "忆金莲移换，文鸳得侣，绣茵催衮，舞凤轻分。", "懊恨深遮，牵情半露，出没风前烟缕裙。", "知何似，似一钩新月，浅碧笼云。"]'),
('song-ci-523','水调歌头','刘过','宋','宋词','song-ci','水调歌头','[]','春事能几许，密叶著青梅。',114,'宋词/ci.song.12000.json','["春事能几许，密叶著青梅。", "日高花困，海棠春暖想都开。", "不惜春衣典尽，只怕春光归去，片片点苍苔。", "能得几时好，追赏莫俳徊。", "雨飘红，风换翠，苦相催。", "人生行乐，且须痛饮莫辞杯。", "坐则高谈风月，醉则恣眠芳草，醒后亦佳哉。", "湖上新亭好，何事不曾来。"]'),
('song-ci-524','水调歌头','刘过','宋','宋词','song-ci','水调歌头','[]','弓剑出榆塞，铅椠上蓬山。',114,'宋词/ci.song.12000.json','["弓剑出榆塞，铅椠上蓬山。", "得之浑不费力，失亦匹如闲。", "未必古人皆是，未必今人俱错，世事沐猴冠。", "老子不分别，内外与中间。", "酒须饮，诗可作，铗休弹。", "人生行乐，何自催得鬓毛斑。", "达则牙旗金甲，穷则蹇驴破帽，莫作两般看。", "世事只如此，自有识鸮鸾。"]'),
('song-ci-525','水调歌头','刘过','宋','宋词','song-ci','水调歌头','[]','文采汉机轴，人物晋风流。',114,'宋词/ci.song.12000.json','["文采汉机轴，人物晋风流。", "丈夫有此，便可谈笑觅封侯。", "试问湘南水石，今古阅人多矣，曾见此公不。", "名姓出天上，声誉塞南州。", "斩楼兰，擒颉利，志须酬。", "青衫何事，犹在楚尾与吴头。", "闻道长安灞水，尽是三槐风月，好奉板舆游。", "此曲为君寿，为我唤歌喉。"]'),
('song-ci-526','念奴娇','刘过','宋','宋词','song-ci','念奴娇','[]','知音者少，算乾坤许大，著身何处。',120,'宋词/ci.song.12000.json','["知音者少，算乾坤许大，著身何处。", "直待功成方肯退，何日可寻归路。", "多景楼前，垂虹亭下，一枕眠秋雨。", "虚名相误，十年枉费辛苦。", "不是奏赋明光，上书北阙，无惊人之语。", "我自匆忙天未许，赢得衣裾尘土。", "白壁追欢，黄金买笑，付与君为主。", "莼鲈江上，浩然明日归去。"]'),
('song-ci-527','念奴娇','刘过','宋','宋词','song-ci','念奴娇','[]','并肩楼上，小阑干、犹记年时凭处。',120,'宋词/ci.song.12000.json','["并肩楼上，小阑干、犹记年时凭处。", "百岁光阴弹指过，消得几番寒暑。", "鹊去桥空，燕飞钗在，不见穿针女。", "老怀凄断，夜凉知共谁诉。", "不管天上人间，秋期月影，两处相思苦。", "闲揭纱窗人未寝，泪眼不曾晴雨。", "花落莲汀，叶喧梧井，孤雁应为侣。", "浩歌而已，一杯长记时序。"]'),
('song-ci-528','唐多令','刘过','宋','宋词','song-ci','唐多令','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','芦叶满汀洲。',74,'宋词/ci.song.12000.json','["芦叶满汀洲。", "塞沙带浅流。", "二十年、重过南楼。", "柳下系舟犹未稳，能几日、又中秋。", "黄鹤断矶头。", "故人今不在。", "旧江山，浑是新愁。", "欲买桂花同载酒，终不似、少年游。"]'),
('song-ci-529','满江红','刘过','宋','宋词','song-ci','满江红','[]','猎猎风蒲，画船转、碧湾沙浦。',115,'宋词/ci.song.12000.json','["猎猎风蒲，画船转、碧湾沙浦。", "都不是、蓼汀桃岸，橘州梅渚。", "指点山公骑马地，经由羊祜登山处。", "悄一如、人在水晶宫，销烦暑。", "薰风动，帘旌举。", "秦筝奏，凌波舞。", "拼冰壶沈醉，晚凉归去。", "侵岸一篙杨柳浪，过云几点荷花雨。", "倚楼人、十里凭阑干，神仙侣。"]'),
('song-ci-530','满江红','刘过','宋','宋词','song-ci','满江红','[]','敌面风轻，一两点、海棠微雨。',115,'宋词/ci.song.12000.json','["敌面风轻，一两点、海棠微雨。", "春总在、英雄元帅，晓来游处。", "楼阁万家帘幕卷，江郊十里旌旗驻。", "有黄鹂、百舌啭新声，垂杨舞。", "寒食近，喧箫鼓。", "车马闹，铜鞮路。", "尽不妨沈醉，与花为主。", "风韵可将图画比，笑谈尽是惊人语。", "问何如、邹湛岘山头，陪羊祜。"]'),
('song-ci-531','满江红','刘过','宋','宋词','song-ci','满江红','[]','霜树啼鸦，梅欲放、小春清晓。',115,'宋词/ci.song.12000.json','["霜树啼鸦，梅欲放、小春清晓。", "庆初度、佩环风外，笑声云表。", "一柱独擎梁栋重，十年整顿乾坤了。", "种春风、桃李满人间，知多少。", "功甚大，心常小。", "居廊庙，思耕钓。", "奈华夷休戚，系王颦笑。", "盟府山河书带砺，成周师保须周召。", "看貂蝉、绿鬓本天人，真难老。"]'),
('song-ci-532','谒金门','刘过','宋','宋词','song-ci','谒金门','[]','归不去。',53,'宋词/ci.song.12000.json','["归不去。", "船泊早春梅渚。", "试听玉人歌白苎。", "行云无觅处。", "翦烛写诗无语。", "漠漠寒生窗户。", "明日短篷眠夜雨。", "宝钗留半股。"]'),
('song-ci-533','谒金门','刘过','宋','宋词','song-ci','谒金门','[]','秋兴恶。',53,'宋词/ci.song.12000.json','["秋兴恶。", "愁怯罗衾风弱。", "雨线垂垂晴又落。", "轻烟笼翠箔。", "休道旅怀萧索。", "生怕香浓灰薄。", "桂子莫教孤酒约。", "诗情浑落魄。"]'),
('song-ci-534','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','倦舞轮袍后。',141,'宋词/ci.song.12000.json','["倦舞轮袍后。", "正鸾慵凤困，依然怨新怀旧。", "别有艳妆来执乐，春笋微揎罗袖。", "试一曲、琅璈初奏。", "莫放珠帘容易卷，怕人知、世有梨园手。", "钗玉冷，钏金瘦。", "烛花对翦明於昼。", "画堂深、屏山掩翠，炭红围兽。", "错认佩环犹未是，依约雏莺啭柳。", "任箭滴、铜壶银漏。", "一片雄心天外去，为声清、响彻云霄透。", "人醉也，尚呼酒。"]'),
('song-ci-535','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','院宇重重掩。',142,'宋词/ci.song.12000.json','["院宇重重掩。", "醉沈沈、亭阴转午，绣帘高卷。", "金鸭香浓喷宝篆，惊起雕梁语燕。", "正一架、酴醿开遍。", "嫩萼梢头舒素脸。", "似月娥、初试宫妆浅。", "风力嫩，异香软。", "佳人无意拈针线。", "绕朱阑、六曲俳徊，为他留恋。", "试把花心轻轻数，暗卜归期近远。", "奈数了、依然重怨。", "把酒问春春不管。", "枉教人、只恁空肠断。", "肠断处，怎消遣。"]'),
('song-ci-536','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','老去相如倦。',141,'宋词/ci.song.12000.json','["老去相如倦。", "向文君说似，而今怎生消遣。", "衣袂京尘曾染处，空有香红尚软。", "料彼此、魂销肠断。", "一枕新凉眠客舍，听梧桐、疏雨秋声颤。", "灯晕冷，记初见。", "楼低不放珠帘卷。", "晚妆残、翠钿狼藉，泪痕凝面。", "人道愁来须殢酒，无奈愁深酒浅。", "但寄兴、焦琴纨扇。", "莫鼓琵琶江上曲，怕荻花、枫叶俱凄怨。", "云万叠，寸心远。"]'),
('song-ci-537','贺新郎','刘过','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','睡觉莺啼晓。',141,'宋词/ci.song.12000.json','["睡觉莺啼晓。", "醉西湖、两峰日日，买花簪帽。", "去尽酒徒无人问，唯有玉山自倒。", "任拍手、儿童争笑。", "一舸乘风翩然去，避鱼龙、不见波声悄。", "歌韵歇，唤苏小。", "神仙路远蓬莱岛。", "紫云深、参差禁树，有烟花绕。", "人世红尘西障日，百计不如归好。", "付乐事、与他年少。", "费尽柳金梨雪句，问沈香亭北何时召。", "心未惬，鬓先老。"]'),
('song-ci-538','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','晓印霜花步。',142,'宋词/ci.song.12000.json','["晓印霜花步。", "梦半醒、扶上雕鞍，马嘶人去。", "岚湿青丝双辔冷，缓鞚野梅江路。", "听画角，吹残更鼓。", "悲壮寒声撩客恨，甚貂裘、重拥愁无数。", "霜月白，照离绪。", "青楼回首家何处。", "早山遥、水阔天低，断肠烟树。", "谁念天涯牢落况，轻负暖烟浓雨。", "记酒醒、香销时语。", "客里归鞯须早发，怕天寒、风急相思苦。", "应为我，翠眉聚。"]'),
('song-ci-539','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','多病刘郎瘦。',142,'宋词/ci.song.12000.json','["多病刘郎瘦。", "最伤心、天寒岁晚，客他乡久。", "大舸翩翩何许至，元是高阳旧友。", "便一笑、相欢携手。", "为问武昌城下月，定何如、扬子江头柳。", "追往事，两眉皱。", "烛花细翦明於昼。", "唤青娥、小红楼上，殷勤劝酒。", "昵昵琵琶恩怨语，春笋轻笼翠袖。", "看舞彻、金钗微溜。", "若见故乡吾父老，道长安、市上狂如旧。", "重会面，几时又。"]'),
('song-ci-540','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','弹铗西来路。',141,'宋词/ci.song.12000.json','["弹铗西来路。", "记匆匆、经行十日，几番风雨。", "梦里寻秋秋不见，秋在平芜远树。", "雁信落、家山何处。", "万里西风吹客鬓，把菱花、自笑人如许。", "留不住，少年去。", "男儿事业无凭据。", "记当年、悲歌击楫，酒酣箕踞。", "腰下光芒三尺剑，时解挑灯夜语。", "谁更识、此时情绪。", "唤起杜陵风月手，写江东渭北相思句。", "歌此恨，慰羁旅。"]'),
('song-ci-541','水龙吟','刘过','宋','宋词','song-ci','水龙吟','[]','谪仙狂客何如，看来毕竟归田好。',127,'宋词/ci.song.12000.json','["谪仙狂客何如，看来毕竟归田好。", "玉堂无比，三山海上，虚无飘缈。", "读罢离骚，酒香犹在，觉人间小。", "任菜花葵麦，刘郎去后，桃开处、春多少。", "一夜雪迷兰棹。", "傍寒溪、欲寻安道。", "而今纵有，新诗冰柱，有知音否。", "想见鸾飞，如椽健笔，檄书亲草。", "算平生、白傅风流，未可向、香山老。"]'),
('song-ci-542','水龙吟','刘过','宋','宋词','song-ci','水龙吟','[]','庆流阅古无穷，相门又见生名世。',126,'宋词/ci.song.12000.json','["庆流阅古无穷，相门又见生名世。", "致君事业，全如忠献，经天纬地。", "十二年间，挺身为国，勋庸知几。", "便书之竹帛，铭之彝鼎，勤劳意、竟谁记。", "一自平章庶政，觉人心、顿然兴起。", "朝庭既正，乾坤交泰，华夷欢喜。", "行定中原，锦衣归相，分茅□□。", "看貂蝉绿鬓，中书上考，过三千岁。"]'),
('song-ci-543','祝英台近','刘过','宋','宋词','song-ci','祝英台近','[]','笑天涯，还倦客。',95,'宋词/ci.song.12000.json','["笑天涯，还倦客。", "欲起病无力。", "风雨春归，一日近一日。", "看人结束征衫，前呵骑马，腰剑上、陇西平贼。", "鬓分白。", "只可归去家山，无田种瓜得。", "空抱遗书，憔悴小楼侧。", "杜鹃不管人愁，月明枝上，直啼到、枕边相觅。"]'),
('song-ci-544','柳梢青','刘过','宋','宋词','song-ci','柳梢青','[]','泛菊杯深，吹梅角远，同在京城。',61,'宋词/ci.song.12000.json','["泛菊杯深，吹梅角远，同在京城。", "聚散匆匆，云边孤雁，水上浮萍。", "教人怎不伤情。", "觉几度、魂飞梦惊。", "后夜相思，尘随马去，月逐舟行。"]'),
('song-ci-545','霜天晓角','刘过','宋','宋词','song-ci','霜天晓角','[]','霜天晓角。',53,'宋词/ci.song.12000.json','["霜天晓角。", "梦回滋味恶。", "酒醒不襟寒力，纱窗外、月华薄。", "拥衾思旧约。", "无情风透幕。", "惟有梅花相伴，不成是、也吹落。"]'),
('song-ci-546','辘轳金井・四犯翦梅花','刘过','宋','宋词','song-ci','辘轳金井・四犯翦梅花','[]','翠眉重扫。',116,'宋词/ci.song.12000.json','["翠眉重扫。", "后房深、自唤小蛮娇小。", "绣带罗垂，报浓妆才了。", "堂虚夜悄。", "但依约、鼓箫声闹。", "一曲梅花，尊前舞彻，梨园新调。", "高阳醉、玉山未倒。", "看鞋飞凤翼，钗梁微袅。", "秋满东湖，更西风凉早。", "桃源路杳。", "记流水、泛舟曾到。", "桂子香浓，梧桐影转，月寒天晓。"]'),
('song-ci-547','好事近','刘过','宋','宋词','song-ci','好事近','[]','谁斫碧琅轩，影撼半庭风月。',54,'宋词/ci.song.12000.json','["谁斫碧琅轩，影撼半庭风月。", "尚有岁寒心在，留得数茎华发。", "龙孙戏弄碧波涛，随手清风发。", "滚到浪花深处，起一窝香雪。"]'),
('song-ci-548','四字令・醉太平','刘过','宋','宋词','song-ci','四字令・醉太平','[]','情深意真。',46,'宋词/ci.song.12000.json','["情深意真。", "眉长鬓青。", "小楼明月调筝。", "写春风数声。", "思君忆君。", "魂牵梦萦。", "翠销香暖云屏。", "更那堪酒醒。"]'),
('song-ci-549','蝶恋花','刘过','宋','宋词','song-ci','蝶恋花','[]','帘幕闻声歌已妙。',70,'宋词/ci.song.12000.json','["帘幕闻声歌已妙。", "一曲尊前，真个梅花早。", "眉黛两山谁为扫。", "风流京兆江南调。", "醉得白鬚人易老。", "老去侯鲭，旧也曾年少。", "后夜短篷霜月晓。", "梦魂依约云山绕。"]'),
('song-ci-550','蝶恋花','刘过','宋','宋词','song-ci','蝶恋花','[]','宝鉴年来微有晕。',72,'宋词/ci.song.12000.json','["宝鉴年来微有晕。", "懒照容华，人远天涯近。", "昨夜灯花还失信。", "无心更唱《江城引》。", "行过短墙回首认。", "醉撼花梢，红雨飞成阵。", "拌了为郎憔悴损。", "庞儿恰似江梅韵。"]'),
('song-ci-551','临江仙','刘过','宋','宋词','song-ci','临江仙','[]','满院花香晴昼永，愔愔亭户无人。',70,'宋词/ci.song.12000.json','["满院花香晴昼永，愔愔亭户无人。", "谁将心绪管青春。", "游丝知我懒，江柳也眉颦。", "近水远山都积恨，可堪芳草如茵。", "何曾一日不思君。", "无书凭朔雁，有泪在罗巾。"]'),
('song-ci-552','临江仙','刘过','宋','宋词','song-ci','临江仙','[]','数叠小山亭馆静，落花红雨园林。',70,'宋词/ci.song.12000.json','["数叠小山亭馆静，落花红雨园林。", "画楼风月想重临。", "琵琶金凤语，长笛水龙吟。", "青眼已伤前遇少，白头孤负知音。", "苔墙藓井夜沈沈。", "无聊成独坐，有恨即沾襟。"]'),
('song-ci-553','临江仙','刘过','宋','宋词','song-ci','临江仙','[]','长短驿亭南北路，蒙茸醉拥驼裘。',70,'宋词/ci.song.12000.json','["长短驿亭南北路，蒙茸醉拥驼裘。", "雪天行计欠人留。", "严风催酒醒，微雨替梅愁。", "自作小词呵冻写，冷金淡衬银钩。", "此情知得几时休。", "寒云迷洛浦，残梦绕秦楼。"]'),
('song-ci-554','临江仙','刘过','宋','宋词','song-ci','临江仙','[]','红袖扶来聊促膝，龙团共破春温。',70,'宋词/ci.song.12000.json','["红袖扶来聊促膝，龙团共破春温。", "高标终是绝尘氛。", "两箱留烛影，一水试云痕。", "饮罢清风生两腋，馀香齿颊犹存。", "离情凄咽更休论。", "银鞍和月载，金碾为谁分。"]'),
('song-ci-555','江城子','刘过','宋','宋词','song-ci','江城子','[]','海棠风韵玉梅春。',85,'宋词/ci.song.12000.json','["海棠风韵玉梅春。", "小腰身。", "晓妆新。", "长是花时，犹系茜罗裙。", "一撮精神娇欲滴，说不似，画难真。", "楼前江柳又江云。", "隔音尘。", "泪沾襟。", "一点征帆，烟浪渺无津。", "万斛相思红豆子，凭寄与个中人。"]'),
('song-ci-556','江城子','刘过','宋','宋词','song-ci','江城子','[]','淡香幽艳露华浓。',86,'宋词/ci.song.12000.json','["淡香幽艳露华浓。", "晚妆慵。", "略匀红。", "春困恹恹，□□鬓云松。", "早是自来莲步小，新样子，为谁弓。", "画堂西畔曲栏东。", "醉醒中。", "苦匆匆。", "卷上珠帘，依旧半床空。", "香炧满炉人未寝，花弄月，竹摇风。"]'),
('song-ci-557','浣溪沙','刘过','宋','宋词','song-ci','浣溪沙','["\u9ec4\u9e64\u697c"]','黄鹤楼前识楚卿。',48,'宋词/ci.song.12000.json','["黄鹤楼前识楚卿。", "彩云重叠拥娉婷。", "席间谈笑觉风生。", "标格胜如张好好，情怀浓似薛琼琼。", "半帘花月听弹筝。"]'),
('song-ci-558','浣溪沙','刘过','宋','宋词','song-ci','浣溪沙','[]','墙外濛濛雨湿烟。',48,'宋词/ci.song.12000.json','["墙外濛濛雨湿烟。", "参差小树绿阴圆。", "残春中酒落花前。", "海燕成巢终是客，鳏鱼入夜几曾眠。", "人间一段恶因缘。"]'),
('song-ci-559','浣溪沙','刘过','宋','宋词','song-ci','浣溪沙','[]','著意寻芳已自迟。',48,'宋词/ci.song.12000.json','["著意寻芳已自迟。", "可堪容易送春归。", "酒阑无奈思依依。", "杨柳小桥人远别，梨花深巷月斜辉，此情惟我与君知。"]'),
('song-ci-560','浣溪沙','刘过','宋','宋词','song-ci','浣溪沙','[]','谁把幽香透骨薰。',48,'宋词/ci.song.12000.json','["谁把幽香透骨薰。", "韵高全似玉楼人。", "几时劝酒不深颦。", "竹里绝怜闲体态，月边无限好精神。", "一枝斜插坐生春。"]'),
('song-ci-561','浣溪沙','刘过','宋','宋词','song-ci','浣溪沙','[]','雾鬓云鬟已懒梳。',48,'宋词/ci.song.12000.json','["雾鬓云鬟已懒梳。", "君休乔木妾归欤。", "且来卖酒伴相如，骨细肌丰周昉画，肉多韵胜子瞻书。", "琵琶弦索尚能无。"]'),
('song-ci-562','满庭芳','刘过','宋','宋词','song-ci','满庭芳','[]','浅约鸦黄，轻匀螺黛，故教取次梳妆。',118,'宋词/ci.song.12000.json','["浅约鸦黄，轻匀螺黛，故教取次梳妆。", "减轻琶面，新样小鸾凰。", "每为花娇玉软，慵对客、斜倚银床。", "春来病，兰薰半歇，满笐舞衣裳。", "悲凉。", "人事改，三春秾艳，一夜繁霜。", "似人归洛浦，云散高唐。", "痛念平生情分，孤负我、临老风光。", "罗裙在，凭谁留意，去觅反魂香。"]'),
('song-ci-563','西江月','刘过','宋','宋词','song-ci','西江月','[]','细雨黄梅初熟，微风燕子交飞。',58,'宋词/ci.song.12000.json','["细雨黄梅初熟，微风燕子交飞。", "手拈团扇写新题。", "心事恹恹难寄。", "片月只堪供恨，双星却有重期。", "石榴裙子正芬菲。", "知为何人慵系。"]'),
('song-ci-564','西江月','刘过','宋','宋词','song-ci','西江月','[]','素面偏宜酒晕，晓妆净洗啼痕。',58,'宋词/ci.song.12000.json','["素面偏宜酒晕，晓妆净洗啼痕。", "只疑身是玉梅魂。", "长为春风瘦损。", "冉冉烟生兰渚，娟娟月挂愁村。", "落花飞絮耿黄昏。", "又是一番新恨。"]'),
('song-ci-565','西江月','刘过','宋','宋词','song-ci','西江月','[]','楼上佳人楚楚，天边皓月徐徐。',58,'宋词/ci.song.12000.json','["楼上佳人楚楚，天边皓月徐徐。", "呼童忙为卷虾须。", "试问中情几句。", "圆少却因底事，缺多毕竟何如。", "嫦娥无语谩踌躇。", "飞过画栏西去。"]'),
('song-ci-566','天仙子','刘过','宋','宋词','song-ci','天仙子','[]','别酒醺醺容易醉。',80,'宋词/ci.song.12000.json','["别酒醺醺容易醉。", "回过头来三十里。", "马儿只管去如飞，牵一会。", "坐一会。", "断送杀人山共水。", "是则青衫终可喜。", "不道恩情拼得未。", "雪迷村店酒旗斜，去也是。", "住也是。", "烦恼自家烦恼你。"]'),
('song-ci-567','天仙子','刘过','宋','宋词','song-ci','天仙子','[]','彩笔恹恹慵赋咏。',80,'宋词/ci.song.12000.json','["彩笔恹恹慵赋咏。", "斗草闲来寻小迳。", "西园春事只供愁，当好景。", "成孤另。", "春又那知人欲病。", "洗尽残妆临晚镜。", "淡玉一团浆水莹。", "强持檀板近芳樽，云遏定。", "君须听。", "低唱月来花弄影。"]'),
('song-ci-568','六州歌头','刘过','宋','宋词','song-ci','六州歌头','["\u6d1e\u5ead\u6e56"]','中兴诸将，谁是万人英。',182,'宋词/ci.song.12000.json','["中兴诸将，谁是万人英。", "身草莽，人虽死，气填膺。", "尚如生。", "年少起河朔，弓两石，剑三尺，定襄汉，开虢洛，洗洞庭。", "北望帝京。", "狡兔依然在，良犬先烹。", "过旧时营垒，荆鄂有遗民。", "忆故将军。", "泪如倾。", "说当年事，知恨苦，不奉诏，伪耶真。", "臣有罪，陛下圣，可鉴临。", "一片心。", "万古分茅土，终不到，旧奸臣。", "人世夜，白日照，忽开明。", "衮佩冕圭百拜，九泉下、荣感君恩。", "看年年三月，满地野花春。", "卤簿迎神。"]'),
('song-ci-569','六州歌头','刘过','宋','宋词','song-ci','六州歌头','[]','镇长淮，一都会，古扬州。',181,'宋词/ci.song.12000.json','["镇长淮，一都会，古扬州。", "升平日，珠帘十里春风、小红楼。", "谁知艰难去，边尘暗，胡马扰，笙歌散，衣冠渡，使人愁。", "屈指细思，血战成何事，万户封侯。", "但琼花无恙，开落几经秋。", "故垒荒丘。", "似含羞。", "怅望金陵宅，丹阳郡，山不断绸缪。", "兴亡梦，荣枯泪，水东流。", "甚时休。", "野灶炊烟里，依然是，宿貔貅。", "叹灯火，今萧索，尚淹留。", "莫上醉翁亭，看濛濛雨、杨柳丝柔。", "笑书生无用，富贵拙身谋。", "骑鹤东游。"]'),
('song-ci-570','沁园春','刘过','宋','宋词','song-ci','沁园春','[]','天下稼轩，文章有弟，看来未迟。',139,'宋词/ci.song.12000.json','["天下稼轩，文章有弟，看来未迟。", "正三齐盗起，两河民散，势倾似土，国泛如杯。", "猛士云飞，狂胡灰灭，机会之来人共知。", "何为者，望桂林西去，一骑星驰。", "离筵不用多悲。", "唤红袖佳人分藕丝。", "种黄柑千户，梅花万里，等闲游戏，毕竟男儿。", "入幕来南，筹边如北，翻覆手高来去棋。", "公馀且，画玉簪珠履，倩米元晖。"]'),
('song-ci-571','八声甘州','刘过','宋','宋词','song-ci','八声甘州','[]','问紫岩去后汉公卿，不知几貂蝉。',114,'宋词/ci.song.12000.json','["问紫岩去后汉公卿，不知几貂蝉。", "谁能借留侯箸，著祖生鞭。", "依旧尘沙万里，河洛染腥膻。", "谁识道山客，衣钵曾传。", "共记玉堂对策，欲先明大义，次第筹边。", "况重湖八桂，袖手已多年。", "望中原驱驰去也，拥十州、牙纛正翩翩。", "春风早，看东南王气，飞绕星躔。"]'),
('song-ci-572','四犯翦梅花','刘过','宋','宋词','song-ci','四犯翦梅花','[]','水殿风凉，赐环归、正是梦熊华旦。',116,'宋词/ci.song.12000.json','["水殿风凉，赐环归、正是梦熊华旦。", "叠雪罗轻，称云章题扇。", "西清侍宴。", "望黄伞、日华笼辇。", "金券三王，玉堂四世，帝恩偏眷。", "临安记、龙飞凤舞，信神明有后，竹梧阴满。", "笑折花看，橐荷香红润。", "功名岁晚。", "带河与、砺山长远。", "麟脯杯行，狨鞯坐稳，内家宣劝。"]'),
('song-ci-573','小桃红・连理枝','刘过','宋','宋词','song-ci','小桃红・连理枝','[]','晚入纱窗静。',86,'宋词/ci.song.12000.json','["晚入纱窗静。", "戏弄菱花镜。", "翠袖轻匀，玉纤弹去，小妆红粉。", "画行人、愁外两青山，兴尊前离恨。", "宿酒醺难醒。", "笑记香肩并。", "暖借莲腮，碧云微透，晕眉斜印。", "最多情、生怕外人猜，拭香津微搵。"]'),
('song-ci-574','竹香子','刘过','宋','宋词','song-ci','竹香子','[]','一琐窗儿明快。',59,'宋词/ci.song.12000.json','["一琐窗儿明快。", "料想那人不在。", "熏笼脱下旧衣裳，件件香难赛。", "匆匆去得忒煞。", "这镜儿、也不曾盖。", "千朝百日不曾来，没这些儿个采。"]'),
('song-ci-575','祝英台近','刘过','宋','宋词','song-ci','祝英台近','[]','窄轻衫，联宝辔，花里控金勒。',95,'宋词/ci.song.12000.json','["窄轻衫，联宝辔，花里控金勒。", "有底风光，都在画阑侧。", "日迟春暖融融，杏红深处，为花醉，一鞭春色。", "对娇质。", "为我歌捧瑶觞，欢歌动阡陌。", "□似多情，飞上鬓云碧。", "晚来约住青骢，蹋花归去，乱红碎、一庭风月。"]'),
('song-ci-576','临江仙','刘过','宋','宋词','song-ci','临江仙','[]','半雨半晴模样，乍寒乍热天时。',68,'宋词/ci.song.12000.json','["半雨半晴模样，乍寒乍热天时。", "榴花香逐湿风飞。", "绿云翻翠浪，水急转前溪。", "谁识清凉意思，珊瑚枕冷先知。", "秋光预若借些儿。", "剩催金粟闹，素魄好扬辉。"]'),
('song-ci-577','鹧鸪天','刘过','宋','宋词','song-ci','鹧鸪天','[]','楼外云山千万重。',64,'宋词/ci.song.12000.json','["楼外云山千万重。", "画眉人隔小帘栊。", "风垂舞柳春犹浅，雪点酥胸暖未融。", "携手处，又相逢。", "夜阑心事与郎同。", "一杯自劝羔儿酒，十幅销金暖帐笼。"]'),
('song-ci-578','清平乐','刘过','宋','宋词','song-ci','清平乐','[]','忔憎憎地。',54,'宋词/ci.song.12000.json','["忔憎憎地。", "一捻儿年纪。", "待道瘦来肥不是。", "宜著淡黄衫子。", "唇边一点樱多。", "见人频敛双蛾。", "我自金陵怀古，唱时休唱西河。"]'),
('song-ci-579','西江月','刘过','宋','宋词','song-ci','西江月','[]','堂上谋臣尊俎，边头将士干戈。',58,'宋词/ci.song.12000.json','["堂上谋臣尊俎，边头将士干戈。", "天时地利与人和。", "燕可伐欤曰可。", "今日楼台鼎鼐，明年带砺山河。", "大家齐唱大风歌。", "不日四方来贺。"]'),
('song-ci-580','临江仙','刘过','宋','宋词','song-ci','临江仙','[]','行道桥南无酒卖，老天犹困英雄。',15,'宋词/ci.song.12000.json','["行道桥南无酒卖，老天犹困英雄。"]'),
('song-ci-581','糖多令・唐多令','刘过','宋','宋词','song-ci','糖多令・唐多令','[]','解缆蓼花湾。',74,'宋词/ci.song.12000.json','["解缆蓼花湾。", "好风吹去帆。", "二十年、重过新滩。", "洛浦凌波人去后，空梦绕、翠屏间。", "飞雾湿征衫。", "苍苍烟树寒。", "望星河、低处长安。", "绮陌红楼应笑我，为梅事、过江南。"]'),
('song-ci-582','贺新郎','刘过','宋','宋词','song-ci','贺新郎','[]','水浴芙蓉净。',142,'宋词/ci.song.12000.json','["水浴芙蓉净。", "护浓香、迟开半敛，靓妆临镜。", "长忆耶溪薰风里，年少红颜照映。", "夜露冷、酒随香醒。", "回首当时同舟侣，为相思、怕折琼瑶柄。", "千万缕，意难罄。", "玻璃三万六千顷。", "洗精神、尘埃尽绝，敻然端整。", "浪蕊年来都慵问，爱此浓情淡性。", "待移种、灵根玉井。", "太一真人今何在，取高花、十丈供烟艇。", "来伴我，泛清影。"]'),
('song-ci-583','清平乐','刘过','宋','宋词','song-ci','清平乐','[]','新来塞北。',54,'宋词/ci.song.12000.json','["新来塞北。", "传到真消息。", "赤地居民无一粒。", "更五单于争立。", "维师尚父鹰扬。", "熊罴百万堂堂。", "看取黄金假钺，归来异姓真王。"]'),
('song-ci-584','西吴曲','刘过','宋','宋词','song-ci','西吴曲','[]','说襄阳、旧事重省。',129,'宋词/ci.song.12000.json','["说襄阳、旧事重省。", "记铜驼巷陌、醉还醒。", "笑莺花别后，刘郎憔悴萍梗。", "倦客天涯，还买个、西风轻艇。", "便欲访、骑马山翁，问岘首、那时风景。", "楚王城里，知几度经过，摩挲故宫柳瘿。", "漫吊景。", "冷烟衰草凄迷，伤心兴废，赖有阳春古郢。", "乾坤谁望，陆百里路中原，空老尽英雄，肠断剑锋冷。"]'),
('song-ci-585','好事近','蔡幼学','宋','宋词','song-ci','好事近','[]','日日惜春残，春去更无明日。',53,'宋词/ci.song.12000.json','["日日惜春残，春去更无明日。", "拟把醉同春住，又醒来岑寂。", "明年不怕不逢春，娇春怕无力。", "待向灯前休睡，与留连今夕。"]'),
('song-ci-586','西江月','卢炳','宋','宋词','song-ci','西江月','[]','残雪犹馀远岭。',58,'宋词/ci.song.12000.json','["残雪犹馀远岭。", "晚烟半隐寒林。", "溶溶春涨绿波深。", "时有渔人钓艇。", "倚岸野梅坠粉。", "蘸溪宫柳摇金。", "凭栏凝伫酒初醒。", "料得谁知此景。"]'),
('song-ci-587','念奴娇','卢炳','宋','宋词','song-ci','念奴娇','[]','晚天清楚，扫太虚纤翳，凉生江曲。',120,'宋词/ci.song.12000.json','["晚天清楚，扫太虚纤翳，凉生江曲。", "四顾青冥天地阔，惟有残霞孤骛。", "山气凝蓝，汀烟引素，竦竦浮群木。", "白苹风定，波澄万顷寒玉。", "时有一叶渔舟，收纶垂钓，来往何幽独。", "短发萧萧襟袖冷，便觉都无袢褥。", "曳杖归来，夜深人悄，月照鳞鳞屋。", "藤床一枕，迥然清梦无俗。"]'),
('song-ci-588','鹊桥仙','卢炳','宋','宋词','song-ci','鹊桥仙','[]','馀霞散绮，明河翻雪。',68,'宋词/ci.song.12000.json','["馀霞散绮，明河翻雪。", "隐隐鹊桥初结。", "牛郎织女两逢迎，□胜却、人间欢悦。", "一宵相会，经年离别。", "此语真成浪说。", "细思怎得似嫦娥，解独宿、广寒宫阙。"]'),
('song-ci-589','柳梢青','卢炳','宋','宋词','song-ci','柳梢青','[]','兰蕙心情，海棠韵度，杨柳腰肢。',61,'宋词/ci.song.12000.json','["兰蕙心情，海棠韵度，杨柳腰肢。", "步稳金莲，手纤春笋，肤似凝脂。", "歌生舞态都宜。", "拚著个、坚心共伊。", "无奈相思，带围宽尽，说与教知。"]'),
('song-ci-590','柳梢青','卢炳','宋','宋词','song-ci','柳梢青','[]','雅淡精神，铅黄未洗，犹带残妆。',61,'宋词/ci.song.12000.json','["雅淡精神，铅黄未洗，犹带残妆。", "春艳一枝，鹅儿颜色，染就纤裳。", "月移影转南窗。", "特地送、些儿暗香。", "宿酒初醒，这般滋味，梦断池塘。"]'),
('song-ci-591','谒金门','卢炳','宋','宋词','song-ci','谒金门','[]','春寂寂。',53,'宋词/ci.song.12000.json','["春寂寂。", "节物又催寒食。", "楼上卷帘双燕入。", "断魂愁似织。", "门外雨馀风急。", "满地落英红湿。", "好梦惊回无处觅。", "天涯芳草碧。"]'),
('song-ci-592','谒金门','卢炳','宋','宋词','song-ci','谒金门','[]','春事寂。',53,'宋词/ci.song.12000.json','["春事寂。", "苦笋鲥鱼初食。", "风卷绣帘飞絮入。", "柳丝萦似织。", "迅速韶光去急。", "过雨绿阴尤湿。", "回首旧游何处觅。", "远山空伫碧。"]'),
('song-ci-593','谒金门','卢炳','宋','宋词','song-ci','谒金门','[]','门巷寂。',53,'宋词/ci.song.12000.json','["门巷寂。", "梅豆微酸怯食。", "别恨萦心愁易入。", "寸肠如网织。", "去橹咿哑声急。", "泪滴春衫轻湿。", "尺素待凭鱼雁觅。", "远烟凝处碧。"]'),
('song-ci-594','浣溪沙','卢炳','宋','宋词','song-ci','浣溪沙','[]','水阁无尘午昼长。',48,'宋词/ci.song.12000.json','["水阁无尘午昼长。", "薰风十里藕花香。", "一番疏雨酿微凉。", "旋点新茶消睡思，不将醽醁恼诗肠。", "阑干倚遍挹湖光。"]'),
('song-ci-595','贺新郎','卢炳','宋','宋词','song-ci','贺新郎','[]','绿遍芳郊木。',140,'宋词/ci.song.12000.json','["绿遍芳郊木。", "早红褪香乾，堪叹韶华瞬目。", "薄幸东皇缘底事，得恁匆匆去速。", "正永日、初长晴淑。", "尤忆夜来成梦处，记分明、浑似瑶台宿。", "人语静，燕双逐。", "纱窗一炷沈烟馥。", "拚淋浪剧饮，高枕春酲草屋。", "无计留春添怅望，空写新词叠幅。", "算负却、照妆画烛。", "欲说萦心些个事，恐教人、蹙损眉峰绿。", "慵倚遍，画阑曲。"]'),
('song-ci-596','菩萨蛮','卢炳','宋','宋词','song-ci','菩萨蛮','[]','梦回小枕敧寒玉。',52,'宋词/ci.song.12000.json','["梦回小枕敧寒玉。", "博山香暖沈烟续。", "帷薄怯轻纱。", "风牵幌带斜。", "夜窗云影细。", "月送花阴至。", "身世在陶唐。", "闲愁不挂肠。"]'),
('song-ci-597','好事近','卢炳','宋','宋词','song-ci','好事近','[]','庭院欲昏黄，秋思恼人情乱。',53,'宋词/ci.song.12000.json','["庭院欲昏黄，秋思恼人情乱。", "宝瑟试弹新曲，更与谁同伴。", "阳台魂梦杳无踪，奴住巫山畔。", "不似楚襄云雨，俏输他一半。"]'),
('song-ci-598','减字木兰花','卢炳','宋','宋词','song-ci','减字木兰花','[]','传消寄息。',52,'宋词/ci.song.12000.json','["传消寄息。", "咫尺远如千里隔。", "欲见无由。", "惹起新愁与旧愁。", "情怀如醉。", "敧枕连宵终不寐。", "无奈相思。", "此恨凭谁说与伊。"]'),
('song-ci-599','画堂春','卢炳','宋','宋词','song-ci','画堂春','[]','轻红桃杏斗娇妍。',55,'宋词/ci.song.12000.json','["轻红桃杏斗娇妍。", "晓来葱蒨祥烟。", "霓旌绛节下云天。", "行地神仙。", "盛事频封锦诰，歌声齐劝金莲。", "教从沧海变桑田。", "富贵长年。"]'),
('song-ci-600','临江仙','卢炳','宋','宋词','song-ci','临江仙','[]','弱水蓬莱真胜地，祥烟闪烁霓旌。',70,'宋词/ci.song.12000.json','["弱水蓬莱真胜地，祥烟闪烁霓旌。", "瑶池欢会下云軿。", "康宁新喜事，淑善旧家声。", "戏采捧觞真乐事，蟠桃献寿千春。", "从今更愿子孙荣。", "加恩封锦诰，学道诵黄庭。"]'),
('song-ci-601','踏莎行','卢炳','宋','宋词','song-ci','踏莎行','[]','秋色人家，夕阳洲渚。',68,'宋词/ci.song.12000.json','["秋色人家，夕阳洲渚。", "西风催过黄华渡。", "江烟引素忽飞来，水禽破暝双双去。", "奔走红尘，栖迟羁旅。", "断肠犹忆江南句。", "白云低处雁回峰，明朝便踏潇湘路。"]'),
('song-ci-602','杏花天','卢炳','宋','宋词','song-ci','杏花天','[]','镂冰翦玉工夫费。',69,'宋词/ci.song.12000.json','["镂冰翦玉工夫费。", "做六出、飞花乱坠，舞风情态谁相似。", "算只有、江梅可比。", "极目处、璚瑶万里。", "海天阔、清寒似水。", "从教高卷珠帘起。", "看三白、年丰瑞气。"]'),
('song-ci-603','水调歌头','卢炳','宋','宋词','song-ci','水调歌头','[]','华亭新伟观，胜地得高雄。',114,'宋词/ci.song.12000.json','["华亭新伟观，胜地得高雄。", "凭栏徙倚要眇，万里景无穷。", "好是江流萦绕，那更云天舒阔，叠嶂倚晴空。", "眼界无尽藏，怀抱有清风。", "主人贤，开绮席，泛金锺。", "放怀一笑，许我满酌醉颜红。", "祗恐玺书即下，促起飞凫东去，行作黑头公。", "还记今朝客，曾待一杯同。"]'),
('song-ci-604','鹧鸪天','卢炳','宋','宋词','song-ci','鹧鸪天','[]','初过清明春昼长。',64,'宋词/ci.song.12000.json','["初过清明春昼长。", "紫红香雾蔼华堂。", "朱颜阿母逢生旦，采戏儿孙捧寿觞。", "齐祝颂，喜平康。", "天教两鬓正苍苍。", "壶中日月应长久，笑看蟠桃几度芳。"]'),
('song-ci-605','菩萨蛮','卢炳','宋','宋词','song-ci','菩萨蛮','[]','石榴裙束纤腰袅。',52,'宋词/ci.song.12000.json','["石榴裙束纤腰袅。", "金莲稳衬弓靴小。", "娇呆□羞人。", "伞低遮半身。", "恩情如纸薄。", "方信当初错。", "邂逅苦匆匆。", "还疑是梦中。"]'),
('song-ci-606','踏莎行','卢炳','宋','宋词','song-ci','踏莎行','[]','雅淡容仪，温柔情性。',68,'宋词/ci.song.12000.json','["雅淡容仪，温柔情性。", "偏伊赋得多风韵。", "明眸剪水玉为肌，凤鞋弓小金莲衬。", "相见虽频，欢娱无定。", "蛮笺写了凭谁问。", "坚心好事有成时，须教人道都相称。"]'),
('song-ci-607','贺新郎','卢炳','宋','宋词','song-ci','贺新郎','[]','池管闲凝目。',139,'宋词/ci.song.12000.json','["池管闲凝目。", "有玉人、向晚妖娆，洗妆梳束。", "雅淡容仪妃子样，羞使胭脂点触。", "莹冰雪、精神难掬。", "好是月明微露下，似晚凉、初向清泉浴。", "好对我，笑羞缩。", "好风拂面浑无俗。", "更撩人清兴，异香芬馥。", "惹起新愁无著处，细与端相未足。", "俏不忍、游蝶飞扑。", "可惜伊家娇媚态，问天公、底事教幽独。", "待拉向，锦屏曲。"]'),
('song-ci-608','水调歌头','卢炳','宋','宋词','song-ci','水调歌头','[]','风驭过姑射，云珮挹浮丘。',114,'宋词/ci.song.12000.json','["风驭过姑射，云珮挹浮丘。", "丁宁月姊，为我澄霁一天秋。", "尽展冰奁玉鉴，要看瑶台银阙，万里冷浮光。", "分与世间景，好在水边楼。", "想霓裳，呈妙舞，起清讴。", "蓝桥何处，试寻玉杵恣追游。", "拟待铅霜捣就，缓引琼浆沈醉，谁信是良筹。", "长啸跨鲸背，不必愿封留。"]'),
('song-ci-609','武陵春','卢炳','宋','宋词','song-ci','武陵春','[]','红荻黄芦秋已老，妆点楚江头。',56,'宋词/ci.song.12000.json','["红荻黄芦秋已老，妆点楚江头。", "更有吴姬拨小桡。", "来往自妖娆。", "款款舣舟临别岸，短缆系花梢。", "料得前身是莫愁。", "依旧有风流。"]'),
('song-ci-610','朝中措','卢炳','宋','宋词','song-ci','朝中措','[]','晓来天气十分凉。',56,'宋词/ci.song.12000.json','["晓来天气十分凉。", "时候近重阳。", "村落人家潇洒，篱菊有芬芳。", "年来渐觉，诗肠愈窄，酒量偏狂。", "好景不须放过，何妨一醉千觞。"]'),
('song-ci-611','小重山','卢炳','宋','宋词','song-ci','小重山','[]','一见情怀便雅投。',70,'宋词/ci.song.12000.json','["一见情怀便雅投。", "尊前成密约，意绸缪。", "已成行计理归舟。", "空相忆，无计为伊留。", "执别话离愁。", "萦萦滋味恶，在心头。", "而今无奈阻欢游。", "些子事，此恨两幽幽。"]'),
('song-ci-612','玉团儿','卢炳','宋','宋词','song-ci','玉团儿','[]','绿云慢绾新梳束。',64,'宋词/ci.song.12000.json','["绿云慢绾新梳束。", "这标致、诸馀不俗。", "邂逅相逢，情怀雅合，全似深熟。", "耳边笑语论心曲。", "把不定、红生脸肉。", "若得同欢，共伊携老，心事忒足。"]'),
('song-ci-613','醉蓬莱','卢炳','宋','宋词','song-ci','醉蓬莱','[]','正春回紫陌，瑞霭飞浮，暖风轻扇。',120,'宋词/ci.song.12000.json','["正春回紫陌，瑞霭飞浮，暖风轻扇。", "皓月初圆，觉严城寒浅。", "采结鳌山，纱笼银烛，与□花争艳。", "午夜融和，红莲万顷，一齐开遍。", "讼简民熙，史君行乐，簇拥朱轮，旌旗辉暖。", "鼎沸笙歌，遏行云不散。", "咫尺泥封，促朝天陛，侍玉皇香案。", "来岁元宵，龙灯影里，金杯宜劝。"]'),
('song-ci-614','一剪梅・一翦梅','卢炳','宋','宋词','song-ci','一剪梅・一翦梅','[]','灯火楼台万斛莲。',72,'宋词/ci.song.12000.json','["灯火楼台万斛莲。", "千门喜笑，素月婵娟。", "几多急莞与繁弦。", "巷陌骈阗。", "毕献芳筵。", "乐与民偕五马贤。", "绮罗丛里，一簇神仙。", "传柑雅宴约明年。", "尽夕留连。", "满泛金船。"]'),
('song-ci-615','满江红','卢炳','宋','宋词','song-ci','满江红','[]','碧眼真仙，算元住、蓬莱宫里。',115,'宋词/ci.song.12000.json','["碧眼真仙，算元住、蓬莱宫里。", "记当日、等闲跨鹤，人间游戏。", "要把忠勋扶帝业，更将姓字联宗系。", "拥朱轮、特地为民来，诗书帅。", "千里地，都和气。", "十万户，生欢喜。", "祝黄堂眉寿，歌谣鼎沸。", "莫惜春醅供燕豆，便承芝检朝天陛。", "看云屏、隔坐并貂蝉，双清贵。"]'),
('song-ci-616','水调歌头','卢炳','宋','宋词','song-ci','水调歌头','["\u592a\u6e56"]','再拜识英度，喜气觉飞浮。',114,'宋词/ci.song.12000.json','["再拜识英度，喜气觉飞浮。", "神清骨秀，元是蓬莱谪仙流。", "盍去冲摩霄汉，刚向平分风月，半刺岭南州。", "素蕴未施展，阔步尚淹留。", "从此去，朝帝阙，侍宸旒。", "论思献替，要须直与古人侔。", "好是羽仪朝著，勒就鼎彝勋业，却伴赤松游。", "曳杖太湖曲，笑傲八千秋。"]'),
('song-ci-617','清平乐','卢炳','宋','宋词','song-ci','清平乐','[]','玻璃翦叶。',54,'宋词/ci.song.12000.json','["玻璃翦叶。", "点缀黄金屑。", "雅淡幽姿风味别。", "翠影婆娑弄月。", "秋光占断江南。", "清香鼻观先参。", "一朵折来和露，乌云髻畔斜簪。"]'),
('song-ci-618','念奴娇','卢炳','宋','宋词','song-ci','念奴娇','[]','凿开方沼，问何人种玉、工夫奇绝。',120,'宋词/ci.song.12000.json','["凿开方沼，问何人种玉、工夫奇绝。", "幻出瀛州有□□，十万水仙罗列。", "风曳璚琚，露零珠珮，天上人装结。", "君看炎夏，堕来何处冰雪。", "我来对此凉生，红尘飞尽，却笑凌波袜。", "最爱幽姿能雅淡，自蓄芳馨孤洁。", "挹取天浆，唤将空籁，齐作清歌发。", "不知尘世，晃然身在瑶阙。"]'),
('song-ci-619','念奴娇','卢炳','宋','宋词','song-ci','念奴娇','[]','碧池如染，把玻璃甃就，纤埃都绝。',120,'宋词/ci.song.12000.json','["碧池如染，把玻璃甃就，纤埃都绝。", "西国夫人空里坠，圆盖亭亭排列。", "莹质无暇，尘心不染，远社堪重结。", "当时盛事，虎溪茗碗翻雪。", "千载此意谁论，人争买笑，醉眼看罗袜。", "坐上如今皆我辈，素蕴从来蠲洁。", "击节临风，停杯对月。", "浩气俱英发。", "两翁仙举，玉堂正在金阙。"]'),
('song-ci-620','念奴娇','卢炳','宋','宋词','song-ci','念奴娇','[]','好风明月，共芙蕖、占作人间三绝。',120,'宋词/ci.song.12000.json','["好风明月，共芙蕖、占作人间三绝。", "试问千花还□□，敢与英姿同列。", "一曲千锺，凌云长啸，舒放愁肠结。", "人生易老，莫教双鬓添雪。", "回首蝇利蜗名，微官多误，自笑尘生袜。", "争似玉人真妩媚，表里冰壶明洁。", "露下寒生，参横斗转，又听胡笳发。", "夜阑人静，一声清透云阙。"]'),
('song-ci-621','瑞鹧鸪','卢炳','宋','宋词','song-ci','瑞鹧鸪','[]','客里惊嗟又岁除。',64,'宋词/ci.song.12000.json','["客里惊嗟又岁除。", "萧萧寒雨滴茅庐。", "山深溪转泉声碎，夜永风摇烛影孤。", "冷甚只多烧木叶，诗成无处写桃符。", "强酬节物聊清酌，今岁屠苏自取疏。"]'),
('song-ci-622','武陵春','卢炳','宋','宋词','song-ci','武陵春','[]','常忆江南春欲到，消息付南枝。',56,'宋词/ci.song.12000.json','["常忆江南春欲到，消息付南枝。", "疏影横斜照水时。", "月淡暗香迟。", "可惜江头千树玉，雨暗更风欺。", "传语东君管领伊。", "憔悴有谁知。"]'),
('song-ci-623','鹧鸪天','卢炳','宋','宋词','song-ci','鹧鸪天','[]','秋月明眸两鬓浓。',64,'宋词/ci.song.12000.json','["秋月明眸两鬓浓。", "衫儿贴体绉轻红。", "清声宛转歌金缕，纤手殷勤捧玉锺。", "娇娅姹，语惺松。", "酒香沸沸透羞容。", "刘郎莫恨相逢晚，且喜桃源路已通。"]'),
('song-ci-624','蓦山溪','卢炳','宋','宋词','song-ci','蓦山溪','["\u897f\u6e56"]','淡妆西子，怎比西湖好。',102,'宋词/ci.song.12000.json','["淡妆西子，怎比西湖好。", "南北两长堤，有罨画、楼台多少。", "翠光千顷，一片净琉璃，泛兰舟，摇画桨，尽日金尊倒。", "名园精舍，总被游人到。", "年少与佳人，共携手、嬉游歌笑。", "夕阳西下，沈醉尽归来，鞭宝马，闹竿随，簇著花藤轿。"]'),
('song-ci-625','蓦山溪','卢炳','宋','宋词','song-ci','蓦山溪','[]','韶华七换，阻庆生申旦。',102,'宋词/ci.song.12000.json','["韶华七换，阻庆生申旦。", "今日向高堂，载卮酒、为君满劝。", "绣帘低挂，瑞霭□香浓，倩双娥，敲象板，缓缓歌珠贯。", "芝兰挺秀，俱是皇家彦。", "只这一般奇，见方寸、平生积善。", "几多厚德，天锡与遐龄，鬓长青，颜不老，日日开华宴。"]'),
('song-ci-626','减字木兰花','卢炳','宋','宋词','song-ci','减字木兰花','[]','莎衫筠笠。',52,'宋词/ci.song.12000.json','["莎衫筠笠。", "正是村村农务急。", "绿水千畦。", "惭愧秧针出得齐。", "风斜雨细。", "麦欲黄时寒又至。", "饁妇耕夫。", "画作今年稔岁图。"]'),
('song-ci-627','满江红','卢炳','宋','宋词','song-ci','满江红','[]','积雨连朝，添新涨、一篙春碧。',115,'宋词/ci.song.12000.json','["积雨连朝，添新涨、一篙春碧。", "寒犹在、东风料峭，柳丝无力。", "系惹画船都不住，从教兰棹双飞急。", "泛大江、东去欲何之，瓜期迫。", "龙锺裔，神仙伯。", "金闺彦，文章客。", "算河阳花县，恁生留得。", "制锦才高书善最，鸣琴化洽人欢怿。", "想未容、坐暖诏归来，君王侧。"]'),
('song-ci-628','踏莎行','卢炳','宋','宋词','song-ci','踏莎行','[]','猎猎霜风，濛濛晓雾。',68,'宋词/ci.song.12000.json','["猎猎霜风，濛濛晓雾。", "归来喜踏江南路。", "千林翠幄半红黄，试看青女工夫做。", "茅舍疏篱，竹边低户。", "谁家酒滴真珠露。", "旋酤一盏破清寒，趁晴同过黄花渡。"]'),
('song-ci-629','蝶恋花','卢炳','宋','宋词','song-ci','蝶恋花','[]','满架冰蕤开遍了。',70,'宋词/ci.song.12000.json','["满架冰蕤开遍了。", "试问花神，留得春多少。", "清胜荀香娇韵好。", "谢庭风月应难到。", "酒酿新醅名不老。", "醉倒花前，真个无烦恼。", "满座清欢供一笑。", "春酲拼却明窗晓。"]'),
('song-ci-630','点绛唇','卢炳','宋','宋词','song-ci','点绛唇','[]','过眼溪山，向来都是经行处。',50,'宋词/ci.song.12000.json','["过眼溪山，向来都是经行处。", "骖鸾人去。", "冷落吹箫侣。", "小立江亭，愁对蒹葭浦。", "无情绪。", "酒杯慵举。", "闲看江枫舞。"]'),
('song-ci-631','诉衷情','卢炳','宋','宋词','song-ci','诉衷情','[]','无端风雨送清秋。',54,'宋词/ci.song.12000.json','["无端风雨送清秋。", "天气冷飕飕。", "行人先自离索，直是不禁愁。", "思往事，忆前游。", "泪难收。", "重阳近也，黄花依旧，谁伴清瓯。"]'),
('song-ci-632','念奴娇','卢炳','宋','宋词','song-ci','念奴娇','[]','快风收雨，正江城初霁，物华如许。',120,'宋词/ci.song.12000.json','["快风收雨，正江城初霁，物华如许。", "丽日融和春思好，是处莺啼燕语。", "嫩绿成阴，落红堆绣，只恐春将暮。", "园林清昼，看看又见飞絮。", "太守无限风流，铃斋多暇，载酒郊原路。", "几队旌旗光闪烁，鼓吹更翻新谱。", "曲水流觞，兰亭修禊，俯仰成今古。", "为君一醉，归时楼上初鼓。"]'),
('song-ci-633','冉冉云','卢炳','宋','宋词','song-ci','冉冉云','[]','雨洗千红又春晚。',72,'宋词/ci.song.12000.json','["雨洗千红又春晚。", "留牡丹、倚阑初绽。", "娇娅姹、偏赋精神君看。", "算费尽、工夫点染。", "带露天香最清远。", "太真妃、院妆体段。", "拼对花、满把流霞频劝。", "怕逐东风零乱。"]'),
('song-ci-634','减字木兰花','卢炳','宋','宋词','song-ci','减字木兰花','[]','冰姿雪艳。',52,'宋词/ci.song.12000.json','["冰姿雪艳。", "天赋精神偏冷淡。", "惟有清香。", "何逊扬州暗断肠。", "孤芳好处。", "消得骚人题妙句。", "皴皵寒枝。", "未必生绡画得宜。"]'),
('song-ci-635','鹧鸪天','卢炳','宋','宋词','song-ci','鹧鸪天','[]','阁雨浮云寒尚轻。',64,'宋词/ci.song.12000.json','["阁雨浮云寒尚轻。", "商量雪意未全成。", "莫嫌竹外萧然处，忽有幽香透鼻清。", "诗兴逸，酒魂醒。", "主人留客更多情。", "不辞满引成痴客，且把梅花醉一觥。"]'),
('song-ci-636','水龙吟','卢炳','宋','宋词','song-ci','水龙吟','[]','晚晴一碧天如水，风约尘埃都扫。',126,'宋词/ci.song.12000.json','["晚晴一碧天如水，风约尘埃都扫。", "素娥睡起，玉轮稳驾，初离海表。", "碾破秋云，涌成银阙，光欺南斗。", "想广寒宫里，风流女伴，应都把、仙歌奏。", "夜永风生悄悄。", "耀冰雪、寒侵重峤。", "今宵休道，从来此夕，阴多晴少。", "坐久更深，露冷襟袖，不禁清晓。", "更天风吹下，桂香拂袂，想蟠根老。"]'),
('song-ci-637','柳梢青','卢炳','宋','宋词','song-ci','柳梢青','[]','笑菊欺梅。',61,'宋词/ci.song.12000.json','["笑菊欺梅。", "嫌蜂却蝶，压尽寒荄。", "月下精神，醉时风韵，红透香腮。", "天工造化难猜。", "甚怪我、愁眉未开。", "故遣名花，凌霜带露，先送春来。"]'),
('song-ci-638','少年游','卢炳','宋','宋词','song-ci','少年游','[]','绣罗褑子间金丝。',60,'宋词/ci.song.12000.json','["绣罗褑子间金丝。", "打扮好容仪。", "晓雪明肌，秋波入鬓，鞋小步行迟。", "冠儿时样都相称，花插楝双枝。", "倩俏精神，风流情态，惟有粉郎知。"]'),
('song-ci-639','汉宫春','卢炳','宋','宋词','song-ci','汉宫春','[]','向暖南枝，最是他潇洒，先带春回。',119,'宋词/ci.song.12000.json','["向暖南枝，最是他潇洒，先带春回。", "因何事、向岁晚，搀占花魁。", "天公著意，安排巧、特地教开。", "知道是，仙翁诞节，琼英要泛金杯。", "人学寿阳妆面，正梁州初按，羯鼓声催。", "年年此花开后，宴启蓬莱。", "朱颜不老，算难教、绿野徘徊。", "消息好，行看父子，和羹鼎鼐盐梅。"]'),
('song-ci-640','多丽','卢炳','宋','宋词','song-ci','多丽','[]','庆佳辰。',173,'宋词/ci.song.12000.json','["庆佳辰。", "熊罴协梦生申。", "记当年、曾游月殿，笑谈高跃龙津。", "德弥高、源流孔孟，才迥出、黼黻卿云。", "亟步华涂，蜚英腾茂，姓名端的简枫宸。", "最好是、雍容兰省，直道事吾君。", "还知否，承明倦直，来抚斯民。", "算人生、五马最贵，朱旛画戟行春。", "讼庭清、祥风和畅，铃斋静、佳气氤氲。", "寿宴香浓，梅繁柳嫩，年年今日劝芳尊。", "须信道、朱颜不老，眉寿等松椿。", "从兹去，衮衣特立，廊庙经纶。"]'),
('song-ci-641','满江红','卢炳','宋','宋词','song-ci','满江红','[]','媚景良时，无非是、三春富贵。',115,'宋词/ci.song.12000.json','["媚景良时，无非是、三春富贵。", "花共柳、著工夫染，嫩红轻翠。", "日丽风和薰协气。", "莺吟燕舞皆欢意。", "况生辰、恰恰值清明，笙歌沸。", "分天派，真龙裔。", "到月殿，攀仙桂。", "看眉间黄色，诏书将至。", "莫向蓝田分佐理。", "便趋紫禁参朝对。", "问玉皇、仙籍注长生，三千岁。"]'),
('song-ci-642','蝶恋花','卢炳','宋','宋词','song-ci','蝶恋花','[]','罗幕护寒遮晓雾。',70,'宋词/ci.song.12000.json','["罗幕护寒遮晓雾。", "爱日烘晴，又是年华暮。", "潇洒江梅争欲吐。", "暗香漏泄春来处。", "何日寻芳溪畔路。", "挈榼携筇，写景论心素。", "千里相逢真会遇。", "羡君解道江南句。"]'),
('song-ci-643','水调歌头','卢炳','宋','宋词','song-ci','水调歌头','[]','富贵本何物，底用苦趋奔。',114,'宋词/ci.song.12000.json','["富贵本何物，底用苦趋奔。", "都为造物娱弄，人事覆来翻。", "须索高抬目力，觑破祗同儿戏，不必更重论。", "但愿吾长健，赢得日加飨。", "衣轻裘，乘驷马，驾高轩。", "算来荣耀，终输渔叟钓江村。", "休叹谋身太拙，未必折腰便是，炙手几曾温。", "清议不可辱，千古要长存。"]'),
('song-ci-644','满江红','卢炳','宋','宋词','song-ci','满江红','[]','罨画池亭，对十万、盈盈粉面。',115,'宋词/ci.song.12000.json','["罨画池亭，对十万、盈盈粉面。", "依翠盖、临风一曲，霓裳舞遍。", "亭上人如蓬岛客，坐中别有飞琼伴。", "占世间、风月最清凉，宜开宴。", "当盛旦，歌喉啭。", "齐祝寿，金尊劝。", "算才华合侍，玉皇香案。", "处事从来坚特操，立朝更要持公论。", "使他时、台阁振风声，朝天眷。"]'),
('song-ci-645','诉衷情','卢炳','宋','宋词','song-ci','诉衷情','[]','柴扉人寂草生畦。',54,'宋词/ci.song.12000.json','["柴扉人寂草生畦。", "藤蔓乱萦篱。", "秋净楚天如水，云叶度墙低。", "同把盏，且伸眉。", "对残晖。", "红茱笑拈，黄菊斜簪，恋饮忘归。"]'),
('song-ci-646','浣溪沙','卢炳','宋','宋词','song-ci','浣溪沙','[]','常记京华昔浪游。',48,'宋词/ci.song.12000.json','["常记京华昔浪游。", "青罗买笑万金酬。", "醉中曾此当貂裘。", "自恨山翁今老矣，惜花心性谩风流。", "清樽独酌更何愁。"]'),
('song-ci-647','清平乐','卢炳','宋','宋词','song-ci','清平乐','[]','方池小小。',54,'宋词/ci.song.12000.json','["方池小小。", "风摺玻璃皱。", "数朵荷花开更好。", "把住薰风一笑。", "芳容淡注胭脂。", "亭亭翠叶相依。", "只欠一双鸂鶒，便如画底屏帷。"]'),
('song-ci-648','菩萨蛮','卢炳','宋','宋词','song-ci','菩萨蛮','[]','而今怕听相思曲。',52,'宋词/ci.song.12000.json','["而今怕听相思曲。", "多情蹙损眉峰绿。", "惜别上扁舟。", "望穷江际楼。", "蛮笺封了发。", "为忆人如雪。", "离恨写教看。", "休令盟约寒。"]'),
('song-ci-649','小重山令・小重山','姜夔','宋','宋词','song-ci','小重山令・小重山','[]','人绕湘皋月坠时。',70,'宋词/ci.song.12000.json','["人绕湘皋月坠时。", "斜横花树小，浸愁漪。", "一春幽事有谁知。", "东风冷、香远茜裙归。", "鸥去昔游非。", "遥怜花可可，梦依依。", "九疑云杳断魂啼。", "相思血，都沁绿筠枝。"]'),
('song-ci-650','江梅引・江城梅花引','姜夔','宋','宋词','song-ci','江梅引・江城梅花引','[]','人间离别易多时。',108,'宋词/ci.song.12000.json','["人间离别易多时。", "见梅枝。", "忽相思。", "几度小窗，幽梦手同携。", "今夜梦中无觅处，漫徘徊。", "寒侵被、尚未知。", "湿红恨墨浅封题。", "宝筝空、无雁飞。", "俊游巷陌，算空有、古木斜晖。", "旧约扁舟，心事已成非。", "歌罢淮南春草赋，又萋萋。", "漂零客、泪满衣。"]'),
('song-ci-651','蓦山溪','姜夔','宋','宋词','song-ci','蓦山溪','[]','与鸥为客。',102,'宋词/ci.song.12000.json','["与鸥为客。", "绿野留吟屐。", "雨行柳垂阴，是当日、仙翁手植。", "一亭寂寞。", "烟外带愁横，荷苒苒，展凉云，横卧虹千尺。", "才因老尽，秀句君休觅。", "万绿正迷人，更愁入、山阳夜笛。", "百年心事，惟有玉阑知，吟未了，放船回，月下空相忆。"]'),
('song-ci-652','莺声绕红楼','姜夔','宋','宋词','song-ci','莺声绕红楼','[]','十亩梅花作雪飞。',60,'宋词/ci.song.12000.json','["十亩梅花作雪飞。", "冷香下、携手多时。", "两年不到断桥西。", "长笛为予吹。", "人妒垂杨绿，春风为、染作仙衣。", "垂杨却又妒腰枝。", "近前舞丝丝。"]'),
('song-ci-653','鬲溪梅令','姜夔','宋','宋词','song-ci','鬲溪梅令','[]','好花不与殢香人。',56,'宋词/ci.song.12000.json','["好花不与殢香人。", "浪粼粼。", "又恐春风归去绿成阴。", "玉钿何处寻。", "木兰双桨梦中云。", "小横陈。", "漫向孤山山下觅盈盈。", "翠禽啼一春。"]'),
('song-ci-654','阮郎归','姜夔','宋','宋词','song-ci','阮郎归','[]','红云低压碧玻璃。',56,'宋词/ci.song.12000.json','["红云低压碧玻璃。", "惺惚花上啼。", "静看楼角拂长枝。", "朝寒吹翠眉。", "休涉笔，且裁诗。", "年年风絮时。", "绣衣夜半草符移。", "月中双桨归。"]'),
('song-ci-655','阮郎归','姜夔','宋','宋词','song-ci','阮郎归','[]','旌阳宫殿昔徘徊。',56,'宋词/ci.song.12000.json','["旌阳宫殿昔徘徊。", "一坛云叶垂。", "与君闲看壁间题。", "夜凉笙鹤期。", "茅店酒，寿君时。", "老枫临路歧。", "年年强健得追随。", "名山游遍归。"]'),
('song-ci-656','好事近','姜夔','宋','宋词','song-ci','好事近','[]','凉夜摘花钿，苒苒动摇云绿。',53,'宋词/ci.song.12000.json','["凉夜摘花钿，苒苒动摇云绿。", "金络一团香露，正纱厨人独。", "朝来碧缕放长穿，钗头挂层玉。", "记得如今时候，正荔枝初熟。"]'),
('song-ci-657','点绛唇','姜夔','宋','宋词','song-ci','点绛唇','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u592a\u6e56"]','燕雁无心，太湖西畔随云去。',50,'宋词/ci.song.12000.json','["燕雁无心，太湖西畔随云去。", "数峰清苦。", "商略黄昏雨。", "第四桥边，拟共天随住。", "今何许。", "凭栏怀古。", "残柳参差舞。"]'),
('song-ci-658','点绛唇','姜夔','宋','宋词','song-ci','点绛唇','[]','金谷人归，绿扬低扫吹笙道。',50,'宋词/ci.song.12000.json','["金谷人归，绿扬低扫吹笙道。", "数声啼鸟。", "也学相思调。", "月落潮生，掇送刘郎老。", "淮南好。", "甚时重到。", "陌上生春草。"]'),
('song-ci-659','虞美人','姜夔','宋','宋词','song-ci','虞美人','[]','西园曾为梅花醉。',66,'宋词/ci.song.12000.json','["西园曾为梅花醉。", "叶翦春云细。", "玉笙凉夜隔帘吹。", "卧看花梢摇动、一枝枝。", "娉娉袅袅教谁惜。", "空压纱巾侧。", "沈香亭北又青苔。", "唯有当时蝴蝶、自飞来。"]'),
('song-ci-660','虞美人','姜夔','宋','宋词','song-ci','虞美人','[]','摩挲紫盖峰头石。',66,'宋词/ci.song.12000.json','["摩挲紫盖峰头石。", "上瞰苍崖立。", "玉盘摇动半崖花。", "花树扶蔬、一半白云遮。", "盈盈相望无由摘。", "惆怅归来屐。", "而今仙迹杳难寻。", "那日青楼、曾见似花人。"]'),
('song-ci-661','忆王孙','姜夔','宋','宋词','song-ci','忆王孙','[]','冷红叶叶下塘秋。',36,'宋词/ci.song.12000.json','["冷红叶叶下塘秋。", "长与行云共一舟。", "零落江南不自由。", "两绸缪。", "料得吟鸾夜夜愁。"]'),
('song-ci-662','少年游','姜夔','宋','宋词','song-ci','少年游','[]','双螺未合，双蛾先敛，家在碧云西。',64,'宋词/ci.song.12000.json','["双螺未合，双蛾先敛，家在碧云西。", "别母情怀，随郎滋味，桃叶渡江时。", "扁舟载了，匆匆归去，今夜泊前溪。", "杨柳津头，梨花墙外，心事两人知。"]'),
('song-ci-663','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','[]','京洛风流绝代人。',64,'宋词/ci.song.12000.json','["京洛风流绝代人。", "因何风絮落溪津。", "笼鞋浅出鸦头袜，知是凌波漂渺身。", "红乍笑，绿长嚬。", "与谁同度可怜春。", "鸳鸯独宿何曾惯，化作西楼一缕云。"]'),
('song-ci-664','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','[]','曾共君侯历聘来。',64,'宋词/ci.song.12000.json','["曾共君侯历聘来。", "去年今日踏莓苔。", "旌扬宅里疏疏磬。", "挂屩枫前草草杯。", "呼煮酒，摘青梅。", "今年官事莫徘徊。", "移家径入蓝田县，急急船头打鼓催。"]'),
('song-ci-665','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','[]','柏绿椒红事事新。',64,'宋词/ci.song.12000.json','["柏绿椒红事事新。", "隔篱灯影贺年人。", "三茅钟动西窗晓，诗鬓无端又一春。", "慵对客，缓开门。", "梅花闲伴老来身。", "娇儿学作人间字，郁垒神荼写未真。"]'),
('song-ci-666','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','[]','巷陌风光纵赏时。',64,'宋词/ci.song.12000.json','["巷陌风光纵赏时。", "笼纱未出马先嘶。", "白头居士无呵殿，只有乘肩小女随。", "花满市，月侵衣。", "少年情事老来悲。", "沙河塘上春寒浅，看了游人缓缓归。"]'),
('song-ci-667','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','[]','忆昨天街预赏时。',64,'宋词/ci.song.12000.json','["忆昨天街预赏时。", "柳悭梅小未教知。", "而今正是欢游夕，却怕春寒自掩扉。", "帘寂寂，月低低。", "旧情惟有绛都词。", "芙蓉影暗三更后，卧听邻娃笑语归。"]'),
('song-ci-668','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','肥水东流无尽期。',64,'宋词/ci.song.12000.json','["肥水东流无尽期。", "当初不合种相思。", "梦中未比丹青见，暗里忽惊山鸟啼。", "春未绿，鬓先丝。", "人间别久不成悲。", "谁教岁岁红莲夜，两处沈吟各自知。"]'),
('song-ci-669','鹧鸪天','姜夔','宋','宋词','song-ci','鹧鸪天','[]','辇路珠帘两行垂。',64,'宋词/ci.song.12000.json','["辇路珠帘两行垂。", "千枝银烛舞僛僛。", "东风历历红楼下，谁识三生杜牧之。", "欢正好，夜何其。", "明朝春过小桃枝。", "鼓声渐远游人散，惆怅归来有月知。"]'),
('song-ci-670','夜行船','姜夔','宋','宋词','song-ci','夜行船','[]','略彴横溪人不度。',70,'宋词/ci.song.12000.json','["略彴横溪人不度。", "听流澌、佩环无数。", "屋角垂枝，船头生影，算唯有、春知处。", "回首江南天欲暮。", "折寒香、倩谁传语。", "玉笛无声，诗人有句，花休道、轻分付。"]'),
('song-ci-671','杏花天','姜夔','宋','宋词','song-ci','杏花天','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绿丝低拂鸳鸯浦。',73,'宋词/ci.song.12000.json','["绿丝低拂鸳鸯浦。", "想桃叶、当时唤渡。", "又将愁眼与春风，待去。", "倚兰桡、更少驻。", "金陵路。", "莺吟燕舞。", "算潮水、知人最苦。", "满汀芳草不成归，日暮。", "更移舟、向甚处。"]'),
('song-ci-672','醉吟商小品・小品','姜夔','宋','宋词','song-ci','醉吟商小品・小品','[]','又正是春归，细柳暗黄千缕。',36,'宋词/ci.song.12000.json','["又正是春归，细柳暗黄千缕。", "暮鸦啼处。", "梦逐金鞍去。", "一点芳心休诉。", "琵琶解语。"]'),
('song-ci-673','玉梅令','姜夔','宋','宋词','song-ci','玉梅令','[]','疏疏雪片。',82,'宋词/ci.song.12000.json','["疏疏雪片。", "散入溪南苑。", "春寒锁、旧家亭馆。", "有玉梅几树，背立怨东风，高花未吐，暗香已远。", "公来领略，梅花能劝。", "花长好、愿公更健。", "便揉春为酒，翦雪作新诗，拚一日、绕花千转。"]'),
('song-ci-674','踏莎行','姜夔','宋','宋词','song-ci','踏莎行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','燕燕轻盈，莺莺娇软。',68,'宋词/ci.song.12000.json','["燕燕轻盈，莺莺娇软。", "分明又向华胥见。", "夜长争得薄情知，春初早被相思染。", "别后书辞，别时针线。", "离魂暗逐郎行远。", "淮南皓月冷千山，冥冥归去无人管。"]'),
('song-ci-675','诉衷情','姜夔','宋','宋词','song-ci','诉衷情','[]','石榴一树浸溪红。',54,'宋词/ci.song.12000.json','["石榴一树浸溪红。", "零落小桥东。", "五日凄凉心事，山雨打船篷。", "谙世味，楚人弓。", "莫忡忡。", "白头行客，不采苹花，孤负薰风。"]'),
('song-ci-676','浣溪沙','姜夔','宋','宋词','song-ci','浣溪沙','[]','著酒行行满袂风。',48,'宋词/ci.song.12000.json','["著酒行行满袂风。", "草枯霜鹘落晴空。", "销魂都在夕阳中。", "恨入四弦人欲老，梦寻千驿意难通。", "当时何似莫匆匆。"]'),
('song-ci-677','浣溪沙','姜夔','宋','宋词','song-ci','浣溪沙','[]','春点疏梅雨后枝。',48,'宋词/ci.song.12000.json','["春点疏梅雨后枝。", "翦灯心事峭寒时。", "市桥携手步迟迟。", "蜜炬来时人更好，玉笙吹彻夜何其。", "东风落靥不成归。"]'),
('song-ci-678','浣溪沙','姜夔','宋','宋词','song-ci','浣溪沙','[]','钗燕笼云晚不忺。',48,'宋词/ci.song.12000.json','["钗燕笼云晚不忺。", "拟将裙带系郎船。", "别离滋味又今年。", "杨柳夜寒犹自舞，鸳鸯风急不成眠。", "些儿闲事莫萦牵。"]'),
('song-ci-679','浣溪沙','姜夔','宋','宋词','song-ci','浣溪沙','[]','雁怯重云不肯啼。',48,'宋词/ci.song.12000.json','["雁怯重云不肯啼。", "画船愁过石塘西。", "打头风浪恶禁持。", "春浦渐生迎棹绿，小梅应长亚门枝。", "一年灯火要人归。"]'),
('song-ci-680','浣溪沙','姜夔','宋','宋词','song-ci','浣溪沙','[]','花里春风未觉时。',48,'宋词/ci.song.12000.json','["花里春风未觉时。", "美人呵蕊缀横枝。", "隔帘飞过蜜蜂儿。", "书寄岭头封不到，影浮杯面误人吹。", "寂寥惟有夜寒知。"]'),
('song-ci-681','浣溪沙','姜夔','宋','宋词','song-ci','浣溪沙','[]','翦翦寒花小更垂。',48,'宋词/ci.song.12000.json','["翦翦寒花小更垂。", "阿琼愁里弄妆迟。", "东风烧烛夜深归。", "落蕊半黏钗上燕，露黄斜映鬓边犀。", "老夫无味已多时。"]'),
('song-ci-682','霓裳中序第一','姜夔','宋','宋词','song-ci','霓裳中序第一','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','亭皋正望极。',125,'宋词/ci.song.12000.json','["亭皋正望极。", "乱落江莲归未得。", "多病却无气力。", "况纨扇渐疏，罗衣初萦。", "流光过隙。", "叹杏梁、双燕如客。", "人何在，一帘淡月，仿佛照颜色。", "幽寂。", "乱蛩吟壁。", "动庾信、清愁似织。", "沈思年少浪迹。", "笛里关山，柳下坊陌。", "坠红无信息。", "漫暗水，涓涓溜碧。", "漂零久，而今何意，醉卧酒垆侧。"]'),
('song-ci-683','庆宫春・高阳台','姜夔','宋','宋词','song-ci','庆宫春・高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','双桨莼波，一蓑松雨，暮愁渐满空阔。',126,'宋词/ci.song.12000.json','["双桨莼波，一蓑松雨，暮愁渐满空阔。", "呼我盟鸥，翩翩欲下，背人还过木末。", "那回归去，荡云雪、孤舟夜发。", "伤心重见，依约眉山，黛痕低压。", "采香径里春寒，老子婆娑，自歌谁答。", "垂虹西望，飘然引去，此兴平生难遏。", "酒醒波远，政凝想、明珰素袜。", "如今安在，唯有阑干，伴人一霎。"]'),
('song-ci-684','齐天乐','姜夔','宋','宋词','song-ci','齐天乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','庾郎先自吟愁赋。',123,'宋词/ci.song.12000.json','["庾郎先自吟愁赋。", "凄凄更闻私语。", "露湿铜铺，苔侵石井，都是曾听伊处。", "哀音似诉。", "正思妇无眠，起寻机杼。", "曲曲屏山，夜凉独自甚情绪。", "西窗又吹暗雨。", "为谁频断续，相和砧杵。", "候馆迎秋，离宫吊月，别有伤心无数。", "豳诗漫与。", "笑篱落呼灯，世间儿女。", "写入琴丝，一声声更苦。"]'),
('song-ci-685','满江红','姜夔','宋','宋词','song-ci','满江红','[]','仙姥来时，正一望、千倾翠澜。',115,'宋词/ci.song.12000.json','["仙姥来时，正一望、千倾翠澜。", "旌旗共、乱云俱下，一依前山。", "命驾群龙金作轭，相从诸娣玉为冠。", "向夜深、风定悄无人，闻佩环。", "神奇处，君试看。", "奠淮右，诅江南。", "遣六丁雷电，别守东关。", "却笑英雄无好手，一篙春水走曹瞒。", "又怎知、人在小红楼，帘影间。"]'),
('song-ci-686','一萼红','姜夔','宋','宋词','song-ci','一萼红','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','古城阴。',133,'宋词/ci.song.12000.json','["古城阴。", "有官梅几许，红萼未宜簪。", "池面冰胶，墙腰雪老，云意还又沈沈。", "翠藤共、闲穿径竹，渐笑语、惊起卧沙禽。", "野老林泉，故王台榭，呼唤登临。", "南去北来何事，荡湘云楚水，目极伤心。", "朱户黏鸡，金盘簇燕，空叹时序侵寻。", "记曾共，西楼雅集，想垂杨、还袅万丝金。", "待得归鞍到时，只怕春深。"]'),
('song-ci-687','念奴娇','姜夔','宋','宋词','song-ci','念奴娇','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','闹红一舸，记来时、尝与鸳鸯为侣。',121,'宋词/ci.song.12000.json','["闹红一舸，记来时、尝与鸳鸯为侣。", "三十六陂人未到，水佩风裳无数。", "翠叶吹凉，玉容销酒，更洒菰蒲雨。", "嫣然摇动，冷香飞上诗句。", "日暮。", "青盖亭亭，情人不见，争忍凌波去。", "只恐舞衣寒易落，愁入西风南浦。", "高柳垂阴，老鱼吹浪，留我花间住。", "田田多少，几回沙际归路。"]'),
('song-ci-688','念奴娇','姜夔','宋','宋词','song-ci','念奴娇','[]','楚山修竹，自娟娟、不受人间袢暑。',120,'宋词/ci.song.12000.json','["楚山修竹，自娟娟、不受人间袢暑。", "我醉欲眠伊伴我，一枕凉生如许。", "象齿为材，花藤为面，终是无真趣。", "梅风吹溽，此君直恁清苦。", "须信下榻殷勤，け然成梦，梦与秋相遇。", "翠袖佳人来共看，漠漠风烟千亩。", "蕉叶窗纱，荷花池馆，别有留人处。", "此时归去，为君听尽秋雨。"]'),
('song-ci-689','眉妩','姜夔','宋','宋词','song-ci','眉妩','[]','看垂杨连苑，杜若侵沙，愁损未归眼。',128,'宋词/ci.song.12000.json','["看垂杨连苑，杜若侵沙，愁损未归眼。", "信马青楼去，重帘下，娉婷人妙飞燕。", "翠尊共款。", "听艳歌、郎意先感。", "便携手、月地云阶里，爱良夜微暖。", "无限。", "风流疏散。", "有暗藏弓履，偷寄香翰。", "明日闻津鼓，湘江上，催人还解春缆。", "乱红万点。", "怅断魂、烟水遥远。", "又争似相携，乘一舸、镇长见。"]'),
('song-ci-690','月下笛','姜夔','宋','宋词','song-ci','月下笛','[]','与客携壶，梅花过了，夜来风雨。',123,'宋词/ci.song.12000.json','["与客携壶，梅花过了，夜来风雨。", "幽禽自语。", "啄香心、度墙去。", "春衣都是柔荑翦，尚沾惹、残茸半缕。", "怅玉钿似扫，朱门深闭，再见无路。", "凝伫。", "曾游处。", "但系马垂杨，认郎鹦鹉。", "扬州梦觉，彩云飞过何许。", "多情须倩梁间燕，问吟袖、弓腰在否。", "怎知道，误了人，年少自恁虚度。"]'),
('song-ci-691','清波引','姜夔','宋','宋词','song-ci','清波引','[]','冷云迷浦。',103,'宋词/ci.song.12000.json','["冷云迷浦。", "倩谁唤、玉妃起舞。", "岁华如许。", "野梅弄眉妩。", "屐齿印苍藓，渐为寻花来去。", "自随秋雁南来，望江国、渺何处。", "新诗漫与。", "好风景、长是暗度。", "故人知否。", "抱幽恨难语。", "何时共渔艇，莫负沧浪烟雨。", "况有清夜啼猿，怨人良苦。"]'),
('song-ci-692','法曲献仙音','姜夔','宋','宋词','song-ci','法曲献仙音','[]','虚阁笼寒，小帘通月，暮色偏怜高处。',113,'宋词/ci.song.12000.json','["虚阁笼寒，小帘通月，暮色偏怜高处。", "树隔离宫，水平驰道，湖山尽入尊俎。", "奈楚客淹留久，砧声带愁去。", "屡回顾。", "过秋风、未成归计。", "谁念我、重见冷枫红舞。", "唤起淡妆人，问逋仙、今在何许。", "象笔鸾笺，甚而今、不道秀句。", "怕平生幽恨，化作沙边烟雨。"]'),
('song-ci-693','琵琶仙・自度曲','姜夔','宋','宋词','song-ci','琵琶仙・自度曲','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','双桨来时，有人似、旧曲桃根桃叶。',124,'宋词/ci.song.12000.json','["双桨来时，有人似、旧曲桃根桃叶。", "歌扇轻约飞花，蛾眉正奇绝。", "春渐远、汀洲自绿，更添了、几声啼鴂。", "十里扬州，三生杜牧，前事休说。", "又还是、宫烛分烟，奈愁里、匆匆换时节。", "都把一襟芳思，与空阶榆荚。", "千万缕、藏鸦细柳，为玉尊、起舞回雪。", "想见西出阳关，故人初别。"]'),
('song-ci-694','玲珑四犯','姜夔','宋','宋词','song-ci','玲珑四犯','[]','叠鼓夜寒，垂灯春浅，匆匆时事如许。',122,'宋词/ci.song.12000.json','["叠鼓夜寒，垂灯春浅，匆匆时事如许。", "倦游欢意少，俯仰悲今古。", "江淹又吟恨赋。", "记当时、送君南浦。", "万里乾坤，百年身世，唯有此情苦。", "扬州柳，垂官路。", "有轻盈换马，端正窥户。", "酒醒明月下，梦逐潮声去。", "文章信美知何用，漫赢得、天涯羁旅。", "教说与。", "春来要、寻花伴侣。"]'),
('song-ci-695','侧犯','姜夔','宋','宋词','song-ci','侧犯','[]','恨春易去。',94,'宋词/ci.song.12000.json','["恨春易去。", "甚春却向扬州住。", "微雨。", "正茧栗梢头弄诗句。", "红桥二十四，总是行云处。", "无语。", "渐半脱宫衣笑相顾。", "金壶细叶，千朵围歌舞。", "谁念我、鬓成丝，来此共尊俎。", "后日西园，绿阴无数。", "寂寞刘郎，自修花谱。"]'),
('song-ci-696','水龙吟','姜夔','宋','宋词','song-ci','水龙吟','[]','夜深客子移舟处，两两沙禽惊起。',126,'宋词/ci.song.12000.json','["夜深客子移舟处，两两沙禽惊起。", "红衣入浆，青灯摇浪，微凉意思。", "把酒临风，不思归去，有如此水。", "况茂林游倦，长干望久，芳心事、箫声里。", "屈指归期尚未。", "鹊南飞、有人应喜。", "画栏桂子，留香小待，提携影底。", "我已情多，十年幽梦，略曾如此。", "甚谢郎、也恨飘零，解道月明千里。"]'),
('song-ci-697','探春慢','姜夔','宋','宋词','song-ci','探春慢','[]','衰草愁烟，乱鸦送日，风沙回旋平野。',125,'宋词/ci.song.12000.json','["衰草愁烟，乱鸦送日，风沙回旋平野。", "拂雪金鞭，欺寒茸帽，还记章台走马。", "谁念飘零久，漫赢得、幽怀难写。", "故人清沔相逢，小窗闲共情话。", "长恨离多会少，重访问竹西，珠泪盈把。", "雁碛波平，渔汀人散，老去不堪游冶。", "无奈苕溪月，又照我、扁舟东下。", "甚日归来，梅花零乱春夜。"]'),
('song-ci-698','八归','姜夔','宋','宋词','song-ci','八归','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','芳莲坠粉，蔬桐吹绿，庭院暗雨乍歇。',139,'宋词/ci.song.12000.json','["芳莲坠粉，蔬桐吹绿，庭院暗雨乍歇。", "无端抱影销魂处，还见筱墙萤暗，藓阶蛩切。", "送客重寻西去路，问水面、琵琶谁拨。", "最可惜、一片江山，总付与啼鴂。", "长恨相从未款，而今何事，又对西风离别。", "渚寒烟淡，棹移人远，缥缈行舟如叶。", "想文君望久，倚竹愁生步罗袜。", "归来后、翠尊双饮，下了珠帘，玲珑闲看月。"]'),
('song-ci-699','解连环','姜夔','宋','宋词','song-ci','解连环','[]','玉鞭重倚。',132,'宋词/ci.song.12000.json','["玉鞭重倚。", "却沈吟未上，又萦离思。", "为大乔、能拨春风，小乔妙移筝，雁啼秋水。", "柳怯云松，更何必、十分梳洗。", "道郎携羽扇，那日隔帘，半面曾记。", "西窗夜凉雨霁。", "叹幽欢未足，何事轻弃。", "问后约、空指蔷薇，算如此溪山，甚时重至。", "水驿灯昏，又见在、曲屏近底。", "念唯有、夜来皓月，照伊自睡。"]'),
('song-ci-700','喜迁莺慢・喜迁莺','姜夔','宋','宋词','song-ci','喜迁莺慢・喜迁莺','[]','玉珂朱组。',128,'宋词/ci.song.12000.json','["玉珂朱组。", "又占了、道人林下真趣。", "窗户新成，青红犹润，双燕为君胥宇。", "秦淮贵人宅第，问谁记、六朝歌舞。", "总付与、在柳桥花馆，玲珑深处。", "居士。", "闲记取。", "高卧未成，且种松千树。", "觅句堂深，写经窗静，他日任听风雨。", "列仙更教谁做，一院双成俦侣。", "世间住。", "且休将鸡犬，云中飞去。"]'),
('song-ci-701','摸鱼儿','姜夔','宋','宋词','song-ci','摸鱼儿','[]','向秋来、渐疏班扇，雨声时过金井。',140,'宋词/ci.song.12000.json','["向秋来、渐疏班扇，雨声时过金井。", "堂虚已放新凉入，湘竹最宜敧枕。", "闲记省。", "又还是、斜河旧约今再整。", "天风夜冷。", "自织锦人归，乘槎客去，此意有谁领。", "空赢得，今古三星炯炯。", "银波相望千顷。", "柳州老矣犹儿戏，瓜果为伊三请。", "云路回。", "漫说道、年年野鹊曾并影。", "无人与问。", "但浊酒相呼，疏帘自卷，微月照清饮。"]'),
('song-ci-702','扬州慢','姜夔','宋','宋词','song-ci','扬州慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','淮左名都，竹西佳处，解鞍少驻初程。',120,'宋词/ci.song.12000.json','["淮左名都，竹西佳处，解鞍少驻初程。", "过春风十里，尽荠麦青青。", "自胡马窥江去后，废池乔木，犹厌言兵。", "渐黄昏，清角吹寒，都在空城。", "杜郎俊赏，算而今，重到须惊。", "纵豆蔻词工，青楼梦好，难赋深情。", "二十四桥仍在，波心荡、冷月无声。", "念桥边红药，年年知为谁生。"]'),
('song-ci-703','长亭怨慢','姜夔','宋','宋词','song-ci','长亭怨慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','渐吹尽、枝头香絮。',121,'宋词/ci.song.12000.json','["渐吹尽、枝头香絮。", "是处人家，绿深门户。", "远浦萦回，暮帆零乱向何许。", "阅人多矣，谁得似、长亭树。", "树若有情时，不会得、青青如此。", "日暮。", "望高城不见，只见乱山无数。", "韦郎去也，怎忘得、玉环分付。", "第一是、早早归来，怕红萼、无人为主。", "算空有并刀，难翦离愁千缕。"]'),
('song-ci-704','淡黄柳','姜夔','宋','宋词','song-ci','淡黄柳','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','空城晓月。',78,'宋词/ci.song.12000.json','["空城晓月。", "吹入垂杨陌。", "马上单衣寒恻恻。", "看尽鹅黄嫩绿，都是江南旧相识。", "正岑寂。", "明朝又寒食。", "强携酒、小桥宅，怕梨花落尽成秋色。", "燕燕飞来，问春何在，唯有池塘自碧。"]'),
('song-ci-705','石湖仙','姜夔','宋','宋词','song-ci','石湖仙','[]','松江烟浦。',111,'宋词/ci.song.12000.json','["松江烟浦。", "是千古三高，游衍佳处。", "须信石湖仙，似鸱夷、翩然引去。", "浮云安在，我自爱、绿香红舞。", "容与。", "看世间、几度今古。", "卢沟旧曾驻马，为黄花、闲吟秀句。", "见说胡儿，也学纶巾敧雨。", "玉友金蕉，玉人金缕。", "缓移筝柱。", "闲好语。", "明年定在槐府。"]'),
('song-ci-706','暗香','姜夔','宋','宋词','song-ci','暗香','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','旧时月色。',120,'宋词/ci.song.12000.json','["旧时月色。", "算几番照我，梅边吹笛。", "唤起玉人，不管清寒与攀摘。", "何逊而今渐老，都忘却、春风词笔。", "但怪得、竹外疏花，香冷入瑶席。", "江国。", "正寂寂。", "叹寄与路遥，夜雪初积。", "翠尊易泣。", "红萼无言耿相忆。", "长记曾携手处，千树压、西湖寒碧。", "又片片、吹尽也，几时见得。"]'),
('song-ci-707','疏影','姜夔','宋','宋词','song-ci','疏影','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','苔枝缀玉。',134,'宋词/ci.song.12000.json','["苔枝缀玉。", "有翠禽小小，枝上同宿。", "客里相逢，篱角黄昏，无言自倚修竹。", "昭君不惯胡沙远，但暗忆、江南江北。", "想佩环、月夜归来，化作此花幽独。", "犹记深宫旧事，那人正睡里，飞近蛾绿。", "莫似春风，不管盈盈，早与安排金屋。", "还教一片随波去，又却怨、玉龙哀曲。", "等恁时、重觅幽香，已入小窗横幅。"]'),
('song-ci-708','惜红衣','姜夔','宋','宋词','song-ci','惜红衣','[]','簟枕邀凉，琴书换日，睡馀无力。',108,'宋词/ci.song.12000.json','["簟枕邀凉，琴书换日，睡馀无力。", "细洒冰泉，并刀破甘碧。", "墙头唤酒，谁问讯、城南诗客。", "岑寂。", "高柳晚蝉，说西风消息。", "虹粱水陌。", "鱼浪吹香，红衣半狼藉。", "维舟试望故国。", "眇天北。", "可惜渚边沙外，不共美人游历。", "问甚时同赋，三十六陂秋色。"]'),
('song-ci-709','角招','姜夔','宋','宋词','song-ci','角招','["\u897f\u6e56"]','为春瘦。',134,'宋词/ci.song.12000.json','["为春瘦。", "何堪更绕西湖，尽是垂柳。", "自看烟外岫。", "记得与君，湖上携手。", "君归未久。", "早乱落、香红千亩。", "一叶凌波缥缈，过三十六离宫，遣游人回首。", "犹有。", "画船障袖。", "青楼倚扇，相映人争秀。", "翠翘光欲溜。", "爱著宫黄，而今时候。", "伤春似旧。", "荡一点、春心如酒。", "写入吴丝自奏。", "问谁识，曲中心、花前友。"]'),
('song-ci-710','徵招','姜夔','宋','宋词','song-ci','徵招','[]','潮回却过西陵浦，扁舟仅容居士。',117,'宋词/ci.song.12000.json','["潮回却过西陵浦，扁舟仅容居士。", "去得几何时，黍离离如此。", "客途今倦矣。", "漫赢得、一襟诗思。", "记忆江南，落帆沙际，此行还是。", "迤逦。", "剡中山，重相见、依依故人情味。", "似怨不来游，拥愁鬟十二。", "一丘聊复尔。", "也孤负、幼舆高志。", "水葓晚，漠漠摇烟，奈未成归计。"]'),
('song-ci-711','秋宵吟','姜夔','宋','宋词','song-ci','秋宵吟','[]','古帘空，坠月皎。',123,'宋词/ci.song.12000.json','["古帘空，坠月皎。", "坐久西窗人悄。", "蛩吟苦，渐漏水丁丁，箭壶催晓。", "引凉飔、动翠葆。", "露脚斜飞云表。", "因嗟念，似去国情怀，暮帆烟草。", "带眼销磨，为近日、愁多顿老。", "卫娘何在，宋玉归来，两地暗萦绕。", "摇落江枫早。", "嫩约无凭，幽梦又杳。", "但盈盈、泪洒单衣，今夕何夕恨未了。"]'),
('song-ci-712','凄凉犯','姜夔','宋','宋词','song-ci','凄凉犯','["\u897f\u6e56"]','绿杨巷陌。',115,'宋词/ci.song.12000.json','["绿杨巷陌。", "秋风起、边城一片离索。", "马嘶渐远，人归甚处，戍楼吹角。", "情怀正恶。", "更衰草寒烟淡薄。", "似当时、将军部曲，迤逦度沙漠。", "追念西湖上，小舫携歌，晚花行乐。", "旧游在否，想如今、翠凋红落。", "漫写羊裙，等新雁来时系著。", "怕匆匆、不肯寄与，误后约。"]'),
('song-ci-713','翠楼吟','姜夔','宋','宋词','song-ci','翠楼吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','月冷龙沙，尘轻虎落，今年汉酺初赐。',126,'宋词/ci.song.12000.json','["月冷龙沙，尘轻虎落，今年汉酺初赐。", "新翻胡部曲，听毡幕、元戎歌吹。", "层楼高峙。", "看栏曲萦红，檐牙飞翠。", "人姝丽。", "粉香吹下，夜寒风细。", "此地。", "宜有词仙，拥素云黄鹤，与君游戏。", "玉梯凝望久，叹芳草、萋萋千里。", "天涯情味。", "仗酒襏清愁，花销英气。", "西山外。", "晚来还卷，一帘秋霁。"]'),
('song-ci-714','湘月・念奴娇','姜夔','宋','宋词','song-ci','湘月・念奴娇','[]','五湖旧约，问经年底事，长负清景。',122,'宋词/ci.song.12000.json','["五湖旧约，问经年底事，长负清景。", "暝入西山，渐唤我、一叶夷犹乘兴。", "倦网都收，归禽时度，月上汀州冷。", "中流容与，画桡不点清镜。", "谁解唤起湘灵，烟鬟雾鬓，理哀弦鸿阵。", "玉麈谈玄，叹坐客、多少风流名胜。", "暗柳萧萧，飞星冉冉，夜久知秋信。", "鲈鱼应好，旧家乐事谁省。"]'),
('song-ci-715','小重山令・小重山','姜夔','宋','宋词','song-ci','小重山令・小重山','[]','寒食飞红满帝城。',70,'宋词/ci.song.12000.json','["寒食飞红满帝城。", "慈乌相对立，柳青青。", "玉阶端笏细陈情。", "天恩许，春尽可还京。", "鹊报倚门人。", "安舆扶上了，更亲擎。", "看花携乐缓行程。", "争迎处，堂下拜公卿。"]'),
('song-ci-716','念奴娇','姜夔','宋','宋词','song-ci','念奴娇','[]','昔游未远，记湘皋闻瑟，沣浦捐褋。',120,'宋词/ci.song.12000.json','["昔游未远，记湘皋闻瑟，沣浦捐褋。", "因觅孤山林处士，来踏梅根残雪。", "獠女供花，伧儿行酒，卧看青门辙。", "一丘吾老，可怜情事空切。", "曾见海作桑田，仙人云表，笑汝真痴绝。", "说与依依王谢燕，应有凉风时节。", "越只青山，吴惟芳草，万古皆沈灭。", "绕枝三匝，白头歌尽明月。"]'),
('song-ci-717','卜算子','姜夔','宋','宋词','song-ci','卜算子','["\u897f\u6e56"]','江左咏梅人，梦绕青青路。',52,'宋词/ci.song.12000.json','["江左咏梅人，梦绕青青路。", "因向凌风台下看，心事还将与。", "忆别庾郎时，又过林逋处。", "万古西湖寂寞春，惆怅谁能赋。"]'),
('song-ci-718','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','月上海云沈，鸥去吴波回。',52,'宋词/ci.song.12000.json','["月上海云沈，鸥去吴波回。", "行过西泠有一枝，竹暗人家静。", "又见水沈亭，举目悲风景。", "花下铺毡把一杯，缓饮春风影。"]'),
('song-ci-719','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','藓干石斜妨，玉蕊松低覆。',52,'宋词/ci.song.12000.json','["藓干石斜妨，玉蕊松低覆。", "日暮冥冥一见来，略比年时瘦。", "凉观酒初醒，竹阁吟才就。", "犹恨幽香作许悭，小迟春心透。"]'),
('song-ci-720','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','家在马城西，今赋梅屏雪。',52,'宋词/ci.song.12000.json','["家在马城西，今赋梅屏雪。", "梅雪相兼不见花，月影玲珑彻。", "前度带愁看，一饷和愁折。", "若使逋仙及见之，定自成愁绝。"]'),
('song-ci-721','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','摘蕊暝禽飞，倚树悬冰落。',52,'宋词/ci.song.12000.json','["摘蕊暝禽飞，倚树悬冰落。", "下竺桥边浅立时，香已漂流却。", "空径晚烟平，古寺春寒恶。", "老子寻花第一番，常恐吴儿觉。"]'),
('song-ci-722','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','绿萼更横枝，多少梅花样。',52,'宋词/ci.song.12000.json','["绿萼更横枝，多少梅花样。", "惆怅西村一坞春，开遍无人赏。", "细草藉金舆，岁岁长吟想。", "枝上么禽一两声，犹似宫娥唱。"]'),
('song-ci-723','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','象笔带香题，龙笛吟春咽。',52,'宋词/ci.song.12000.json','["象笔带香题，龙笛吟春咽。", "杨柳娇痴未觉愁，花管人离别。", "路出古昌源，石瘦冰霜洁。", "折得青须碧藓花，持向人间说。"]'),
('song-ci-724','卜算子','姜夔','宋','宋词','song-ci','卜算子','[]','御苑接湖波，松下春风细。',52,'宋词/ci.song.12000.json','["御苑接湖波，松下春风细。", "云绿峨峨玉万枝，别有仙风味。", "长信昨来看，忆共东皇醉。", "此树婆娑一惘然，苔藓生春意。"]'),
('song-ci-725','洞仙歌','姜夔','宋','宋词','song-ci','洞仙歌','[]','花中惯识，压架玲珑雪。',101,'宋词/ci.song.12000.json','["花中惯识，压架玲珑雪。", "乍见缃蕤间琅叶。", "恨春风将了，染额人归，留得个、袅袅垂香带月。", "鹅儿真似酒，我爱幽芳，远比酴醿又娇绝。", "自种古松根，待看黄龙，乱飞上、苍髯五鬣。", "更老仙、添与笔端春，敢唤起桃花，问谁优劣。"]'),
('song-ci-726','蓦山溪','姜夔','宋','宋词','song-ci','蓦山溪','[]','青青官柳，飞过双双燕。',102,'宋词/ci.song.12000.json','["青青官柳，飞过双双燕。", "楼上对春寒，卷珠帘、瞥然一见。", "如今春去，香絮乱因风，沾径草，惹墙花，一一教谁管。", "阳关去也，方表人肠断。", "几度拂行轩，念衣冠、尊前易散。", "翠眉织锦，红叶浪题诗。", "烟渡口，水亭边，长是心先乱。"]'),
('song-ci-727','永遇乐','姜夔','宋','宋词','song-ci','永遇乐','[]','我与先生，夙期已久，人间无此。',128,'宋词/ci.song.12000.json','["我与先生，夙期已久，人间无此。", "不学杨郎，南山种豆，十一徵微利。", "云霄直上，诸公衮衮，乃作道边苦李。", "五千言，老来受用，肯教造物儿戏。", "东冈记得，同来胥宇，岁月几时难计。", "柳老悲桓，松高对阮。", "未办为邻地。", "长干白下，青楼朱阁，往往梦中槐蚁。", "却不如、洼尊放满，老夫未醉。"]'),
('song-ci-728','虞美人','姜夔','宋','宋词','song-ci','虞美人','[]','阑干表立苍龙背。',66,'宋词/ci.song.12000.json','["阑干表立苍龙背。", "三面巉天翠。", "东游才上小蓬莱。", "不见此楼烟雨、未应回。", "而今指点来时路。", "却是冥濛处。", "老仙鹤驭几时归。", "未必山川城郭、是耶非。"]'),
('song-ci-729','永遇乐','姜夔','宋','宋词','song-ci','永遇乐','[]','云隔迷楼，苔封很石，人向何处。',127,'宋词/ci.song.12000.json','["云隔迷楼，苔封很石，人向何处。", "数骑秋烟，一篙寒汐，千古空来去。", "使君心在，苍厓绿嶂，苦被北门留住。", "有尊中酒差可饮，大旗尽绣熊虎。", "前身诸葛，来游此地，数语便酬三顾。", "楼外冥冥，江皋隐隐，认得征西路。", "中原生聚，神京耆老，南望长淮金鼓。", "问当时、依依种柳，至今在否。"]'),
('song-ci-730','水调歌头','姜夔','宋','宋词','song-ci','水调歌头','[]','日落爱山紫，沙涨省潮回。',114,'宋词/ci.song.12000.json','["日落爱山紫，沙涨省潮回。", "平生梦犹不到，一叶眇西来。", "欲讯桑田成海，人世了无知者，鱼鸟两相推。", "天外玉笙杳，子晋只空台。", "倚阑干，二三子，总仙才。", "尔歌远游章句，云气入吾杯。", "不问王郎五马，颇忆谢生双屐，处处长青苔。", "东望赤城近，吾兴亦悠哉。"]'),
('song-ci-731','汉宫春','姜夔','宋','宋词','song-ci','汉宫春','[]','云曰归欤。',118,'宋词/ci.song.12000.json','["云曰归欤。", "纵垂天曳曳，终反衡庐。", "扬州十年一梦，俯仰差殊。", "秦碑越殿，悔旧游、作计全疏。", "分付与、高怀老尹，管弦丝竹宁无。", "知公爱山入剡，若南寻李白，问讯何如。", "年年雁飞波上，愁亦关予。", "临皋领客，向月边、携酒携鲈。", "今但借、秋风一榻，公歌我亦能书。"]'),
('song-ci-732','汉宫春','姜夔','宋','宋词','song-ci','汉宫春','[]','一顾倾吴。',118,'宋词/ci.song.12000.json','["一顾倾吴。", "苎萝人不见，烟杳重湖。", "当时事如对弈，此亦天乎。", "大夫仙去，笑人间、千古须臾。", "有倦客、扁舟夜泛，犹疑水鸟相呼。", "秦山对楼自绿，怕越王故垒，时下樵苏。", "只今倚阑一笑，然则非欤。", "小丛解唱，倩松风、为我吹竽。", "更坐待、千岩月落，城头眇眇啼鸟。"]'),
('song-ci-733','点绛唇','姜夔','宋','宋词','song-ci','点绛唇','[]','祝寿筵开，画堂深映花如绣。',50,'宋词/ci.song.12000.json','["祝寿筵开，画堂深映花如绣。", "瑞烟喷兽。", "帘幕香风透。", "一点台星，化作人间秀。", "韶音奏。", "两行红袖。", "齐劝长生酒。"]'),
('song-ci-734','越女镜心・法曲献仙音','姜夔','宋','宋词','song-ci','越女镜心・法曲献仙音','[]','风竹吹香，水枫鸣绿，睡觉凉生金缕。',114,'宋词/ci.song.12000.json','["风竹吹香，水枫鸣绿，睡觉凉生金缕。", "镜底同心，枕前双玉，相看转伤幽素。", "傍绮阁、轻阴度。", "飞来鉴湖雨。", "近重午。", "燎银篝、暗薰溽暑。", "罗扇小、空写数行怨苦。", "纤手结芳兰，且休歌、九辩怀楚。", "故国情多，对溪山、都是离绪。", "但一川烟苇，恨满西陵归路。"]'),
('song-ci-735','月上海棠','姜夔','宋','宋词','song-ci','月上海棠','[]','红妆艳色，照浣花溪影，绝代姝丽。',110,'宋词/ci.song.12000.json','["红妆艳色，照浣花溪影，绝代姝丽。", "弄轻风、摇荡满林罗绮。", "自然富贵天姿，都不比、等闲桃李。", "帘栊静悄，月上正贪春睡。", "长记初开日，逞妖丽、如与人面争媚。", "过韶光一瞬，便成流水。", "对此日叹浮华，惜芳菲、易成憔悴。", "留无计。", "惟有花边尽醉。"]'),
('song-ci-736','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','听说古时月，皎洁胜今时。',114,'宋词/ci.song.12000.json','["听说古时月，皎洁胜今时。", "今人但见今月，也道似琉璃。", "君看少年眸子，那比婴儿神彩，投老又堪悲。", "明月不在盛，玉斧亦何为。", "约东坡，招太白，试寻思。", "凭谁斫却，里面桂影数千枝。", "忆在无怀天上，仍向有虞宫殿，看月到陈隋。", "别有一轮月，万古没成亏。"]'),
('song-ci-737','乳燕飞・贺新郎','汪莘','宋','宋词','song-ci','乳燕飞・贺新郎','[]','去郢频回首。',142,'宋词/ci.song.12000.json','["去郢频回首。", "正横江、荪桡容与，兰旌悠久。", "怅望龙门都不见，似把长楸孤负。", "念往日、佳人为偶。", "独向芳洲相思处，采苹花、杜若空盈手。", "乘赤豹，谁来后。", "云中眼界穷高厚。", "览山川、冀州还在，陶唐何有。", "木叶纷纷秋风晚，缥缈潇湘左右。", "见帝子、冰魂厮守。", "应记薰弦相对日，酹一杯、太乙东皇酒。", "问此意，君知否。"]'),
('song-ci-738','乳燕飞・贺新郎','汪莘','宋','宋词','song-ci','乳燕飞・贺新郎','["\u897f\u6e56"]','晓趁西湖约。',142,'宋词/ci.song.12000.json','["晓趁西湖约。", "到湖头，烟消日出，波生雨脚。", "日挈白鱼携碧酒，要与诗人共酌。", "把楼上、珠帘卷却。", "坐对荷花三万朵，念西邻、未嫁肌如削。", "待折与，不堪著。", "别来又见秋萧索。", "恨无由、将余风月，伴君云鹤。", "想见登山临水处，醉把茱萸槃礴。", "唱白雪、阳春新作。", "一自东篱人去后，算人间，黄菊空零落。", "叹作者，多命薄。"]'),
('song-ci-739','浪淘沙','汪莘','宋','宋词','song-ci','浪淘沙','[]','天末起凉风。',64,'宋词/ci.song.12000.json','["天末起凉风。", "云气匆匆。", "如今何处有英雄。", "独佩一壶溪上去，秋水澄空。", "绝壁耸云中，倒挂青松。", "醉歌汉殿与秦宫。", "日现山西留不住，目送飞鸿。"]'),
('song-ci-740','沁园春','汪莘','宋','宋词','song-ci','沁园春','[]','春至伤春，秋至悲秋，谁在华胥。',139,'宋词/ci.song.12000.json','["春至伤春，秋至悲秋，谁在华胥。", "叹谪仙才气，飞扬拔扈，渊明何事，慷慨欷歔。", "自我少年，如今晚境，行半人间真有馀。", "都休问，且一觞一咏，吾爱吾庐。", "南皋境界何如。", "舍明月清风谁与居。", "望蓬山路杳，万株翠桧，方壶门掩，四面红蕖。", "中有佳人，绰如姑射，一炷清香满太虚。", "尘寰外，被鸣鸾报客，飞鹤传书。"]'),
('song-ci-741','满江红','汪莘','宋','宋词','song-ci','满江红','[]','荆楚岁时，念自古、登临风俗。',115,'宋词/ci.song.12000.json','["荆楚岁时，念自古、登临风俗。", "休更道、桓家车骑，谢家丝竹。", "不觉吹将头上帽，可来共采篱边菊。", "叹如今，重九有何人，相追逐。", "穷处士，枯如木。", "贤太守，温如玉。", "遣厨人馈酒，廪人馈粟。", "欲寄唐虞无限意，离骚都是相思曲。", "奈两三、寒蝶尚于飞，秋光促。"]'),
('song-ci-742','满江红','汪莘','宋','宋词','song-ci','满江红','[]','万古灰飞，算何用、黄金满屋。',115,'宋词/ci.song.12000.json','["万古灰飞，算何用、黄金满屋。", "吾老矣，几番重九，几杯醽醁。", "此日登临多恨别，明年强健何由卜。", "且唤教、儿女逐人来，寻黄菊。", "苹已白，枫犹绿。", "鲈已晚，橙初熟。", "叹人间何事，稍如吾欲。", "五柳爱寻王母使，三闾好作湘妃曲。", "向飘风、冻雨返柴扉，骑黄犊。"]'),
('song-ci-743','浣溪沙','汪莘','宋','宋词','song-ci','浣溪沙','[]','一曲清溪绕舍流。',48,'宋词/ci.song.12000.json','["一曲清溪绕舍流。", "数间茅屋正宜秋。", "芙蓉灼灼出墙头。", "元亮气高还作令，少陵形瘦不封侯。", "村醪闲饮两三瓯。"]'),
('song-ci-744','念奴娇','汪莘','宋','宋词','song-ci','念奴娇','[]','龙山高会，忆当时宾主，风流云散。',120,'宋词/ci.song.12000.json','["龙山高会，忆当时宾主，风流云散。", "今日紫阳峰顶上，人望旌旗天半。", "万叠红蕖，千层黄菊，照耀成飞观。", "西风浩荡，碧天斜去双雁。", "遥想健笔淋漓，龙蛇落纸，妙句高张翰。", "笼日轻霞横数抹，绿水金波相间。", "目寄宣平，神追师道，归棹摇星汉。", "城中万户，烛光香雾交贯。"]'),
('song-ci-745','蓦山溪','汪莘','宋','宋词','song-ci','蓦山溪','[]','金风玉露，洗出乾坤体。',102,'宋词/ci.song.12000.json','["金风玉露，洗出乾坤体。", "乘兴到前村，见一片、清溪无底。", "竹篱茅舍，鸡犬两三家，寻渔父，问湘灵，拄杖斜阳里。", "青春误我，白发今如此。", "幸自识方壶，有个人，神通游戏。", "涧边野鹤，岩上忽孤云，倾浊酒，对黄花，又似东篱子。"]'),
('song-ci-746','生查子','汪莘','宋','宋词','song-ci','生查子','[]','春来春色佳，秋至秋光好。',48,'宋词/ci.song.12000.json','["春来春色佳，秋至秋光好。", "无计奈春归，又看秋光老。", "去年飞雪时，病与梅花道。", "来岁雪飞时，为把金樽倒。"]'),
('song-ci-747','感皇恩','汪莘','宋','宋词','song-ci','感皇恩','[]','年少好寻芳，早春时节。',81,'宋词/ci.song.12000.json','["年少好寻芳，早春时节。", "飞去飞来似蝴蝶。", "如今老大，懒趁五陵豪侠。", "梦中时听得，秦箫咽。", "割断人间，柳枝桃叶。", "海上书来恨离别。", "旧游还在，空锁烟霞万叠。", "举杯相忆处，青天月。"]'),
('song-ci-748','忆秦娥','汪莘','宋','宋词','song-ci','忆秦娥','[]','村南北。',56,'宋词/ci.song.12000.json','["村南北。", "夜来陡觉霜风急。", "霜风急。", "征途情绪，塞垣消息。", "佳人独倚琵琶泣。", "一江明月空相忆。", "空相忆。", "寒衣未絮，荻花狼籍。"]'),
('song-ci-749','点绛唇','汪莘','宋','宋词','song-ci','点绛唇','[]','数朵芙蕖，嫣然一笑凌清晓。',50,'宋词/ci.song.12000.json','["数朵芙蕖，嫣然一笑凌清晓。", "谢家池沼。", "秋景偏宜少。", "气挟清霜，似把群花小。", "秋风袅。", "湘君来了。", "一曲烟波渺。"]'),
('song-ci-750','菩萨蛮','汪莘','宋','宋词','song-ci','菩萨蛮','[]','问言何处秋光好。',52,'宋词/ci.song.12000.json','["问言何处秋光好。", "当年曾过长洲道。", "一望没遮拦。", "天宽水亦宽。", "也因轻霭扫。", "也傍斜晖讨。", "指点与君看。", "画他难不难。"]'),
('song-ci-751','桃源忆故人','汪莘','宋','宋词','song-ci','桃源忆故人','[]','人间只解春留住。',55,'宋词/ci.song.12000.json','["人间只解春留住。", "不管秋归去。", "一阵西窗风雨。", "秋也归何处。", "柴扉半掩闲庭户。", "黄叶青苔无数。", "犹把小春分付。", "梅蕊前村路。"]'),
('song-ci-752','浣溪沙','汪莘','宋','宋词','song-ci','浣溪沙','[]','青女催人两鬓霜。',48,'宋词/ci.song.12000.json','["青女催人两鬓霜。", "自篘白酒作重阳。", "方壶老子莫凄凉。", "天地两三胡蝶梦，古今多少菊花香。", "只将破帽送秋光。"]'),
('song-ci-753','点绛唇','汪莘','宋','宋词','song-ci','点绛唇','[]','晓角霜天，昼帘却是春天气。',50,'宋词/ci.song.12000.json','["晓角霜天，昼帘却是春天气。", "小园行处。", "双蝶相随至。", "恰向梅边，又向桃边觑。", "孜孜地。", "访兰寻蕙。", "谁会幽人意。"]'),
('song-ci-754','汉宫春','汪莘','宋','宋词','song-ci','汉宫春','[]','春色平分，甚偏他杨柳，分外风流。',118,'宋词/ci.song.12000.json','["春色平分，甚偏他杨柳，分外风流。", "夭桃自适其适，一笑还休。", "可怜仙李，对东风、却少温柔。", "争奈得、海棠妆点，向人浑不知羞。", "谁觉韶华如梦，到酴醿开后，莺语供愁。", "天教姚黄晚出，贵与王侔。", "花中隐者，有春兰、秋菊俱优。", "须是到、溪山清冻，江梅香喷枝头。"]'),
('song-ci-755','菩萨蛮','汪莘','宋','宋词','song-ci','菩萨蛮','[]','渔翁家住寒潭上。',52,'宋词/ci.song.12000.json','["渔翁家住寒潭上。", "晓霜晚日时相向。", "三尺白鱼长。", "一双摇玉光。", "前朝来献状。", "果慰携壶望。", "水月正商量。", "小桥梅欲香。"]'),
('song-ci-756','小重山','汪莘','宋','宋词','song-ci','小重山','[]','居士情怀爱小春。',70,'宋词/ci.song.12000.json','["居士情怀爱小春。", "恰如重会面，旧时人。", "东君轻笑又轻颦。", "如道我，春去却伤心。", "青鸟下红巾。", "瑶池春信早，莫因循。", "柳丝黄日牡丹晨。", "相随逐，春浅到春深。"]'),
('song-ci-757','聒龙谣','汪莘','宋','宋词','song-ci','聒龙谣','[]','梦下瑶台，神飞阆苑，自叹尘寰久客。',125,'宋词/ci.song.12000.json','["梦下瑶台，神飞阆苑，自叹尘寰久客。", "三入成周，望皇居帝宅。", "荡兰桨、伊阙波涛，曳玉杖、洛阳阡陌。", "独踌躇、武烈文谟，天垂晚，月生魄。", "故人少，别怀多，引壶觞自酌，谁怜衰白。", "群仙问我，尚低头方册。", "共云将、东过扶摇，遇鸿濛、顿超玄默。", "待功成，翳凤骑麟，把蟠桃摘。"]'),
('song-ci-758','水龙吟','汪莘','宋','宋词','song-ci','水龙吟','[]','当年翦彩垂髫，超然便欲为仙去。',126,'宋词/ci.song.12000.json','["当年翦彩垂髫，超然便欲为仙去。", "世间俗状，人心狡计，不堪同住。", "每坐空山，独临古涧，神闲意寓。", "想瀛洲鸡犬，蓬莱猿鹤，应怅望，门前路。", "自昔侯王将相，几番成、落花飞絮。", "仰天醉眼，兴云妙手，年华迟暮。", "长揖烟尘，静朝日月，谁知幽素。", "正风清麟背，星垂海角，晓钟初寤。"]'),
('song-ci-759','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','寄语山阿子，何日出幽篁。',114,'宋词/ci.song.12000.json','["寄语山阿子，何日出幽篁。", "兰衣蕙带，为我独立万寻冈。", "头上青天荡荡，足下白云霭霭，和气自悠扬。", "一阵东风至，灵雨过南塘。", "招山鬼，吊河伯，俟东皇。", "朱宫紫阙，何事宛在水中央。", "长望龙輈雷驾，凭仗箫钟交鼓，宾日出扶桑。", "我乃援北斗，子亦射天狼。"]'),
('song-ci-760','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','谁与玩芳草，公子未西归。',114,'宋词/ci.song.12000.json','["谁与玩芳草，公子未西归。", "天然脱去雕饰，秋水落芙蕖。", "发轫朝兮东壁，弭节夕兮西极，故国入踌躇。", "梦里不知路，南斗正扶疏。", "鸩不好，凤不利，忆三闾。", "算来何事，苦道岁晏孰华余。", "首拜东皇太乙，复次云君司命，高曳九霞裾。", "山鬼正含睇，慕我欲何如。"]'),
('song-ci-761','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','尧舜去已远，稷契不重来。',114,'宋词/ci.song.12000.json','["尧舜去已远，稷契不重来。", "周流天上地下，我马亦悠哉。", "君向云中独立，知与何人相俟，孔盖逐风回。", "长忆目成处，却苦别离催。", "被明月，佩宝璐，冠崔嵬。", "可怜幼好奇服，年老在尘埃。", "天地与我同性，日月与我同命，何事有馀哀。", "故国空乔木，野鹿上高台。"]'),
('song-ci-762','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','孔孟化尘土，秦汉共丘墟。',114,'宋词/ci.song.12000.json','["孔孟化尘土，秦汉共丘墟。", "人间美恶如梦，试看几张书。", "还是天一地二，做出朝三暮四，堪笑又堪悲。", "谁忆陶元亮，春酒解饥劬。", "老将至，岁既晏，念春归。", "停云亲友南北，何以慰离居。", "半郭半村佳处，一竹一花生意，吾亦爱吾庐。", "时访前村酒，旋买小溪鱼。"]'),
('song-ci-763','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','志可洞金石，气可塞堪舆。',114,'宋词/ci.song.12000.json','["志可洞金石，气可塞堪舆。", "问君所志安在，富贵胜人乎。", "看取首阳二子，叩住孟津匹马，天讨不枝梧。", "特立浮云外，大块可齐驱。", "铁可折，玉可碎，海可枯。", "不论穷达生死，直节贯殊途。", "立处孤峰万仞，袖里青蛇三尺，用舍付河图。", "晞汝阳阿上，濯汝洞庭河。"]'),
('song-ci-764','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','欲觅存心法，当自尽心求。',114,'宋词/ci.song.12000.json','["欲觅存心法，当自尽心求。", "此心尽处，豁地知性与天侔。", "行尽武陵溪路，忽见桃源洞口，渔子舍渔舟。", "输与逃秦侣，绝境几春秋。", "举全体，既尽得，要敛收。", "勿忘勿助之际，玄牝一丝头。", "君看天高地下，中有鸢飞鱼跃，妙用正周流。", "可与知者道，莫语俗人休。"]'),
('song-ci-765','满江红','汪莘','宋','宋词','song-ci','满江红','[]','唐宋诸公，谁道得、梅花亲切。',115,'宋词/ci.song.12000.json','["唐宋诸公，谁道得、梅花亲切。", "到和靖、先生诗出，古人俱拙。", "写照乍分清浅水，传神初付黄昏月。", "尽后来、作者斗尖新，仍重叠。", "离不得，春和腊。", "少不得，烟和雪。", "更茅檐低亚，竹篱轻折。", "何事西邻春得入，还如东阁人伤别。", "总输他、树下作僧来，离言说。"]'),
('song-ci-766','满江红','汪莘','宋','宋词','song-ci','满江红','[]','洞府瑶池，多是见、桃红满地。',115,'宋词/ci.song.12000.json','["洞府瑶池，多是见、桃红满地。", "君试问、江海清绝，因何抛弃。", "仙景常如二三月，此花不受春风醉。", "被贩儿、俚妇折来看，添憔悴。", "泛雪艇，摇冰枻。", "溪馆静，村扉闭。", "须祁寒彻骨，清香透鼻。", "孤竹赤松真我友，姚黄魏紫非吾契。", "笑方壶、日日绕南枝，犹多事。"]'),
('song-ci-767','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','[]','草木自成岁，禽鸟已春声。',114,'宋词/ci.song.12000.json','["草木自成岁，禽鸟已春声。", "仰观俯察，多少宇宙古今情。", "遐想炎黄以上，逮至汉唐而下，几个费经营。", "巢许有真意，无责自身轻。", "富与贵，贫与贱，死还生。", "方壶岁晚，深感梅蕊向人倾。", "造物元来无物，有物还应自造，人意几曾平。", "天际识归路，野鹤忽长鸣。"]'),
('song-ci-768','沁园春','汪莘','宋','宋词','song-ci','沁园春','[]','三十六峰，三十六溪，长锁清秋。',139,'宋词/ci.song.12000.json','["三十六峰，三十六溪，长锁清秋。", "对孤峰绝顶，云烟竞秀，悬崖峭壁，瀑布争流。", "洞里桃花，仙家芝草，雪后春正取次游。", "亲曾见，是龙潭白画，海涌潮头。", "当年黄帝浮丘。", "有玉枕玉床还在不。", "向天都月夜，遥闻凤管，翠微霜晓，仰盼龙楼。", "砂穴长红，丹炉已冷，安得灵方闻早修。", "谁知此，问原头白鹿，水畔青牛。"]'),
('song-ci-769','沁园春','汪莘','宋','宋词','song-ci','沁园春','["\u9ec4\u5c71"]','家在柳塘，榜挂方壶，图挂黄山。',139,'宋词/ci.song.12000.json','["家在柳塘，榜挂方壶，图挂黄山。", "觉仙峰六六，满堂峭峻，仙溪六六，绕屋潺湲。", "行到水穷，坐看云起，只在吾庐寻丈间。", "非人世，但鹤飞深谷，猿啸高岩。", "如今老疾蹒跚。", "向画里嬉游卧里看。", "甚花开花落，悄无人见，山南山北，谁似余闲。", "住个庵儿，了些活计，月白风清人倚阑。", "山中友，类先秦气貌，后晋衣冠。"]'),
('song-ci-770','行香子','汪莘','宋','宋词','song-ci','行香子','[]','野店残冬。',84,'宋词/ci.song.12000.json','["野店残冬。", "绿酒春浓。", "念如今、此意谁同。", "溪光不尽，山翠无穷。", "有几枝梅，几竿竹，几株松。", "篮舆乘兴，薄暮疏钟。", "望孤村、斜日匆匆。", "夜窗雪阵，晓枕云峰。", "便拥渔蓑，顶渔笠，作渔翁。"]'),
('song-ci-771','行香子','汪莘','宋','宋词','song-ci','行香子','[]','策杖溪边。',84,'宋词/ci.song.12000.json','["策杖溪边。", "倚杖峰前。", "望琼林、玉树森然。", "谁家残雪，何处孤烟。", "向一溪桥，一茅店，一渔船。", "别般天地，新样山川。", "唤家童、访鹤寻猿。", "山深寺远，云冷钟残。", "喜竹间灯，梅间屋，石间泉。"]'),
('song-ci-772','水调歌头','汪莘','宋','宋词','song-ci','水调歌头','["\u9ec4\u5c71"]','酿秫小春月，取酒雪花晨。',114,'宋词/ci.song.12000.json','["酿秫小春月，取酒雪花晨。", "漏壶插破浮蚁，涌起碧鳞鳞。", "谁觉东风密至，更带梅香潜入，瓮里净无尘。", "一见酒之面，便得酒之心。", "这番酒，□□□，未及宾。", "黄山图就，旧日境界喜重新。", "三十六峰云嶂，三十六溪烟水，三十六壶春。", "寄语黄山道，我是境中人。"]'),
('song-ci-773','鹊桥仙','汪莘','宋','宋词','song-ci','鹊桥仙','[]','柳塘居处，方壶道号，汪姓莘名耕字。',68,'宋词/ci.song.12000.json','["柳塘居处，方壶道号，汪姓莘名耕字。", "欲将丹药点凡花，教都做、水仙无计。", "家中安石，村中居易，总是一场游戏。", "曲终金石满吾庐，争奈少、柳家风味。"]'),
('song-ci-774','鹊桥仙','汪莘','宋','宋词','song-ci','鹊桥仙','[]','傥来无定，浮生如寄，休说真非真是。',68,'宋词/ci.song.12000.json','["傥来无定，浮生如寄，休说真非真是。", "道人半睡半醒时，全身在、碧霄宫里。", "风师四起，云君六合，茅舍有何准拟。", "待他雪阵打窗来，旋披起、半床纸被。"]'),
('song-ci-775','沁园春','汪莘','宋','宋词','song-ci','沁园春','[]','流水小桥，茅屋竹窗，纸帐蒲团。',139,'宋词/ci.song.12000.json','["流水小桥，茅屋竹窗，纸帐蒲团。", "把坎宫闭了，虎龙吟啸，离宫锁定，日月回环。", "万点星飞，两轮电转，五色圆光天样宽。", "□奇处，渐冥冥杳杳，有个鸦翻。", "当时筑著机关。", "后常把空华戏弄看。", "更有些可笑，寐中清境，有些可怪，镜里清颜。", "太上留魂，老君炼魄，又被瞿昙都扫残。", "如何好，只单修见性，双练还丹。"]'),
('song-ci-776','杏花天','汪莘','宋','宋词','song-ci','杏花天','[]','残雪林塘春意浅。',65,'宋词/ci.song.12000.json','["残雪林塘春意浅。", "倚碧玉、阑干日晚。", "天涯五色明如翦。", "上有新蟾占断。", "从别后、水遥山远。", "倩说与、天台刘阮。", "方壶只有梅花伴。", "不似桃花庭院。"]'),
('song-ci-777','杏花天','汪莘','宋','宋词','song-ci','杏花天','[]','美人家在江南住。',65,'宋词/ci.song.12000.json','["美人家在江南住。", "每惆恨、江南日暮。", "白苹洲畔花无数。", "还忆潇湘风度。", "幸自是、断肠无处。", "怎强作、莺声燕语。", "东风占断秦筝柱。", "也逐落花归去。"]'),
('song-ci-778','减字木兰花','汪莘','宋','宋词','song-ci','减字木兰花','[]','诗家清绝。',52,'宋词/ci.song.12000.json','["诗家清绝。", "檐外森然苍玉节。", "学易无思。", "一笑窗前白玉妃。", "何人共说。", "山上青松松上雪。", "更有谁知。", "溪在门前月在溪。"]'),
('song-ci-779','西江月','汪莘','宋','宋词','song-ci','西江月','[]','红白虽分两色，清香总是梅花。',58,'宋词/ci.song.12000.json','["红白虽分两色，清香总是梅花。", "早春风日野人家。", "相对伯夷柳下。", "爱影拈将灯取，惜香放下帘遮。", "长安如梦只堪嗟。", "乐此应须贤者。"]'),
('song-ci-780','西江月','汪莘','宋','宋词','song-ci','西江月','[]','曾把江梅入室，门人不敬红梅。',58,'宋词/ci.song.12000.json','["曾把江梅入室，门人不敬红梅。", "清香一点入灵台。", "傲雪家风犹在。", "状貌妇人孺子，性情烈士奇才。", "自开自落有谁来。", "与汝上林相待。"]'),
('song-ci-781','西江月','汪莘','宋','宋词','song-ci','西江月','[]','天下老松有数，人间不记何年。',58,'宋词/ci.song.12000.json','["天下老松有数，人间不记何年。", "海心岳顶寺门前。", "我欲收成一片。", "为向此公传语，却教老子随缘。", "龙盘虎踞负青天。", "岂若吾身亲见。"]'),
('song-ci-782','卜算子','汪莘','宋','宋词','song-ci','卜算子','[]','夏则饮红泉，冬则餐红术。',52,'宋词/ci.song.12000.json','["夏则饮红泉，冬则餐红术。", "一片新春入手来，不费些儿力。", "春在水无痕，春在山无迹。", "李白桃红未吐时，好个春消息。"]'),
('song-ci-783','南乡子','汪莘','宋','宋词','song-ci','南乡子','[]','茅舍起疏烟。',66,'宋词/ci.song.12000.json','["茅舍起疏烟。", "家在寒溪阿那边。", "修竹当篱梅当户，萧然。", "问是尧天是葛天。", "风雨入新年。", "惟恐春阴咽管弦。", "绿酒一樽歌一曲，人传。", "不属天仙属散仙。"]'),
('song-ci-784','好事近','汪莘','宋','宋词','song-ci','好事近','["\u9ec4\u5c71"]','堂上挂黄山，辉映庭前春雪。',53,'宋词/ci.song.12000.json','["堂上挂黄山，辉映庭前春雪。", "记得山中雪境，恰一般清绝。", "须知天锡与方壶，比似镜湖别。", "好得镜湖狂客，伴方壶欢伯。"]'),
('song-ci-785','好事近','汪莘','宋','宋词','song-ci','好事近','[]','挽我过溪桥，请与春风权摄。',53,'宋词/ci.song.12000.json','["挽我过溪桥，请与春风权摄。", "推出雪峰千丈，照碧溪春色。", "别来三度见梅花，今日共君说。", "只这溪山十里，剩几多风月。"]'),
('song-ci-786','生查子','汪莘','宋','宋词','song-ci','生查子','[]','天上不知天，洞里休寻洞。',52,'宋词/ci.song.12000.json','["天上不知天，洞里休寻洞。", "洞府天宫在眼前，春日都浮动。", "我自觉来看，他在迷时梦。", "觉则人人总是仙，步步乘鸾凤。"]'),
('song-ci-787','好事近','汪莘','宋','宋词','song-ci','好事近','[]','风日未全春，又是春来风日。',53,'宋词/ci.song.12000.json','["风日未全春，又是春来风日。", "不出方壶门户，见东皇消息。", "此时春事苦无多，春意最端的。", "却被草牙引去，向柳梢收得。"]'),
('song-ci-788','好事近','汪莘','宋','宋词','song-ci','好事近','[]','春早不知春，春晚又还无味。',53,'宋词/ci.song.12000.json','["春早不知春，春晚又还无味。", "一点日中星鸟，想尧民如醉。", "不寒不暖杏花天，花到半开处。", "正是太平风景，为人间留住。"]'),
('song-ci-789','好事近','汪莘','宋','宋词','song-ci','好事近','[]','风雨打黄昏，啼杀满山杜宇。',53,'宋词/ci.song.12000.json','["风雨打黄昏，啼杀满山杜宇。", "到得人间春去，问英雄何处。", "桃红李白竞春光，谁共残妆语。", "最是梨花一树，照谁家庭户。"]'),
('song-ci-790','好事近','汪莘','宋','宋词','song-ci','好事近','["\u6d1e\u5ead\u6e56"]','阆苑梦回时，窗外数声啼鸟。',53,'宋词/ci.song.12000.json','["阆苑梦回时，窗外数声啼鸟。", "觉我床前天气，便清明多少。", "诗人门户约花开，宿蝶误飞了。", "一段山青水绿，作洞庭春晓。"]'),
('song-ci-791','好事近','汪莘','宋','宋词','song-ci','好事近','[]','夹岸隘桃花，花下苍苔如积。',53,'宋词/ci.song.12000.json','["夹岸隘桃花，花下苍苔如积。", "蓦地轻寒一阵，上桃花颜色。", "东邻西舍绝经过，新月是相识。", "白玉阑干斜倚，作蓬山春夕。"]'),
('song-ci-792','好事近','汪莘','宋','宋词','song-ci','好事近','[]','天宇绿无云，迟日江山如绣。',53,'宋词/ci.song.12000.json','["天宇绿无云，迟日江山如绣。", "是日轻衫团扇，笑折花相授。", "南山之北北山南，星鸟尚依旧。", "谁在松风高卧，作嵩阳春画。"]'),
('song-ci-793','好事近','汪莘','宋','宋词','song-ci','好事近','[]','月落画桥西，花影柳阴相亚。',53,'宋词/ci.song.12000.json','["月落画桥西，花影柳阴相亚。", "把住常娥问道，是谁家亭榭。", "天边处士少微星，正在杏花下。", "斜卓参旗一片，作草堂春夜。"]'),
('song-ci-794','洞仙歌','汪莘','宋','宋词','song-ci','洞仙歌','[]','春王正月，雪阵联翩下。',103,'宋词/ci.song.12000.json','["春王正月，雪阵联翩下。", "我有春风怎生卖。", "忽扫残夜雨，推出朝阳，天地里，玉烛一枝无价。", "早春虚过了，尚有二分，是处春光好收买。", "也不违天性，不远人情，杨柳陌、临水夭桃亭榭。", "身子外、只要自家人，共酒后羲皇，花前偏霸。"]'),
('song-ci-795','乳燕飞・贺新郎','汪莘','宋','宋词','song-ci','乳燕飞・贺新郎','[]','策杖南山去。',142,'宋词/ci.song.12000.json','["策杖南山去。", "到南溪、谁家宅院，欺人先渡。", "羽扇徐麾童仆退，翠柳白沙西路。", "帝赐我、阆风玄圃。", "一片飞来红叶阔，细看来、上有双鸾句。", "应念我，尘中住。", "眼前儿女闲相语。", "怪人间、禁烟时节，安排樽俎。", "为道从来寒食好，且莫思量今古。", "共绿水、春风鸥鹭。", "望我壶天天未晚，记碧桃、花发闲庭户。", "归到也，对花舞。"]'),
('song-ci-796','八声甘州','汪莘','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','惜馀春、蛱蝶引春来，杜鹃趣春归。',119,'宋词/ci.song.12000.json','["惜馀春、蛱蝶引春来，杜鹃趣春归。", "算何如桃李，浑无言说，开落忘机。", "多谢黄鹂旧友，相逐落花飞。", "芳草连天远，愁杀斜晖。", "谁向西湖南畔，问亭台在否，花木应非。", "看孤山山下，惟说隐君庐。", "想钱塘、春游依旧，到梨花、寒食隘舟车。", "寻常事，不须惆怅，暮雨沾衣。"]'),
('song-ci-797','浣溪沙','汪莘','宋','宋词','song-ci','浣溪沙','[]','白日青天蘸水开。',48,'宋词/ci.song.12000.json','["白日青天蘸水开。", "落花江上玉鞭回。", "东君擎出牡丹来。", "独占洛阳春气足，遂中天下作花魁。", "相知深处举离杯。"]'),
('song-ci-798','满庭芳','汪莘','宋','宋词','song-ci','满庭芳','[]','云绕花屏，天横练带，画堂三月初三。',118,'宋词/ci.song.12000.json','["云绕花屏，天横练带，画堂三月初三。", "斜风细雨，罗幕护轻寒。", "无数天香国色，枝枝带、洛浦嵩山。", "烧红烛，吞星□日，光射九霞冠。", "仙宫，深几许，黄莺问道，紫莺窥帘。", "似太真姊妹，半醒微酣。", "须信生来富贵，何曾在、草舍茅庵。", "皇州近，扁舟载去，春色冠东南。"]'),
('song-ci-799','谒金门','汪莘','宋','宋词','song-ci','谒金门','[]','檐溜滴。',53,'宋词/ci.song.12000.json','["檐溜滴。", "都是春归消息。", "带雨牡丹无气力。", "黄鹂愁雨湿。", "争看洛阳春色。", "忘却连天草碧。", "南浦绿波双桨急。", "沙头人伫立。"]'),
('song-ci-800','玉楼春','汪莘','宋','宋词','song-ci','玉楼春','[]','一片江南春色晚。',64,'宋词/ci.song.12000.json','["一片江南春色晚。", "牡丹花谢莺声懒。", "问君离恨几多长，芳草连天犹觉短。", "昨夜溪头新溜满。", "樽前自起喷龙管。", "明朝飞棹下钱塘，心共白苹香不断。"]'),
('song-ci-801','江神子・江城子','汪莘','宋','宋词','song-ci','江神子・江城子','[]','鹧鸪声里别江东。',86,'宋词/ci.song.12000.json','["鹧鸪声里别江东。", "绿阴中。", "夕阳红。", "一点离愁，相对景重重。", "目断大罗天上客，朝玉帝，把芙蓉。", "紫阳山下偶相逢。", "醉金锺。", "跨苍龙。", "归去故山，犹带白云封。", "洞口桃花如恨我，飘满地，任春风。"]'),
('song-ci-802','满庭芳','汪莘','宋','宋词','song-ci','满庭芳','[]','云梦南来，岷嶓东会，楼前天水苍茫。',118,'宋词/ci.song.12000.json','["云梦南来，岷嶓东会，楼前天水苍茫。", "黄州太守，万里作金汤。", "淮上烟尘初敛，仍安集、耕陇渔乡。", "须知道，纶巾羽扇，不独数周郎。", "生朝，遥想处，雪消赤壁，春动黄冈。", "有新翻杨柳，细抹丝簧。", "竹外一枝更好，应回首、清浅池塘。", "看看也，天边凤诏，归侍赭袍光。"]'),
('song-ci-803','哨遍','汪莘','宋','宋词','song-ci','哨遍','[]','近腊景和，故山可过，足下听余述。',239,'宋词/ci.song.12000.json','["近腊景和，故山可过，足下听余述。", "便自往山中，憩精蓝，与僧饭讫。", "北涉灞川，明月华映郭，夜登华子冈头立。", "嗟辋水沦涟，与月上下，寒山远火蒙笼。", "听林外犬类豹声雄。", "更村落谁家鸣夜舂。", "疏钟相闻，独坐此时，多思往日。", "噫，记与君同。", "清流仄径玉琤琮。", "携手赋佳什。", "往来萝月松风。", "只待仲春天，春山可望，山中卉木垂萝密。", "见出水轻鯈，点溪白鹭，青皋零露方湿。", "雉朝飞，麦陇鸣俦匹。", "念此去非遥莫相失。", "傥能从我敢相必。", "天机非子清者，此事非所急。", "是中有趣殊深，愿子无忽。", "不能一一。", "偶因驮檗附吾书，是山人王维摩诘。"]'),
('song-ci-804','满庭芳','曹彦约','宋','宋词','song-ci','满庭芳','[]','老子今年，年登七十，阿婆年亦相当。',120,'宋词/ci.song.12000.json','["老子今年，年登七十，阿婆年亦相当。", "几年辛苦，今日小风光。", "遇好景，何妨笑饮，依前是、未放心肠。", "人都道，明明了了，强似个儿郎。", "幸偿。", "婚嫁了，双雏蓝袖，拜舞称觞。", "女随夫上任，孙渐成行。", "惭愧十分圆满，无以报、办取炉香。", "频频祝，百年相守，老子更清强。"]'),
('song-ci-805','祝英台近','张潞','宋','宋词','song-ci','祝英台近','[]','宝熏浓，云幄重，琼叶丽金蕊。',95,'宋词/ci.song.12000.json','["宝熏浓，云幄重，琼叶丽金蕊。", "黛绿蜂黄，秋态未憔悴。", "绣帘深院黄昏，著香无处，人欲睡、为花重起。", "月如水。", "别有天外楼台，玲珑异尘世。", "翠袖生寒，只欠素娥倚。", "何如倩取西风，吹将归去，为添在、广寒宫里。"]'),
('song-ci-806','水调歌头','崔与之','宋','宋词','song-ci','水调歌头','[]','万里云间戍，立马剑门关。',114,'宋词/ci.song.12000.json','["万里云间戍，立马剑门关。", "乱山极目无际，直北是长安。", "人苦百年涂炭，鬼哭三边锋镝，天道久应还。", "手写留屯奏，炯炯寸心丹。", "对青灯，搔白发，漏声残。", "老来勋业未就，妨却一身闲。", "梅岭绿阴青子，蒲间清泉白石，怪我旧盟寒。", "烽火平安夜，归梦到家山。"]'),
('song-ci-807','贺新郎','崔与之','宋','宋词','song-ci','贺新郎','[]','雨过云容扫。',142,'宋词/ci.song.12000.json','["雨过云容扫。", "使星明、德心高揭，福心旁照。", "槐屋犹喧梅正熟，最是清和景好。", "望金节、云间缥缈。", "和气如春清似水，漾恩波、沾渥天南道。", "晨鹊噪，有佳报。", "天家黄纸除书到。", "便归来、升华天下，安边养浩。", "好是六逢初度日，碧落笙歌会早。", "遍西郡、欢声多少。", "人道菊坡新酝美，把一觞、满酌歌难老。", "瓜样大，安期枣。"]'),
('song-ci-808','念奴娇','吴琚','宋','宋词','song-ci','念奴娇','[]','我来浮玉，似凭陵沧海，蹑金鳌背。',120,'宋词/ci.song.12000.json','["我来浮玉，似凭陵沧海，蹑金鳌背。", "又若骑鲸游汗漫，飞入八荒之外。", "钟鼓传声，楼台倒影，不类人间世。", "徘徊吟眺，恨无陶谢酬对。", "今古潮落潮生，问英雄多少，与江俱逝。", "直欲乘风归阆苑，疑是三生习气。", "未辨鱼蓑，先盟鸥鹭，奈卜邻无地。", "从今清夜，梦魂应绕空翠。"]'),
('song-ci-809','柳梢青','吴琚','宋','宋词','song-ci','柳梢青','[]','彩仗鞭春。',61,'宋词/ci.song.12000.json','["彩仗鞭春。", "鹅毛飞管，斗柄回寅。", "拂面东风，虽然料峭，毕竟寒轻。", "戴花折柳心情。", "怎捱得、元宵放灯。", "不是今朝，有些残雪，先去踏青。"]'),
('song-ci-810','浪淘沙','吴琚','宋','宋词','song-ci','浪淘沙','[]','云叶弄轻阴。',64,'宋词/ci.song.12000.json','["云叶弄轻阴。", "屋角鸠鸣。", "青梅著子欲生仁。", "冷落江天寒食雨，花事关情。", "池馆昼盈盈。", "人醉寒轻。", "一川芳草只销凝。", "时有入帘新燕子，明日清明。"]'),
('song-ci-811','浪淘沙','吴琚','宋','宋词','song-ci','浪淘沙','[]','岸柳可藏鸦。',64,'宋词/ci.song.12000.json','["岸柳可藏鸦。", "路转溪斜。", "忘机鸥鹭立汀沙。", "咫尺锺山迷望眼，一半云遮。", "临水整乌纱。", "两鬓苍华。", "故乡心事在天涯。", "几日不来春便老，开尽桃花。"]'),
('song-ci-812','水龙吟','吴琚','宋','宋词','song-ci','水龙吟','[]','紫皇高宴萧台，双成戏击琼包碎。',127,'宋词/ci.song.12000.json','["紫皇高宴萧台，双成戏击琼包碎。", "何人为把，银河水翦，甲兵都洗。", "玉样乾坤，八荒同色，了无尘翳。", "喜冰销太液，暖融鳷鹊，端门晓、班初退。", "圣主忧民深意。", "转鸿钧、满天和气。", "太平有象，三宫二圣，万年千岁。", "双玉杯深，五云楼迥，不妨频醉。", "细看来、不是飞花，片片是、丰年瑞。"]'),
('song-ci-813','酹江月・念奴娇','吴琚','宋','宋词','song-ci','酹江月・念奴娇','[]','玉虹遥挂，望青山隐隐，一眉如抹。',120,'宋词/ci.song.12000.json','["玉虹遥挂，望青山隐隐，一眉如抹。", "忽觉天风吹海立，好似春霆初发。", "白马凌空，琼鳌驾水，日夜朝天阙。", "飞龙舞凤，郁葱环拱吴越。", "此景天下应无，东南形胜，伟观真奇绝。", "好是吴儿飞彩帜，蹴起一江秋雪。", "黄屋天临，水犀云拥，看击中流楫。", "晚来波静，海门飞上明月。"]'),
('song-ci-814','桂殿秋','刘翰','宋','宋词','song-ci','桂殿秋','[]','青帝子，碧莲宫。',32,'宋词/ci.song.12000.json','["青帝子，碧莲宫。", "不驾云车骑白龙。", "瑶池路远羽衣湿，玉珮泠泠明月中。"]'),
('song-ci-815','桂殿秋','刘翰','宋','宋词','song-ci','桂殿秋','[]','双玉节，到神京。',32,'宋词/ci.song.12000.json','["双玉节，到神京。", "碧杯仙露冷如冰。", "一声金磬千花发，洞口天风吹洒醒。"]'),
('song-ci-816','蝶恋花','刘翰','宋','宋词','song-ci','蝶恋花','[]','团扇题诗春又晚。',70,'宋词/ci.song.12000.json','["团扇题诗春又晚。", "小梦惊残，碧草池塘满。", "一曲银钩帘半卷。", "绿窗睡足莺声软。", "瘦损衣围罗带减。", "前度风流，陡觉心情懒。", "谁品新腔拈翠管。", "画楼吹彻江南怨。"]'),
('song-ci-817','清平乐','刘翰','宋','宋词','song-ci','清平乐','[]','萋萋芳草。',54,'宋词/ci.song.12000.json','["萋萋芳草。", "怨得王孙老。", "瘦损腰围罗带小。", "长是锦书来少。", "玉箫吹落梅花。", "晓寒犹透轻纱。", "惊起半屏幽梦，小窗淡月啼鸦。"]'),
('song-ci-818','清平乐','刘翰','宋','宋词','song-ci','清平乐','[]','鸳鸯翡翠。',54,'宋词/ci.song.12000.json','["鸳鸯翡翠。", "小小池塘水。", "落絮游丝花满地。", "度日阑干独倚。", "金刀裁就春衫。", "起来初试轻寒。", "满把相思清恨，题诗欲寄江南。"]'),
('song-ci-819','好事近','刘翰','宋','宋词','song-ci','好事近','[]','花底一声莺，花上半钩斜月。',53,'宋词/ci.song.12000.json','["花底一声莺，花上半钩斜月。", "月落乌啼何处，点飞英如雪。", "东风吹尽去年愁，解放丁香结。", "惊动小亭红雨，舞双双金蝶。"]'),
('song-ci-820','菩萨蛮','刘翰','宋','宋词','song-ci','菩萨蛮','[]','去时满地花阴月。',52,'宋词/ci.song.12000.json','["去时满地花阴月。", "归来落尽梧桐叶。", "帘外小梅残。", "绿窗幽梦寒。", "明朝提玉勒。", "又作江南客。", "芳草遍长亭。", "东风吹恨生。"]'),
('song-ci-821','谒金门','赵','宋','宋词','song-ci','谒金门','[]','天色晚。',53,'宋词/ci.song.12000.json','["天色晚。", "云外一筝斜雁。", "独凭阑干秋满眼。", "菊花寒尚浅。", "叶落香沟红泛。", "懒把新诗题怨。", "何处笛声三弄断。", "月迟帘未卷。"]'),
('song-ci-822','酹江月・念奴娇','杜','宋','宋词','song-ci','酹江月・念奴娇','[]','江山如此，是天开万古，东南王气。',120,'宋词/ci.song.12000.json','["江山如此，是天开万古，东南王气。", "一自髯孙横短策，坐使英雄鹊起。", "玉树声消，金莲影散，多少伤心事。", "千年辽鹤，并疑城郭非是。", "当日万驷云屯，潮生潮落处，石头孤峙。", "人笑褚渊今齿冷，只有袁公不死。", "斜日荒烟，神州何在，欲堕新亭泪。", "元龙老矣，世间何限馀子。"]'),
('song-ci-823','摸鱼儿','杜','宋','宋词','song-ci','摸鱼儿','[]','放扁舟、万山环处，平铺碧浪千顷。',140,'宋词/ci.song.12000.json','["放扁舟、万山环处，平铺碧浪千顷。", "仙人怜我征尘久，借与梦游清枕。", "风乍静。", "望两岸群峰，倒浸玻璃影。", "楼台相映。", "更日薄烟轻，荷花似醉，飞鸟堕寒镜。", "中都内，罗绮千街万井。", "天教此地幽胜。", "仇池仙伯今何在，堤柳几眠还醒。", "君试问。", "□此意、只今更有何人领。", "功名未竟。", "待学取鸱夷，仍携西子，来动五湖兴。"]'),
('song-ci-824','蓦山溪','杜','宋','宋词','song-ci','蓦山溪','[]','春风如客，可是繁华主。',102,'宋词/ci.song.12000.json','["春风如客，可是繁华主。", "红紫未全开，早绿遍、江南千树。", "一番新火，多少倦游人，纤腰柳，不知愁，犹作风前舞。", "小阑干外，两两幽禽语。", "问我不归家，有佳人、天寒日暮。", "老来心事，唯只有春知，江头路，带春来，更带春归去。"]'),
('song-ci-825','贺新郎','刘仙伦','宋','宋词','song-ci','贺新郎','[]','翠盖笼娇面。',141,'宋词/ci.song.12000.json','["翠盖笼娇面。", "记当年、沈香亭北，醉中曾见。", "见了风流倾国艳，红紫纷纷过眼。", "算好处、何嫌春晚。", "谁把天香和晓露，倩东君、特地匀娇脸。", "千万朵，开时遍。", "隔花听取提壶劝。", "道此花过了，春归蝶愁莺怨。", "挽住东君须醉倒，花底不妨留恋。", "待唤取、笙歌一片。", "最爱就中红一朵，似状元、得意春风殿。", "还惹起，少年恨。"]'),
('song-ci-826','木兰花慢','刘仙伦','宋','宋词','song-ci','木兰花慢','[]','渐秋空向晚，被风雨、趱重阳。',122,'宋词/ci.song.12000.json','["渐秋空向晚，被风雨、趱重阳。", "正木落疏林，海棠枝上，忽见红妆。", "料应妒他兰菊，任年年、独甚占秋光。", "故把春风娇面，向人逞艳呈芳。", "看来毕竟此花强。", "只是欠些香。", "诮一似当年，五陵公子，却厌膏梁。", "肯来水边竹下，与幽人、相对说凄凉。", "只恐夜深花睡，五更微有清霜。"]'),
('song-ci-827','菩萨蛮','刘仙伦','宋','宋词','song-ci','菩萨蛮','[]','东风去了秦楼畔。',52,'宋词/ci.song.12000.json','["东风去了秦楼畔。", "一川烟草无人管。", "芳树雨初晴。", "黄鹂三两声。", "海棠花已谢。", "春事无多也。", "只有牡丹时。", "知他归不归。"]'),
('song-ci-828','贺新郎','刘仙伦','宋','宋词','song-ci','贺新郎','[]','小队停钲鼓。',142,'宋词/ci.song.12000.json','["小队停钲鼓。", "向沙边、柳下维舟，庆公初度。", "平尽群蛮方易镇，此事多应有数。", "奈自古、功成人妒。", "君看乐羊中山役，任谤书、盈箧终无据。", "千载下，竞谁与。", "诗中带得西山雨。", "指天台、雁荡归欤，寿乡深处。", "缓急朝廷须公出，更作中流砥柱。", "笑痴呆、纷纷儿女。", "多少人间不平事，有皇天、老眼能区处。", "挥玉斝，听金缕。"]'),
('song-ci-829','贺新郎','刘仙伦','宋','宋词','song-ci','贺新郎','[]','重唤松江渡。',141,'宋词/ci.song.12000.json','["重唤松江渡。", "叹垂虹亭下，销磨几番今古。", "依旧四桥风景在，为问坡仙甚处。", "但遗爱、沙边鸥鹭。", "天水相连苍茫外，更碧云、去尽山无数。", "潮正落，日还暮。", "十年到此长凝伫。", "恨无人、与共秋风，脍丝莼缕。", "小转朱弦弹九奏，拟致湘妃伴侣。", "俄皓月、飞来烟渚。", "恍若乘槎河汉上，怕客星、犯斗蛟龙怒。", "歌欸乃，过江去。"]'),
('song-ci-830','贺新郎','刘仙伦','宋','宋词','song-ci','贺新郎','[]','郑玉非娼女。',141,'宋词/ci.song.12000.json','["郑玉非娼女。", "叹尘缘未了，飘零被春留住。", "肠断胭脂坡下路。", "成甚心情意绪。", "生怕入、梨园歌舞。", "寂寞阳台云雨散，算人间、谁是吹箫侣。", "空买断，两眉聚。", "新来镜里惊如许。", "暗伤怀、莺老花残，几番春暮。", "事逐孤鸿都已往，月落千山杜宇。", "念修竹、天寒何处。", "不念琐窗并绣户，妾从前、命薄甘荆布。", "谁为作，解绦主。"]'),
('song-ci-831','念奴娇','刘仙伦','宋','宋词','song-ci','念奴娇','[]','艅艎东下，望西江千里，苍茫烟水。',120,'宋词/ci.song.12000.json','["艅艎东下，望西江千里，苍茫烟水。", "试问襄州何处是，雉堞连云天际。", "叔子残碑，卧龙陈迹，遗恨斜阳里。", "后来人物，如君瑰伟能几。", "其肯为我来耶，河阳下士，正自强人意。", "勿谓时平无事也，便以言兵为讳。", "眼底山河，楼头鼓角，都是英雄泪。", "功名机会，要须闲暇先备。"]'),
('song-ci-832','念奴娇','刘仙伦','宋','宋词','song-ci','念奴娇','[]','吴山青处，恨长安路断，黄尘如雾。',120,'宋词/ci.song.12000.json','["吴山青处，恨长安路断，黄尘如雾。", "荆楚西来行堑远，北过淮堧严扈。", "九塞貔貅，三关虎豹，空作陪京固。", "天高难叫，若为得诉忠语。", "追念江左英雄，中兴事业，枉被奸臣误。", "不见翠华移跸处，枉负吾皇神武。", "击楫凭谁，问筹无计，何日宽忧顾。", "倚筇长叹，满怀清泪如雨。"]'),
('song-ci-833','念奴娇','刘仙伦','宋','宋词','song-ci','念奴娇','[]','西风何事，为行人扫荡，烦襟如洗。',120,'宋词/ci.song.12000.json','["西风何事，为行人扫荡，烦襟如洗。", "垂涨蒸澜都卷尽，一片潇湘清泚。", "酒病惊秋，诗愁入鬓，对景人千里。", "楚宫故事，一时分付流水。", "江上买取扁舟，排云涌浪，直过金沙尾。", "归去江南丘壑处，不用来寻月姊。", "风露杯深，芙蓉裳冷，笑傲烟霞里。", "草庐如旧，卧龙知为谁起。"]'),
('song-ci-834','满江红','刘仙伦','宋','宋词','song-ci','满江红','[]','快阁东西，鸥边问、晚晴可喜。',115,'宋词/ci.song.12000.json','["快阁东西，鸥边问、晚晴可喜。", "鸥解语、既盟之后，两翁曾倚。", "笛弄惯听黄鲁直，履声深识徐渊子。", "添我来、相对两忘机，真相似。", "也不种，闲桃李。", "也不玩，佳山水。", "有新诗字字，爱民而已。", "一片心闲秋水外，三年人在春风里。", "涨一篙、江水送归鸿，明朝是。"]'),
('song-ci-835','满江红','刘仙伦','宋','宋词','song-ci','满江红','[]','著意留春，留不住、春归难恋。',115,'宋词/ci.song.12000.json','["著意留春，留不住、春归难恋。", "最苦是、梅天烟雨，麦秋庭院。", "嫩竹阴浓莺出谷，柔桑采尽蚕成茧。", "奈沈腰、宽尽有谁知，难消遣。", "幽阁恨，双眉敛。", "香笺寄，飞鸿远。", "向风帘羞见，一双归燕。", "翠被闲将情做梦，青楼赚得恩成怨。", "对尊前、莫惜唤琼姬，持杯劝。"]'),
('song-ci-836','霜天晓角','刘仙伦','宋','宋词','song-ci','霜天晓角','[]','倚空绝壁。',53,'宋词/ci.song.12000.json','["倚空绝壁。", "直下江千尺。", "天际两蛾凝黛，愁与恨、几时极。", "暮潮风正急。", "酒醒闻塞笛。", "试问谪仙何处，青山外，远烟碧。"]'),
('song-ci-837','诉衷情','刘仙伦','宋','宋词','song-ci','诉衷情','[]','征衣薄薄不禁风。',54,'宋词/ci.song.12000.json','["征衣薄薄不禁风。", "长日雨丝中。", "又是一年春事，花信到梧桐。", "云漠漠，水溶溶。", "去匆匆。", "客怀今夜，家在江西，身在江东。"]'),
('song-ci-838','江神子・江城子','刘仙伦','宋','宋词','song-ci','江神子・江城子','[]','华堂深处出娉婷。',86,'宋词/ci.song.12000.json','["华堂深处出娉婷。", "语声轻。", "笑声清。", "燕语莺啼，一一付春情。", "恰似洛阳花正发，见花好，不知名。", "金瓯盛酒玉纤擎。", "满盈盈。", "劝深深。", "不怕主人，教你十分斟。", "只怕酒阑歌罢后，人不见，暮山青。"]'),
('song-ci-839','系裙腰','刘仙伦','宋','宋词','song-ci','系裙腰','[]','山儿矗矗水儿清。',72,'宋词/ci.song.12000.json','["山儿矗矗水儿清。", "船儿似叶儿轻。", "风儿更没人情。", "月儿明。", "厮合造、送行人。", "眼儿蔌蔌泪儿倾。", "灯儿更冷清清。", "遭逢著雁儿，又没前程。", "一声声。", "怎生得、梦儿成。"]'),
('song-ci-840','永遇乐','刘仙伦','宋','宋词','song-ci','永遇乐','[]','青幄蔽林，白毡铺径，红雨迷楚。',128,'宋词/ci.song.12000.json','["青幄蔽林，白毡铺径，红雨迷楚。", "昼阁关愁，风帘卷恨，尽日萦情绪。", "阳台云去，文园人病，寂寞翠尊雕俎。", "惜韶容、匆匆易失，芳丛对眼如雾。", "巾欹润裛，衣宽凉渗，又觉渐回骄暑。", "解箨吹香，遗丸荐脆，小芰浮鸳浦。", "画栏如旧，依稀犹记，伫立一钩莲步。", "暗销魂，那堪又听，杜鹃更苦。"]'),
('song-ci-841','菩萨蛮','刘仙伦','宋','宋词','song-ci','菩萨蛮','[]','吹箫人去行云杳。',52,'宋词/ci.song.12000.json','["吹箫人去行云杳。", "香篝翠被都闲了。", "叠损缕金衣。", "是他浑不知。", "冷烟寒食夜。", "淡月梨花下。", "犹自软心肠。", "为他烧夜香。"]'),
('song-ci-842','江神子・江城子','刘仙伦','宋','宋词','song-ci','江神子・江城子','[]','东风吹梦落巫山。',86,'宋词/ci.song.12000.json','["东风吹梦落巫山。", "整云鬟。", "却霜纨。", "雪貌冰肤，曾共控双鸾。", "吹罢玉箫香雾湿，残月坠，乱峰寒。", "解珰回首忆前欢。", "见无缘。", "恨无端。", "憔悴萧郎，赢得带围宽。", "红叶不传天上信，空流水，到人间。"]'),
('song-ci-843','蝶恋花','刘仙伦','宋','宋词','song-ci','蝶恋花','[]','小立东风谁共语。',70,'宋词/ci.song.12000.json','["小立东风谁共语。", "碧尽行云，依约兰皋暮。", "谁问离怀知几许。", "一溪流水和烟雨。", "媚荡杨花无著处。", "才伴春来，忙底随春去。", "只恐游蜂粘得住。", "斜阳芳草江头路。"]'),
('song-ci-844','一翦梅','刘仙伦','宋','宋词','song-ci','一翦梅','[]','唱到阳关第四声。',72,'宋词/ci.song.12000.json','["唱到阳关第四声。", "香带轻分。", "罗带轻分。", "杏花时节雨纷纷。", "山绕孤村。", "水绕孤村。", "更没心情共酒尊。", "春衫香满，空有啼痕。", "一般离思两销魂。", "马上黄昏。", "楼上黄昏。"]'),
('song-ci-845','沁园春','刘仙伦','宋','宋词','song-ci','沁园春','[]','闻道参军，今日垂弧，胜如去年。',139,'宋词/ci.song.12000.json','["闻道参军，今日垂弧，胜如去年。", "正新颁蓝绶，天香芬馥，初开黄牒，御墨新鲜。", "鼻祖登科，已逾百载，衣钵于今喜再传。", "图南事，看抟风九万，击水三千。", "官曹小试民编。", "有奕世甘棠在道边。", "向樽前有兴，细斟清醥，琴中得趣，缓拂朱弦。", "东观酬书，西垣草制，此去掀胜好看鞭。", "应难老，信君家眉寿，自有篯山。"]'),
('song-ci-846','好事近','刘仙伦','宋','宋词','song-ci','好事近','[]','春事恰平分，南极夜来星瑞。',53,'宋词/ci.song.12000.json','["春事恰平分，南极夜来星瑞。", "闻道都曹初度，拥万红千翠。", "长才杰出应时须，一郡赖纲纪。", "看即诏还入觐，上鸳行班里。"]'),
('song-ci-847','沁园春','刘仙伦','宋','宋词','song-ci','沁园春','[]','周易一书，更三圣人，深切著明。',139,'宋词/ci.song.12000.json','["周易一书，更三圣人，深切著明。", "凡变通动静，有形有象，盈虚消息，时止时行。", "天相名卿，日探妙趣，往古来今无两心。", "褰帷暇，手韦编不置，聊以娱情。", "如今祝寿殷勤。", "请得以推评理致新。", "看九重有命，晋侯锡马，三公论道，鼎足承君。", "同厥震男，拔乎泰茹，玉笋班中联步什。", "贤奋建，定丰亨豫大，扬夬王庭。"]'),
('song-ci-848','喜迁莺','刘仙伦','宋','宋词','song-ci','喜迁莺','[]','祥云笼昼。',124,'宋词/ci.song.12000.json','["祥云笼昼。", "正梅花弄粉，岁寒时候。", "长记今朝，瑶台仙子，降作人间明秀。", "四德生来全备，绿鬓年年依旧。", "更满目，儿妇儿孙，森罗前后。", "知否。", "笙歌奏。", "去岁芳筵，好事今年又。", "寿烛高烧，寿词齐唱，满劝长生酒。", "元自荣华富贵，况复康宁福寿。", "愿此去，等鹤算龟龄，天长地久。"]'),
('song-ci-849','鹧鸪天','刘仙伦','宋','宋词','song-ci','鹧鸪天','[]','帘幕祥风动玉钩。',64,'宋词/ci.song.12000.json','["帘幕祥风动玉钩。", "凤箫声彻瑞烟浮。", "萧郎玉女来相会，今日齐眉醉玉楼。", "同富贵、共风流。", "一封花诰一封侯。", "更须有子腰金斗，镜里双鸾到白头。"]'),
('song-ci-850','满江红','刘仙伦','宋','宋词','song-ci','满江红','[]','过了烧灯，杨柳外、无边春色。',115,'宋词/ci.song.12000.json','["过了烧灯，杨柳外、无边春色。", "庆初度、香浮东阁，瑞呈南极。", "翰墨场中推老手，曾魁多士催勍敌。", "到而今、官薄在天台，神仙籍。", "和月倚，南坡石。", "滴露点，床头易。", "看白头红颊，目光摇碧。", "富贵康强仍有子，人生似此应难得。", "更摩挲、铜狄说当年，真消息。"]'),
('song-ci-851','好事近','刘仙伦','宋','宋词','song-ci','好事近','[]','桃李绿阴浓，屈指中和三六。',53,'宋词/ci.song.12000.json','["桃李绿阴浓，屈指中和三六。", "恰是仙翁初度，霭瑞烟芬馥。", "歌喉宛转绕华堂，总是长生曲。", "他日临清亭上，看儿孙朝服。"]'),
('song-ci-852','满江红','刘仙伦','宋','宋词','song-ci','满江红','[]','凤历更端，才信宿、年华方好。',115,'宋词/ci.song.12000.json','["凤历更端，才信宿、年华方好。", "深院宇、祥风飘荡，瑞烟缭绕。", "闻道君侯当诞日，欢声解压春寒峭。", "更九衢、烟火近元宵，闻嬉笑。", "人正在，蓬莱岛。", "烧绛蜡，斟清醥。", "听清歌艳曲，一声云杪。", "奠枕江淮无一事，留都宫殿千门晓。", "看赐环、千岁侍君王，人难老。"]'),
('song-ci-853','念奴娇','刘仙伦','宋','宋词','song-ci','念奴娇','[]','一番春事，到芗林、更两日重三节。',120,'宋词/ci.song.12000.json','["一番春事，到芗林、更两日重三节。", "百品名花饶笑处，喜遇诞弥佳月。", "巢叶灵龟，舞琴野鹤，总是千年物。", "来为公寿，纶巾长映华发。", "平生圣处功夫，道□深味，胸次真冰雪。", "高蹈丘园还谢了，枚叟蒲轮朝谒。", "时上篮舆，相随孙子，庆满床簪笏。", "南丰道价，敬持一瓣香爇。"]'),
('song-ci-854','满江红','刘仙伦','宋','宋词','song-ci','满江红','[]','夜半天风，吹佩玉、列仙初度。',115,'宋词/ci.song.12000.json','["夜半天风，吹佩玉、列仙初度。", "又恰是、人间六月，叶蓂方吐。", "黄纸除书惊乍到，青毡旧物欣重睹。", "拥皇华、玉节待清秋，江南去。", "招壮士，增王旅。", "漕廪粟，资淮浦。", "济江南嘉绩，久闻当宁。", "明弼堂前山满眼，来鸿庭后花无数。", "看召环、即到寿星边，朝明主。"]'),
('song-ci-855','醉蓬莱','刘仙伦','宋','宋词','song-ci','醉蓬莱','[]','昨长庚入梦，昴宿呈祥，岳神锺秀。',120,'宋词/ci.song.12000.json','["昨长庚入梦，昴宿呈祥，岳神锺秀。", "降产英贤，信道由天佑。", "蓂荚飞三，九秋将暮，遇称觞时候。", "香爇沈檀，曲调金缕，满斟春酒。", "试纪绛年，六身二首，甲子方延，才经八九。", "款醉蓬莱，寿与天长久。", "桂子青春，兰孙方茂，谅箕裘方绍。", "折桂来秋，成名指日，家毡复旧。"]'),
('song-ci-856','满江红','杜旃','宋','宋词','song-ci','满江红','[]','半落半开花有恨，一晴一雨春无力。',34,'宋词/ci.song.12000.json','["半落半开花有恨，一晴一雨春无力。", "……别缆解时风度紧，离觞尽处花飞急。"]'),
('song-ci-857','浣溪沙','韩彦古','宋','宋词','song-ci','浣溪沙','[]','一缕金香永夜清。',48,'宋词/ci.song.12000.json','["一缕金香永夜清。", "残编未掩古琴横。", "绣衾寒拥宝缺明。", "坐听竹风敲石磴，旋倾花水漱春酲。", "落梅和雨打帘声。"]'),
('song-ci-858','水调歌头','张祥','宋','宋词','song-ci','水调歌头','[]','为爱龙山胜，小队一登临。',114,'宋词/ci.song.12000.json','["为爱龙山胜，小队一登临。", "冯仙洞府安在，抉石试幽寻。", "商略生平事业，摆脱人间尘土，欲与断丝苓。", "泉响似相答，未可启归心。", "中原地，禾黍茂，犬羊腥。", "君王梦想豪杰，有待扫妖氛。", "缚虎正须人手，跨鹤缓酬夙志，行矣勿因循。", "夜半遣雷雨，助我作秋成。"]'),
('song-ci-859','柳梢青','张履信','宋','宋词','song-ci','柳梢青','[]','雨歇桃繁，风微柳静，日淡湖湾。',61,'宋词/ci.song.12000.json','["雨歇桃繁，风微柳静，日淡湖湾。", "寒食清明，虽然过了，未觉春闲。", "行云掩映春山。", "真水墨、山阴道间。", "燕语侵愁，花飞撩恨，人在江南。"]'),
('song-ci-860','谒金门','张履信','宋','宋词','song-ci','谒金门','[]','春睡起。',53,'宋词/ci.song.12000.json','["春睡起。", "小阁明窗儿底。", "帘外雨声花积水。", "薄寒犹在里。", "欲起还慵未起。", "好是孤眠滋味。", "一曲广陵应忘记。", "起来调绿绮。"]'),
('song-ci-861','婆罗门引','赵昂','宋','宋词','song-ci','婆罗门引','[]','暮霞照水，水边无数木芙蓉。',93,'宋词/ci.song.12000.json','["暮霞照水，水边无数木芙蓉。", "晓来露湿轻红。", "十里锦丝步障，日转影重重。", "向楚天空迥，人立西风。", "夕阳道中。", "叹秋色、与愁浓。", "寂寞三千粉黛，临鉴妆慵。", "施朱太赤，空惆怅、教妾若为容。", "花易老、烟水无穷。"]'),
('song-ci-862','谒金门','徐','宋','宋词','song-ci','谒金门','[]','秋欲暮。',53,'宋词/ci.song.12000.json','["秋欲暮。", "路入乱山深处。", "扑面西风吹雾雨。", "驿亭欣暂驻。", "可惜国香风度。", "空谷寂寥谁顾。", "已作竹枝传楚女。", "客愁推不去。"]'),
('song-ci-863','谒金门','徐','宋','宋词','song-ci','谒金门','[]','春欲半。',53,'宋词/ci.song.12000.json','["春欲半。", "重到寂寥山馆。", "修竹连山青不断。", "谁家门可款。", "红晕花梢未半。", "绿蘸柳芽犹短。", "金缕香消春不管。", "素蟾光又满。"]'),
('song-ci-864','万年欢','郭应祥','宋','宋词','song-ci','万年欢','[]','佳气葱葱，望长安日下，鸾鹤翔舞。',122,'宋词/ci.song.12000.json','["佳气葱葱，望长安日下，鸾鹤翔舞。", "天佑皇家，当年挺生真主。", "令节标名瑞庆，曾未数、电枢虹渚。", "人都道，福若高宗，太平赛过仁祖。", "需云燕锡广宇。", "有霓旌绛节，西极金母。", "笑捧蟠桃，更酌九霞清醑。", "持向两宫三殿，愿岁岁、此觞同举。", "南山寿、海算沙量，定应高出前古。"]'),
('song-ci-865','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','当年瑞雪多盈尺。',52,'宋词/ci.song.12000.json','["当年瑞雪多盈尺。", "今年仅有些儿白。", "天欲兆丰年。", "须教趁腊前。", "南枝初破萼。", "风味浑如昨。", "快与泻银瓶。", "寒醅醉易醒。"]'),
('song-ci-866','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','开禧三月初逢九。',52,'宋词/ci.song.12000.json','["开禧三月初逢九。", "持杯来庆梅仙寿。", "警捕恰三年。", "四封人宴然。", "政成应不日。", "去作朝京客。", "阴德合长生。", "休看三住铭。"]'),
('song-ci-867','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','雪销未久寒犹力。',52,'宋词/ci.song.12000.json','["雪销未久寒犹力。", "霜华特地催晴色。", "残腊尚馀旬。", "隔年先见春。", "独怜霜点鬓。", "羞戴银幡胜。", "百里却熙然。", "今年强去年。"]'),
('song-ci-868','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','泉江三遇昌阳节。',52,'宋词/ci.song.12000.json','["泉江三遇昌阳节。", "棹歌还向中流发。", "急桨更轻桡。", "看谁夺得标。", "明年归紫淦。", "尚忆舟同泛。", "应有旧双鬟。", "能讴菩萨蛮。"]'),
('song-ci-869','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','转头又是清秋近。',52,'宋词/ci.song.12000.json','["转头又是清秋近。", "晚风淅淅凉犹嫩。", "多谢客携觞。", "空惭画饼章。", "中亭明月可。", "未要亲灯火。", "十阅望舒圆。", "归期在眼前。"]'),
('song-ci-870','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','去年持酒为君寿。',52,'宋词/ci.song.12000.json','["去年持酒为君寿。", "劝君更上悬车奏。", "通籍已金闺。", "腰银袍亦绯。", "壶中闲日月。", "自有长生诀。", "父子弟兄贤。", "一门行地仙。"]'),
('song-ci-871','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','诞辰迟似秋三日。',52,'宋词/ci.song.12000.json','["诞辰迟似秋三日。", "草堂已有新凉入。", "鬓绿未全霜。", "欣然把一觞。", "吟松新纳禄。", "共享清闲福。", "两个老人星。", "君家难弟兄。"]'),
('song-ci-872','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','牡丹已过酴醿谢。',52,'宋词/ci.song.12000.json','["牡丹已过酴醿谢。", "那堪风雨连朝夜。", "底事最堪悲。", "春归人未归。", "春宜留取住。", "人却推将去。", "早晚遂江滨。", "欢然夸尹新。"]'),
('song-ci-873','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','秋堂积雨新凉入。',52,'宋词/ci.song.12000.json','["秋堂积雨新凉入。", "今宵雅乘鹏飞集。", "劲翮会高风。", "功名欬唾中。", "笔头元有准。", "快写平生蕴。", "何日捷书来。", "重阳把一杯。"]'),
('song-ci-874','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','去年今日游稽古。',52,'宋词/ci.song.12000.json','["去年今日游稽古。", "斓斑曾著莱衣舞。", "四世共团栾。", "津然一笑欢。", "归期今不远。", "孥累俱先遣。", "犹有社中人。", "相从寂寞滨。"]'),
('song-ci-875','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','修途六月清无暑。',52,'宋词/ci.song.12000.json','["修途六月清无暑。", "潘舆稳向盱南去。", "喜气已津津。", "平反一笑春。", "人言阴德报。", "罗纸重重诰。", "明岁早归来。", "泉江去鹢催。"]'),
('song-ci-876','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','涂黄仙子娇无力。',52,'宋词/ci.song.12000.json','["涂黄仙子娇无力。", "秋花不敢争颜色。", "风物一番新。", "从今到小春。", "新词仍险韵。", "赓续惭非称。", "桃李寂无言。", "此花名独传。"]'),
('song-ci-877','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','未观岩桂先观菊。',52,'宋词/ci.song.12000.json','["未观岩桂先观菊。", "世间底事真迟速。", "节物苦相催。", "重阳便到来。", "白衣何处觅。", "沽酒邀佳客。", "一笑有馀欢。", "官居终日闲。"]'),
('song-ci-878','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','佳辰昨日传筒黍。',52,'宋词/ci.song.12000.json','["佳辰昨日传筒黍。", "今朝重把离觞举。", "别驾奉安舆。", "前呵方塞途。", "庞眉真寿相。", "两处交迎养。", "庾岭到星沙。", "风光属一家。"]'),
('song-ci-879','菩萨蛮','郭应祥','宋','宋词','song-ci','菩萨蛮','[]','分宜七里逢重九。',52,'宋词/ci.song.12000.json','["分宜七里逢重九。", "篱根无菊尊无酒。", "萧飒鬓如蓬。", "不禁吹帽风。", "插花开口笑。", "未分输年少。", "明岁定王台。", "传杯不放杯。"]'),
('song-ci-880','渔家傲','郭应祥','宋','宋词','song-ci','渔家傲','[]','去岁簿书丛里过。',72,'宋词/ci.song.12000.json','["去岁簿书丛里过。", "生朝也有人来贺。", "随分侑尊呼几个。", "胡厮和。", "愁颜镇日何曾破。", "素发如今添老大。", "归来方是闲当坐。", "旋擘黄柑篘白堕。", "哩喻罗。", "从他扰扰如旋磨。"]'),
('song-ci-881','渔家傲','郭应祥','宋','宋词','song-ci','渔家傲','[]','白古馀杭多俊俏。',72,'宋词/ci.song.12000.json','["白古馀杭多俊俏。", "风流不独夸苏小。", "又见尊前人窈窕。", "花枝袅。", "贪看忘却朱颜老。", "曲巷横街深更杳。", "追欢买笑须年少。", "悔不从前相识早。", "心灰了。", "逢场落得掀髯笑。"]'),
('song-ci-882','传言玉女','郭应祥','宋','宋词','song-ci','传言玉女','[]','稽古堂前，恰见四番端午。',90,'宋词/ci.song.12000.json','["稽古堂前，恰见四番端午。", "又来江上，听鸣鼍急鼓。", "棹歌才发，漠漠一川烟雨。", "轻舟摇扬，浪心掀舞。", "倦客今年续命，欠□彩缕。", "归期渐近，剗地萦心绪。", "何日斑衣，更看迎门儿女。", "百怀且付，尊前蒲黍。"]'),
('song-ci-883','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','依约滩声杂橹声。',64,'宋词/ci.song.12000.json','["依约滩声杂橹声。", "波光隐映月华明。", "眼前好景真无尽，身外浮名尽可轻。", "穷胜赏，续欢盟。", "直饶风雨也须晴。", "满头插菊掀髯笑，笑道齐山浪得名。"]'),
('song-ci-884','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','爱日迎长月向圆。',64,'宋词/ci.song.12000.json','["爱日迎长月向圆。", "当年飞堕蕊珠仙。", "相门赫奕人争羡，阃则柔嘉世所贤。", "罗纸贵，彩衣鲜。", "鼎来盛事乐无边。", "妇姑夫妇孙和子，同住人间五百年。"]'),
('song-ci-885','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','谁道他乡异故乡。',64,'宋词/ci.song.12000.json','["谁道他乡异故乡。", "泉江风物似湄湘。", "钗头缀糁萸偏紫，杯面浮金菊倍黄。", "今共古，几重阳。", "休将往事更平章。", "舞衫歌扇姑随分，又得掀髯笑一场。"]'),
('song-ci-886','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','风雨潇潇旧满城。',64,'宋词/ci.song.12000.json','["风雨潇潇旧满城。", "今年九日十分晴。", "且同北海邀佳客，共向东篱看落英。", "罗绮队，管弦声。", "银山高处好同登。", "催租岂解妨诗兴，自是潘郎名未成。"]'),
('song-ci-887','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','鸾诰双双妇与姑。',64,'宋词/ci.song.12000.json','["鸾诰双双妇与姑。", "家尊荣宦到中都。", "暂时花县飞凫舄，新看芝庭捧鹤书。", "梅欲放，柳将舒。", "诞辰先占一阳初。", "清心堂下围红处，剩有长生酒满壶。"]'),
('song-ci-888','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','垂领纷纷已二毛。',64,'宋词/ci.song.12000.json','["垂领纷纷已二毛。", "可堪州县尚徒劳。", "催科自笑阳城拙，勇退应惭靖节高。", "来祝寿，笑儿曹。", "说椿说柏说蟠桃。", "世间底事非前定，妙理还须问浊醪。"]'),
('song-ci-889','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','休道泉江寂寞滨。',64,'宋词/ci.song.12000.json','["休道泉江寂寞滨。", "喧喧歌吹遍城闉。", "莫辞邀赏连三日，且庆开禧第一春。", "呼小队，领嘉宾。", "王园佳处踏芳尘。", "星球不用随归骑，自有山头月逐人。"]'),
('song-ci-890','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','人道今年秋较迟。',64,'宋词/ci.song.12000.json','["人道今年秋较迟。", "木樨全未放些儿。", "不因诞节开千岁，争得今辰把一枝。", "呼宝鼎，伴渠伊。", "堂萱喜色正融怡。", "儿前妇后孙曾从，岁岁称觞无尽期。"]'),
('song-ci-891','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','万里澄空没点云。',64,'宋词/ci.song.12000.json','["万里澄空没点云。", "素娥依旧驾冰轮。", "自缘人意看承别，未必清辉减一分。", "倾白堕，拥红裙。", "不知谁主复谁宾。", "更筹易促愁分袂，又作东西南北人。"]'),
('song-ci-892','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','怪得欢声满十龙。',64,'宋词/ci.song.12000.json','["怪得欢声满十龙。", "诞辰和气敌严冬。", "安书莲幕欣频到，庆事花城喜屡逢。", "琼液泛，宝熏浓。", "华堂交口祝椿松。", "阿姑同健夫偕老，会有重重锦诰封。"]'),
('song-ci-893','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','动地欢声遍十龙。',64,'宋词/ci.song.12000.json','["动地欢声遍十龙。", "元宵真赏与民同。", "春归莲焰参差里，人在蓬壶快乐中。", "乘皓月，逐和风。", "凉舆归去莫匆匆。", "班春休道无千炬，也有星球数点红。"]'),
('song-ci-894','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','前数重阳后小春。',64,'宋词/ci.song.12000.json','["前数重阳后小春。", "中间十日是生辰。", "二年稳作栖鸾客，百里谁非贺燕人。", "无一事，扰天真。", "年登八八愈精神。", "句稽宜解淹贤辙，黄发犹须上要津。"]'),
('song-ci-895','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','点检尊前主与宾。',64,'宋词/ci.song.12000.json','["点检尊前主与宾。", "今宵依旧昨宵人。", "自缘笑语生和气，不为风光属小春。", "香叆叇，酒清醇。", "山肴野蔌总前陈。", "掀髯抵掌君休怪，镜里星星白发新。"]'),
('song-ci-896','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','贺了生辰却贺冬。',64,'宋词/ci.song.12000.json','["贺了生辰却贺冬。", "今年乐事又重重。", "寿香喷处芝兰馥，寿洒斟时琥珀浓。", "偕桂隐，到花封。", "迎长介寿恰三逢。", "明年此日称觞罢，稳上肩舆九里松。"]'),
('song-ci-897','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','诞节初开七帙祥。',64,'宋词/ci.song.12000.json','["诞节初开七帙祥。", "今秋仍喜十分凉。", "称觞堂下孙和息，备福人间寿且康。", "从庾岭，到章江。", "两州元自接封疆。", "儿曹此去分风月，莱彩潘舆乐未央。"]'),
('song-ci-898','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','瓶里梅花香正浓。',64,'宋词/ci.song.12000.json','["瓶里梅花香正浓。", "阶前更著锦熏笼。", "且留幡胜明朝戴，共庆桑蓬此日逢。", "眉正绿，脸常红。", "后堂无日不春风。", "明年定又强今岁，会有明珠入掌中。"]'),
('song-ci-899','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','令节标名自古闻。',64,'宋词/ci.song.12000.json','["令节标名自古闻。", "今宵银汉耿无云。", "难寻海上乘槎客，空诵河东乞巧文。", "罗异果，炷名熏。", "纫针拈线漫纷纷。", "蓬莱底事回车处，暗想当年钿合分。"]'),
('song-ci-900','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','我离浏川七载强。',64,'宋词/ci.song.12000.json','["我离浏川七载强。", "去思那有召公棠。", "方怀旧友归鸿阁，忽枉高轩戏彩堂。", "频举白，剩添香。", "剧谈不觉引杯长。", "官居也有城门禁，未到三更尽不妨。"]'),
('song-ci-901','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','古遂长沙千里遥。',64,'宋词/ci.song.12000.json','["古遂长沙千里遥。", "三年三处做生朝。", "试拈疏蕊铜瓶插，更把轻沈宝鼎烧。", "杯绿泛，脸红潮。", "抱孙娱膝语声娇。", "官居只似私居样，管取寒松最后雕。"]'),
('song-ci-902','鹧鸪天','郭应祥','宋','宋词','song-ci','鹧鸪天','[]','方是闲堂寿宴开。',64,'宋词/ci.song.12000.json','["方是闲堂寿宴开。", "今回生日胜前回。", "慈闱斑貌看看到，别驾除书鼎鼎来。", "纷彩服，滟金杯。", "缓歌慢舞不须催。", "明年此际称觞罢，醉向裴亭与定台。"]'),
('song-ci-903','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','巧节已成昨梦，今宵重倒芳尊。',58,'宋词/ci.song.12000.json','["巧节已成昨梦，今宵重倒芳尊。", "主宾和气敌春温。", "雄辩高谈衮衮。", "剩把烛花高照，频教舞袖轻翻。", "笛声幽咽鼓声喧。", "却恨更筹苦短。"]'),
('song-ci-904','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','锁棘方当拔士，挥毫正好摛文。',58,'宋词/ci.song.12000.json','["锁棘方当拔士，挥毫正好摛文。", "词源三峡笔千军。", "尽出平生素蕴。", "天府伫登名姓，夜窗不负辛勤。", "直须平步上青云。", "始信文章有准。"]'),
('song-ci-905','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','十桂胜如五柳，九秋赛过三春。',58,'宋词/ci.song.12000.json','["十桂胜如五柳，九秋赛过三春。", "蓬蓬金粟吐奇芬。", "自有天然风韵。", "休羡一枝高折，尽教十里遥闻。", "尊前若有似花人。", "乞与些儿插鬓。"]'),
('song-ci-906','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','赏月几成喜雨，开尊仍间围棋。',58,'宋词/ci.song.12000.json','["赏月几成喜雨，开尊仍间围棋。", "令人却忆敬斋词。", "小饮不妨文字。", "底事冰轮未放，犹教银幕低垂。", "休言动是隔年期。", "闰八看看又至。"]'),
('song-ci-907','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','此老谁描拙状，今朝持献生辰。',58,'宋词/ci.song.12000.json','["此老谁描拙状，今朝持献生辰。", "一人能变作三人。", "说与儿曹未信。", "坐者行者立者，化身报身法身。", "且须辨取假和真。", "肥瘦短长休问。"]'),
('song-ci-908','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','明日恰当人日，今年远胜常年。',58,'宋词/ci.song.12000.json','["明日恰当人日，今年远胜常年。", "瓣香卮酒寿蓝田。", "喜色津然满面。", "及戍人方竞进，悬车公独高骞。", "身闲便是地行仙。", "赢得千秋强健。"]'),
('song-ci-909','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','令节无过七夕，今年已隔三宵。',58,'宋词/ci.song.12000.json','["令节无过七夕，今年已隔三宵。", "奔驰五百里而遥。", "行止非人所料。", "月入尊罍楚楚，风生襟袖飘飘。", "不须抵死殢河桥。", "对月临风一笑。"]'),
('song-ci-910','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','妙句春云多态，丰姿秋水为神。',58,'宋词/ci.song.12000.json','["妙句春云多态，丰姿秋水为神。", "慕潘应有捧心颦。", "谁是相看楚润。", "试问甜言软语，何如大醉高吟。", "杯行若怕十分深。", "人道对花不饮。"]'),
('song-ci-911','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','洗眼重看十桂，转头已过三秋。',58,'宋词/ci.song.12000.json','["洗眼重看十桂，转头已过三秋。", "人生遇坎与乘流。", "何况有花有酒。", "花若与人有意，酒能为我浇愁。", "拭挼金蕊泛金瓯。", "比似菊英胜否。"]'),
('song-ci-912','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','碎影乱筛月地，浓香时度风檐。',58,'宋词/ci.song.12000.json','["碎影乱筛月地，浓香时度风檐。", "渊明有菊径开三。", "不似此花雅淡。", "兰蕙芬敷可并，芙蓉浅俗堪嫌。", "美人妆罢笑窥帘。", "插鬓些儿正欠。"]'),
('song-ci-913','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','歌扇潜回暖吹，酒兵顿解寒围。',58,'宋词/ci.song.12000.json','["歌扇潜回暖吹，酒兵顿解寒围。", "红莲绛蜡两交辉。", "小醉何妨大醉。", "落笔君如王勃，属辞我愧周墀。", "明年应记盍簪时。", "耿耿怀人不寐。"]'),
('song-ci-914','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','为爱脸边著晕，更怜肌里生香。',58,'宋词/ci.song.12000.json','["为爱脸边著晕，更怜肌里生香。", "此花端合占年芳。", "两朵那堪一样。", "自叹思归陶令，忽逢好事彭郎。", "朋来异卉与名章。", "击节何妨叹赏。"]'),
('song-ci-915','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','不但酴醿芍药，此花亦殿馀春。',58,'宋词/ci.song.12000.json','["不但酴醿芍药，此花亦殿馀春。", "麝囊初破酒初醺。", "恰有这般风韵。", "斓坼真成绝倒，半开犹带轻颦。", "不知抵死笑何人。", "待与折来细问。"]'),
('song-ci-916','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','乐事无过新岁，生辰恰占元宵。',58,'宋词/ci.song.12000.json','["乐事无过新岁，生辰恰占元宵。", "湄湘台下有欢谣。", "令尹风流年少。", "暂借牛刀凫舄，宜参豹尾鸡翘。", "政成三异合归朝。", "试目天边紫诏。"]'),
('song-ci-917','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','头上银幡初卸，堂前玉斝重飞。',58,'宋词/ci.song.12000.json','["头上银幡初卸，堂前玉斝重飞。", "人言七十古来稀。", "七十如今已至。", "斑白元无一点，微黄已透双眉。", "一番庆寿十年期。", "更庆十番不啻。"]'),
('song-ci-918','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','朔旦生朝同贺，寿觞社瓮齐倾。',58,'宋词/ci.song.12000.json','["朔旦生朝同贺，寿觞社瓮齐倾。", "湄湘原是小东京。", "著个风流贰令。", "地胜岂如人胜，秋清争似官清。", "双瞳炯炯鬓青青。", "稳上华途捷径。"]'),
('song-ci-919','西江月','郭应祥','宋','宋词','song-ci','西江月','[]','送我匆匆行色，赖君衮衮名章。',58,'宋词/ci.song.12000.json','["送我匆匆行色，赖君衮衮名章。", "德星今夜聚清湘。", "岂羡瀛洲方丈。", "宾醉须教主醉，更长不怕杯长。", "凤鸣端合在朝阳。", "飞诏来从天上。"]'),
('song-ci-920','昭君怨','郭应祥','宋','宋词','song-ci','昭君怨','[]','歌舞籍中第一。',48,'宋词/ci.song.12000.json','["歌舞籍中第一。", "情致人间第一。", "年纪不多儿。", "尽娇痴。", "昨夜华严阁下。", "今夜海棠洞下。", "多少别离情。", "泪盈盈。"]'),
('song-ci-921','昭君怨','郭应祥','宋','宋词','song-ci','昭君怨','[]','去岁银山塔上。',48,'宋词/ci.song.12000.json','["去岁银山塔上。", "今岁金山塔上。", "屈指到泉江。", "再重阳。", "有菊不妨同戴。", "有酒不妨同醉。", "嘉客与佳宾。", "两俱新。"]'),
('song-ci-922','玉楼春','郭应祥','宋','宋词','song-ci','玉楼春','[]','匆匆相遇匆匆去。',64,'宋词/ci.song.12000.json','["匆匆相遇匆匆去。", "恰似当年元未遇。", "生憎黄土岭头尘，强学章台街里絮。", "雨荒三径云迷路。", "总是离人堪恨处。", "从今对酒与当歌，空惹离情千万绪。"]'),
('song-ci-923','玉楼春','郭应祥','宋','宋词','song-ci','玉楼春','[]','贤僚益友俱亲密。',64,'宋词/ci.song.12000.json','["贤僚益友俱亲密。", "真个三年如一日。", "清尊倒处笑喧哗，彩笔吟馀才俊逸。", "杯盘狼籍情真率。", "歌管棋枰仍间出。", "今朝又喜盍朋簪，何日定当抛县绂。"]'),
('song-ci-924','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','金风淅淅，银河耿耿，七夕如今又至。',68,'宋词/ci.song.12000.json','["金风淅淅，银河耿耿，七夕如今又至。", "人间唤作隔年期，但只似、屈伸指臂。", "罗花列果，拈针弄线，等是纷纷儿戏。", "巧人自少拙人多，那牛女、何曾管你。"]'),
('song-ci-925','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','金飙乍歇，冰轮欲上，万里秋空如扫。',68,'宋词/ci.song.12000.json','["金飙乍歇，冰轮欲上，万里秋空如扫。", "一年十二度团圆，甚恰限、今宵最好。", "烹麟脍凤，幕天席地，争似杯盘草草。", "明年应更胜今年，但只恐、朱颜暗老。"]'),
('song-ci-926','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','泥牛击罢，银幡卸了，又是一番春至。',68,'宋词/ci.song.12000.json','["泥牛击罢，银幡卸了，又是一番春至。", "有人耳畔语低低，道宜入、新年吉利。", "堆盘红缕，浮杯绿蚁，自有及时风味。", "从今日日是东风，待拚了、偎红倚翠。"]'),
('song-ci-927','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','薄云笼月，轻飙却暑，天上人间佳节。',68,'宋词/ci.song.12000.json','["薄云笼月，轻飙却暑，天上人间佳节。", "银河自有鹊为桥，又那要、兰舟桂楫。", "后期可准，新欢如昨，选甚轻离易别。", "姮娥休要妒人呵，待更与、留连一霎。"]'),
('song-ci-928','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','六人欢笑，六姬讴唱，六博时分胜负。',68,'宋词/ci.song.12000.json','["六人欢笑，六姬讴唱，六博时分胜负。", "六家盘馔斗芳鲜，恰两月、六番相聚。", "特排整整，华筵楚楚，终是不如草具。", "赏心乐事四时同，又管甚、落花飞絮。"]'),
('song-ci-929','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','六丁文焰，六韬武略，那更六经心醉。',68,'宋词/ci.song.12000.json','["六丁文焰，六韬武略，那更六经心醉。", "六人相对座生风，继六逸、当年旧事。", "六州清唱，六么妙舞，执乐仍呼六妓。", "大家且饮六分觥，看宾主、迭居六位。"]'),
('song-ci-930','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','杯盘草草，园亭小小，不用罗帷锦幄。',68,'宋词/ci.song.12000.json','["杯盘草草，园亭小小，不用罗帷锦幄。", "酴醿本是殿馀春，更风雨、无端趱却。", "有词可和，有棋可赌，杂以诙谐戏谑。", "闲时日日可遨嬉，又选甚，花开花落。"]'),
('song-ci-931','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','去年七夕，今年五日，两见浴儿高会。',68,'宋词/ci.song.12000.json','["去年七夕，今年五日，两见浴儿高会。", "乃翁种德已多年，看衮衮、公侯未艾。", "封胡羯末，综维缜绛，堪羡金鱼垂袋。", "丹砂白蜜不须涂，把续命、彩丝与带。"]'),
('song-ci-932','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','两情相向，一年厮睚，等得佳期又到。',68,'宋词/ci.song.12000.json','["两情相向，一年厮睚，等得佳期又到。", "休言夜半悄无人，那喜鹊、也须知道。", "来今往古，吟诗度曲，总漫萦牵怀抱。", "不如乞取巧些些，待见了、分明祷告。"]'),
('song-ci-933','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','立春除夕，并为一日，此事今年创见。',68,'宋词/ci.song.12000.json','["立春除夕，并为一日，此事今年创见。", "席间三世共团栾，随分有、笙歌满院。", "一名喜雪，二名饯岁，三则是名春宴。", "从教一岁大家添，但只要、明年强健。"]'),
('song-ci-934','鹊桥仙','郭应祥','宋','宋词','song-ci','鹊桥仙','[]','今年七夕，新秋三日，已觉凉生院宇。',68,'宋词/ci.song.12000.json','["今年七夕，新秋三日，已觉凉生院宇。", "吾乡风物胜他乡，那更著、莱衣起舞。", "泛槎经岁，分钗半夜，往事流传千古。", "独怜词客与诗人，费多少、闲言泼语。"]'),
('song-ci-935','浣溪沙','郭应祥','宋','宋词','song-ci','浣溪沙','[]','仙子凌波袜有尘。',48,'宋词/ci.song.12000.json','["仙子凌波袜有尘。", "翰林摛藻笔如神。", "此花此曲两无伦。", "不与妆台簪宝髻，却来书阁伴幽人。", "恨无佳客只空尊。"]'),
('song-ci-936','浣溪沙','郭应祥','宋','宋词','song-ci','浣溪沙','[]','屈指中秋一日期。',48,'宋词/ci.song.12000.json','["屈指中秋一日期。", "雨馀云薄月来迟。", "冰轮犹自欠些儿。", "世事孰非颠倒相，客居东位主人西。", "觞行莫惜醉如泥。"]'),
('song-ci-937','浣溪沙','郭应祥','宋','宋词','song-ci','浣溪沙','[]','树底全无一点红。',48,'宋词/ci.song.12000.json','["树底全无一点红。", "今年春事又成空。", "不须追恨雨和风。", "欲去未来多恶况，独眠无寐少欢悰。", "一声啼鴂五更钟。"]'),
('song-ci-938','浣溪沙','郭应祥','宋','宋词','song-ci','浣溪沙','[]','尊俎之间著二陈。',48,'宋词/ci.song.12000.json','["尊俎之间著二陈。", "津津眉宇笑生春。", "清歌妙舞两无伦。", "叔隗轻盈饶态度，小乔妩媚足精神。", "风流总属一家人。"]'),
('song-ci-939','好事近','郭应祥','宋','宋词','song-ci','好事近','[]','今日十分晴，好个重阳天气。',53,'宋词/ci.song.12000.json','["今日十分晴，好个重阳天气。", "又向银山高处，为黄花一醉。", "泉江风物饱相谙，瞥眼过三岁。", "但得明年强健，任举杯何地。"]'),
('song-ci-940','好事近','郭应祥','宋','宋词','song-ci','好事近','[]','今岁度元宵，随分点些灯火。',53,'宋词/ci.song.12000.json','["今岁度元宵，随分点些灯火。", "不比旧家繁盛，有红莲千朵。", "客来草草办杯盘，饾饤杂蔬果。", "休羡暗尘随马，与银花铁锁。"]'),
('song-ci-941','好事近','郭应祥','宋','宋词','song-ci','好事近','[]','今岁庆生朝，迟似迎长十日。',53,'宋词/ci.song.12000.json','["今岁庆生朝，迟似迎长十日。", "试向彩衣堂下，听欢声洋溢。", "小孙能笑长能歌，已自堪娱膝。", "管取婆犹未老，见满床堆笏。"]'),
('song-ci-942','满江红','郭应祥','宋','宋词','song-ci','满江红','[]','节物匆匆，又还见、浓春入眼。',115,'宋词/ci.song.12000.json','["节物匆匆，又还见、浓春入眼。", "那更是、晓风初扇，宿云都卷。", "蝶舞已便花蕊乱，燕归仍惬香泥暖。", "又何须、女手学春工，并刀翦。", "欢乐事，郊坰遍。", "游赏处，轮蹄远。", "听谁家弦管，日开华宴。", "有客摛毫多丽句，惭予拆袜无长线。", "问新来、诗酒顿然疏，怎消遣。"]'),
('song-ci-943','满江红','郭应祥','宋','宋词','song-ci','满江红','[]','五十头颅，早已觉、飞腾景暮。',115,'宋词/ci.song.12000.json','["五十头颅，早已觉、飞腾景暮。", "愁眼看、蜂黄蝶粉，草烟花露。", "莫做阳台云雨梦，休怀渭北春天树。", "怅城闉、多少踏青人，红尘路。", "怀古恨，凭书诉。", "倾国貌，障羞妒。", "记山阴陈迹，群贤星聚。", "对景裁诗真漫与，看花不饮成虚负。", "问落红、千点总随流，归何处。"]'),
('song-ci-944','满江红','郭应祥','宋','宋词','song-ci','满江红','[]','七帙华年，这强健、人谁得似。',115,'宋词/ci.song.12000.json','["七帙华年，这强健、人谁得似。", "还又见、设弧令旦，秋风生桂。", "教子已成森砌玉，弄孙仍得追风骥。", "更后堂、深处著婵娟，笙歌沸。", "香叆篆，杯浮蚁。", "欢意洽，酡颜醉。", "有静中日月，闲中天地。", "不必亲扶灵寿杖，何须远挹浮丘袂。", "看蟠桃、著子又开花，三千岁。"]'),
('song-ci-945','念奴娇','郭应祥','宋','宋词','song-ci','念奴娇','[]','琼苞玉屑，问天公、底事乱抛轻坠。',120,'宋词/ci.song.12000.json','["琼苞玉屑，问天公、底事乱抛轻坠。", "城郭山川都一样，那得个般清气。", "谢女才情，如何只道，柳絮因风起。", "比梅差可，但无绿萼红蕊。", "坐上十客雄豪，颓然一老，草具相邀至。", "驱尽寒威凭酒力，买笑千金须费。", "谁办佳词，洛阳年少，笔下生新意。", "待添几盏，共君今夕同醉。"]'),
('song-ci-946','虞美人','郭应祥','宋','宋词','song-ci','虞美人','[]','二年浏水司征榷。',66,'宋词/ci.song.12000.json','["二年浏水司征榷。", "小却平戎略。", "征衫指日去朝京。", "恰恰一江新渌、可扬舲。", "诗工画妙俱臻极。", "到处留真迹。", "一尊莫惜暂停桡。", "不待离歌唱彻、已魂销。"]'),
('song-ci-947','虞美人','郭应祥','宋','宋词','song-ci','虞美人','[]','梅桃末利东篱菊。',66,'宋词/ci.song.12000.json','["梅桃末利东篱菊。", "著个瓶儿簇。", "寻常四物不同时。", "恰似西施二赵、太真妃。", "从来李郭多投分。", "伯仲俱清俊。", "苍颜独我已成翁。", "尚许掀髯一笑、对西风。"]'),
('song-ci-948','虞美人','郭应祥','宋','宋词','song-ci','虞美人','[]','周郎素蕴平戎略。',66,'宋词/ci.song.12000.json','["周郎素蕴平戎略。", "聊此司征榷。", "他人两载已辞难。", "君独三年、只作一朝看。", "紫萸黄菊重阳后。", "木落秋容瘦。", "休斟别酒惨离裾。", "戚畹如今、个个有新除。"]'),
('song-ci-949','虞美人','郭应祥','宋','宋词','song-ci','虞美人','[]','天公有意留君住。',66,'宋词/ci.song.12000.json','["天公有意留君住。", "故作纤纤雨。", "闭门觅句自持觞。", "并舍官梅、时有过来香。", "沈郎诗骨元来瘦。", "更挹湘江秀。", "不须骂雨与嘲风。", "收拾个般、都入锦囊中。"]'),
('song-ci-950','醉落魄・一斛珠','郭应祥','宋','宋词','song-ci','醉落魄・一斛珠','[]','琼楼玉宇。',67,'宋词/ci.song.12000.json','["琼楼玉宇。", "分明不受人间暑。", "寻常岂是无三五。", "惟有今宵，皓彩皆同普。", "素娥阅尽今和古。", "何妨小驻听吾语。", "当年弄影婆娑舞。", "妙曲虽传，毕竟人何许。"]'),
('song-ci-951','采桑子','郭应祥','宋','宋词','song-ci','采桑子','[]','中秋过了还逢社，寿我亲闱。',52,'宋词/ci.song.12000.json','["中秋过了还逢社，寿我亲闱。", "百里熙熙。", "尽道平反赖母慈。", "浏川水阔吾山峻，福禄如斯。", "禄鬓青眉。", "子又生孙孙又儿。"]'),
('song-ci-952','采桑子','郭应祥','宋','宋词','song-ci','采桑子','[]','饯筵绿绕红围处，只这孩儿。',52,'宋词/ci.song.12000.json','["饯筵绿绕红围处，只这孩儿。", "两泪垂垂。", "不忍叫人遽别离。", "别离不作多时计，千日为期。", "却恐归时。", "人道寻春已较迟。"]'),
('song-ci-953','朝中措','郭应祥','宋','宋词','song-ci','朝中措','[]','海棠零落瑒花繁。',57,'宋词/ci.song.12000.json','["海棠零落瑒花繁。", "春意已将阑。", "予告恰当寒食，邀宾同赏芳园。", "湄湘台畔，杯盘楚楚，歌舞喧喧。", "预约牡丹开后，更须重倒清尊。"]'),
('song-ci-954','卜算子','郭应祥','宋','宋词','song-ci','卜算子','[]','春事到清明，过了三之二。',52,'宋词/ci.song.12000.json','["春事到清明，过了三之二。", "秾李夭桃委路尘，太半成泥滓。", "只有海棠花，恰似杨妃醉。", "折向铜壶把烛看，且莫教渠睡。"]'),
('song-ci-955','卜算子','郭应祥','宋','宋词','song-ci','卜算子','[]','谁把洛阳花，翦送河阳县。',52,'宋词/ci.song.12000.json','["谁把洛阳花，翦送河阳县。", "魏紫姚黄此地无，随分红深浅。", "小插向铜瓶，一段真堪羡。", "十二人簪十二枝，面面交相看。"]'),
('song-ci-956','减字木兰花','郭应祥','宋','宋词','song-ci','减字木兰花','[]','仲春是七。',52,'宋词/ci.song.12000.json','["仲春是七。", "门左垂弧当此日。", "点检春光。", "百草千葩已斗芳。", "折花持酒。", "彩袖殷勤来祝寿。", "明岁而今。", "稳向南宫待捷音。"]'),
('song-ci-957','减字木兰花','郭应祥','宋','宋词','song-ci','减字木兰花','[]','偶然相聚。',52,'宋词/ci.song.12000.json','["偶然相聚。", "最是人间堪乐处。", "散步寻春。", "来作琴堂不速宾。", "缓歌一曲。", "野鹜纷纷都退缩。", "不用多杯。", "准拟花时日日来。"]'),
('song-ci-958','减字木兰花','郭应祥','宋','宋词','song-ci','减字木兰花','[]','栖鸾高士。',52,'宋词/ci.song.12000.json','["栖鸾高士。", "文采风流谁得似。", "年德虽高。", "对酒当歌气尚豪。", "明眸皓齿。", "一朵红莲初出水。", "膝上安排。", "爱惜须教不离怀。"]'),
('song-ci-959','减字木兰花','郭应祥','宋','宋词','song-ci','减字木兰花','[]','遇如不遇。',52,'宋词/ci.song.12000.json','["遇如不遇。", "最是暂来还复去。", "归到乡关。", "欲再来时却恐难。", "丁宁去后。", "倩雁传书须访旧。", "万斛羁愁。", "逐水那容许大舟。"]'),
('song-ci-960','柳梢青','郭应祥','宋','宋词','song-ci','柳梢青','[]','春事匆匆。',61,'宋词/ci.song.12000.json','["春事匆匆。", "花慵柳困，雨横风狂。", "寄语诗人，须烧银烛，与照红妆。", "休言桃李河阳。", "但过眼、难寻色香。", "只有今宵，更无明日，且缓飞觞。"]'),
('song-ci-961','柳梢青','郭应祥','宋','宋词','song-ci','柳梢青','[]','遁斋居士。',61,'宋词/ci.song.12000.json','["遁斋居士。", "今年今日，又添一岁。", "鬓雪心灰，十分老懒，十分憔悴。", "休言富贵长年，那个是、生涯活计。", "茗饮一瓯，纹楸一局，沈烟一穗。"]'),
('song-ci-962','柳梢青','郭应祥','宋','宋词','song-ci','柳梢青','[]','薄晚才晴。',61,'宋词/ci.song.12000.json','["薄晚才晴。", "相邀移席，待月中庭。", "环坐斯须，屋山高处，忽吐微明。", "云收雨止风停。", "人世有、琼楼玉京。", "一任星移，从教斗转，且缓飞觥。"]'),
('song-ci-963','柳梢青','郭应祥','宋','宋词','song-ci','柳梢青','[]','合浦名邦。',61,'宋词/ci.song.12000.json','["合浦名邦。", "风流太守，紫绶金章。", "暂驻旌麾，来临祖席，一片潇湘。", "且须缓举离觞。", "细看取、眉间点黄。", "未到还珠，已闻赐玺，归近清光。"]'),
('song-ci-964','柳梢青','郭应祥','宋','宋词','song-ci','柳梢青','[]','两令邀宾。',61,'宋词/ci.song.12000.json','["两令邀宾。", "城南佳处，饯腊迎春。", "步入梅林，纷然缟袂，间似红英。", "遥岑寸碧增明。", "更酬唱、无惭昔人。", "一笑相欢，且斟佳醑，休羡莼羹。"]'),
('song-ci-965','生查子','郭应祥','宋','宋词','song-ci','生查子','[]','尊前主与宾，欠一还成九。',48,'宋词/ci.song.12000.json','["尊前主与宾，欠一还成九。", "休唱木犀词，预饮黄花酒。", "开怀今夕同，分手明朝又。", "不管岁年催，且把馨香嗅。"]'),
('song-ci-966','生查子','郭应祥','宋','宋词','song-ci','生查子','[]','银烛印红衫，薄暮新梳洗。',48,'宋词/ci.song.12000.json','["银烛印红衫，薄暮新梳洗。", "一笑奉宾欢，未解东君意。", "回廊月转初，忆趁良宵会。", "喜事在明年，剧饮拼先醉。"]'),
('song-ci-967','点绛唇','郭应祥','宋','宋词','song-ci','点绛唇','[]','九十韶光，闲忙晴雨常相半。',50,'宋词/ci.song.12000.json','["九十韶光，闲忙晴雨常相半。", "赏春有愿。", "乘兴宁论晚。", "纵饮筠溪，日午花阴转。", "杯行缓。", "量悭嫌浅。", "须索斟教满。"]'),
('song-ci-968','点绛唇','郭应祥','宋','宋词','song-ci','点绛唇','[]','小队郊坰，耄倪争看铜章史。',50,'宋词/ci.song.12000.json','["小队郊坰，耄倪争看铜章史。", "来宣德意。", "劝相遵彝制。", "夜雨连明，百谷应滋遂。", "真奇事。", "开禧元二。", "总是丰登岁。"]'),
('song-ci-969','点绛唇','郭应祥','宋','宋词','song-ci','点绛唇','[]','五马归来，后车载得如花女。',50,'宋词/ci.song.12000.json','["五马归来，后车载得如花女。", "缓歌金缕。", "新样京华舞。", "主悦宾欢，一醉祛袢暑。", "停箫鼓。", "且须听取。", "三朵花能语。"]'),
('song-ci-970','点绛唇','郭应祥','宋','宋词','song-ci','点绛唇','[]','甲第初成，持杯酌酒来相庆。',50,'宋词/ci.song.12000.json','["甲第初成，持杯酌酒来相庆。", "棣华辉映。", "相对开三径。", "小巧规模，百事都相称。", "年方盛。", "从容啸咏。", "不碍青云兴。"]'),
('song-ci-971','江城子','郭应祥','宋','宋词','song-ci','江城子','[]','开尊拟对菊花黄。',86,'宋词/ci.song.12000.json','["开尊拟对菊花黄。", "舞伊凉。", "掺渔阳。", "更有风流，妓女胜徐娘。", "只道难逢开口笑，争驰逐，利名场。", "玉山蓝水两茫茫。", "采幽香。", "泛清觞。", "橙橘堆盘，犹恨未经霜。", "底事□□堪喜处，丰年最，冠江乡。"]');
